{
  "name": "EduManage - Gestão de Alunos",
  "description": "Sistema completo para gestão de alunos, controle financeiro, frequência e aniversariantes com insights inteligentes via Gemini.",
  "requestFramePermissions": []
}

export type Student = {
  id: string;
  name: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  lastPaymentDate: string;
};

export type Transaction = {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  date: string;
  description: string;
  category: string;
};

export type AttendanceRecord = {
  studentId: string;
  date: string;
  present: boolean;
};

export enum AppView {
  Dashboard = 'dashboard',
  Students = 'students',
  Attendance = 'attendance',
  Finance = 'finance',
  Ranking = 'ranking'
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getFinancialAdvice = async (transactions: any[]) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Analise as seguintes transações financeiras e dê um breve resumo (em português) sobre a saúde financeira e uma dica para melhorar: ${JSON.stringify(transactions)}`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Não foi possível gerar insights financeiros no momento.";
  }
};

export const getMotivationalMessage = async (studentName: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Crie uma mensagem motivacional curta e personalizada para o aluno ${studentName} para encorajá-lo a continuar vindo às aulas.`,
    });
    return response.text;
  } catch (error) {
    return "Continue assim! Sua evolução é notável.";
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  CalendarCheck, 
  DollarSign, 
  Trophy, 
  Plus, 
  Search, 
  Cake, 
  Bell,
  TrendingUp,
  ArrowUpCircle,
  ArrowDownCircle,
  Menu,
  X
} from 'lucide-react';
import { Student, Transaction, AppView } from './types';
import { getFinancialAdvice } from './geminiService';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell 
} from 'recharts';

// Mock Initial Data
const INITIAL_STUDENTS: Student[] = [
  { id: '1', name: 'João Silva', birthDate: '1995-05-15', joinDate: '2023-01-10', paymentDay: 10, status: 'active', attendanceCount: 45, lastPaymentDate: '2024-04-10' },
  { id: '2', name: 'Maria Santos', birthDate: '1992-06-20', joinDate: '2023-02-15', paymentDay: 5, status: 'active', attendanceCount: 52, lastPaymentDate: '2024-05-05' },
  { id: '3', name: 'Pedro Costa', birthDate: '1998-05-22', joinDate: '2023-03-01', paymentDay: 15, status: 'active', attendanceCount: 30, lastPaymentDate: '2024-04-15' },
];

const INITIAL_FINANCE: Transaction[] = [
  { id: 't1', type: 'income', amount: 1500, date: '2024-05-01', description: 'Mensalidades Maio', category: 'Mensalidade' },
  { id: 't2', type: 'expense', amount: 400, date: '2024-05-03', description: 'Aluguel Sala', category: 'Fixo' },
  { id: 't3', type: 'expense', amount: 150, date: '2024-05-05', description: 'Materiais Limpeza', category: 'Variável' },
];

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.Dashboard);
  const [students, setStudents] = useState<Student[]>(INITIAL_STUDENTS);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_FINANCE);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [financeInsight, setFinanceInsight] = useState<string>('');
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);

  // Form States
  const [isStudentModalOpen, setIsStudentModalOpen] = useState(false);
  const [newStudent, setNewStudent] = useState<Partial<Student>>({
    name: '',
    birthDate: '',
    paymentDay: 10,
    status: 'active'
  });

  useEffect(() => {
    // Generate Gemini insight on mount
    const fetchInsight = async () => {
      setIsLoadingInsight(true);
      const advice = await getFinancialAdvice(transactions);
      setFinanceInsight(advice || '');
      setIsLoadingInsight(false);
    };
    fetchInsight();
  }, []);

  const birthdaysThisMonth = useMemo(() => {
    const currentMonth = new Date().getMonth() + 1;
    return students.filter(s => {
      const birthMonth = new Date(s.birthDate).getUTCMonth() + 1;
      return birthMonth === currentMonth;
    });
  }, [students]);

  const paymentAlerts = useMemo(() => {
    const today = new Date().getDate();
    return students.filter(s => s.status === 'active' && s.paymentDay <= today + 3 && s.paymentDay >= today - 2);
  }, [students]);

  const stats = useMemo(() => {
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [transactions]);

  const addStudent = () => {
    if (!newStudent.name || !newStudent.birthDate) return;
    const student: Student = {
      id: Date.now().toString(),
      name: newStudent.name!,
      birthDate: newStudent.birthDate!,
      joinDate: new Date().toISOString().split('T')[0],
      paymentDay: newStudent.paymentDay || 10,
      status: 'active',
      attendanceCount: 0,
      lastPaymentDate: ''
    };
    setStudents([...students, student]);
    setIsStudentModalOpen(false);
    setNewStudent({ name: '', birthDate: '', paymentDay: 10, status: 'active' });
  };

  const markAttendance = (id: string) => {
    setStudents(prev => prev.map(s => s.id === id ? { ...s, attendanceCount: s.attendanceCount + 1 } : s));
  };

  const NavItem = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => (
    <button
      onClick={() => { setView(target); setIsSidebarOpen(false); }}
      className={`flex items-center space-x-3 w-full p-4 rounded-xl transition-all ${
        view === target ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-600 hover:bg-indigo-50'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-50 text-slate-900">
      {/* Mobile Top Header */}
      <div className="md:hidden flex items-center justify-between p-4 bg-white border-b sticky top-0 z-40">
        <div className="flex items-center space-x-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <TrendingUp size={18} />
          </div>
          <h1 className="text-xl font-bold text-slate-800">EduManage</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-600">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar Navigation */}
      <aside className={`
        fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 transition-transform duration-200 ease-in-out
        w-72 bg-white border-r p-6 z-50 flex flex-col gap-6
      `}>
        <div className="hidden md:flex items-center space-x-3 mb-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
            <TrendingUp size={24} />
          </div>
          <h1 className="text-2xl font-bold text-slate-800 tracking-tight">EduManage</h1>
        </div>

        <nav className="flex-1 space-y-2">
          <NavItem target={AppView.Dashboard} icon={LayoutDashboard} label="Dashboard" />
          <NavItem target={AppView.Students} icon={Users} label="Alunos" />
          <NavItem target={AppView.Attendance} icon={CalendarCheck} label="Frequência" />
          <NavItem target={AppView.Finance} icon={DollarSign} label="Financeiro" />
          <NavItem target={AppView.Ranking} icon={Trophy} label="Ranking" />
        </nav>

        <div className="mt-auto p-4 bg-indigo-50 rounded-2xl">
          <div className="flex items-center space-x-2 text-indigo-700 font-semibold mb-1">
            <Bell size={18} />
            <span>Alertas</span>
          </div>
          <p className="text-xs text-indigo-600">
            {paymentAlerts.length} alunos próximos do vencimento
          </p>
        </div>
      </aside>

      {/* Overlay for mobile sidebar */}
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/20 z-40 md:hidden" onClick={() => setIsSidebarOpen(false)} />
      )}

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8">

        {/* Dashboard View */}
        {view === AppView.Dashboard && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <header>
              <h2 className="text-2xl font-bold text-slate-800">Bem-vindo, Admin</h2>
              <p className="text-slate-500">Aqui está o que está acontecendo na sua escola hoje.</p>
            </header>

            {/* Stats Overview */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
                <div className="p-3 bg-green-100 text-green-600 rounded-xl"><ArrowUpCircle size={28} /></div>
                <div>
                  <p className="text-sm text-slate-500 font-medium">Receita Mensal</p>
                  <p className="text-2xl font-bold">R$ {stats.income.toLocaleString()}</p>
                </div>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
                <div className="p-3 bg-red-100 text-red-600 rounded-xl"><ArrowDownCircle size={28} /></div>
                <div>
                  <p className="text-sm text-slate-500 font-medium">Despesas Mensais</p>
                  <p className="text-2xl font-bold">R$ {stats.expense.toLocaleString()}</p>
                </div>
              </div>
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
                <div className="p-3 bg-indigo-100 text-indigo-600 rounded-xl"><Users size={28} /></div>
                <div>
                  <p className="text-sm text-slate-500 font-medium">Alunos Ativos</p>
                  <p className="text-2xl font-bold">{students.filter(s => s.status === 'active').length}</p>
                </div>
              </div>
            </div>

            {/* Smart Insights & Alerts */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              {/* Payment Alerts Card */}
              <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
                <div className="flex items-center justify-between mb-6">
                  <h3 className="text-lg font-bold flex items-center space-x-2">
                    <Bell className="text-orange-500" size={20} />
                    <span>Atenção aos Pagamentos</span>
                  </h3>
                  <span className="text-xs font-semibold bg-orange-100 text-orange-700 px-3 py-1 rounded-full">
                    {paymentAlerts.length} pendentes
                  </span>
                </div>
                <div className="space-y-3">
                  {paymentAlerts.map(student => (
                    <div key={student.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                      <div className="flex items-center space-x-3">
                        <div className="w-10 h-10 bg-slate-200 rounded-full flex items-center justify-center font-bold text-slate-600">
                          {student.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-semibold text-slate-800">{student.name}</p>
                          <p className="text-xs text-slate-500">Vencimento: Dia {student.paymentDay}</p>
                        </div>
                      </div>
                      <button className="text-xs bg-indigo-600 text-white px-3 py-1.5 rounded-lg hover:bg-indigo-700 transition">
                        Cobrar
                      </button>
                    </div>
                  ))}
                  {paymentAlerts.length === 0 && <p className="text-center text-slate-400 py-4 italic">Nenhum pagamento pendente no radar.</p>}
                </div>
              </div>

              {/* Gemini Financial Insight */}
              <div className="bg-indigo-900 text-white p-8 rounded-3xl shadow-xl relative overflow-hidden">
                <div className="relative z-10">
                  <h3 className="text-xl font-bold mb-4 flex items-center space-x-2">
                    <TrendingUp size={22} className="text-indigo-300" />
                    <span>Insight Inteligente AI</span>
                  </h3>
                  {isLoadingInsight ? (
                    <div className="animate-pulse space-y-2">
                      <div className="h-4 bg-indigo-800 rounded w-3/4"></div>
                      <div className="h-4 bg-indigo-800 rounded w-full"></div>
                      <div className="h-4 bg-indigo-800 rounded w-5/6"></div>
                    </div>
                  ) : (
                    <p className="text-indigo-100 leading-relaxed italic">
                      "{financeInsight || "Analizando seus dados financeiros para fornecer recomendações estratégicas..."}"
                    </p>
                  )}
                </div>
                {/* Decoration */}
                <div className="absolute top-0 right-0 -mt-10 -mr-10 w-40 h-40 bg-indigo-800 rounded-full blur-3xl opacity-50"></div>
                <div className="absolute bottom-0 left-0 -mb-10 -ml-10 w-40 h-40 bg-indigo-700 rounded-full blur-3xl opacity-30"></div>
              </div>
            </div>

            {/* Birthdays Card */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
              <h3 className="text-lg font-bold mb-6 flex items-center space-x-2">
                <Cake className="text-pink-500" size={20} />
                <span>Aniversariantes do Mês</span>
              </h3>
              <div className="flex flex-wrap gap-4">
                {birthdaysThisMonth.map(student => (
                  <div key={student.id} className="flex items-center space-x-3 bg-pink-50 p-3 pr-5 rounded-2xl border border-pink-100">
                    <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-2xl">🎂</div>
                    <div>
                      <p className="font-bold text-slate-800">{student.name}</p>
                      <p className="text-xs text-pink-600">{new Date(student.birthDate).toLocaleDateString('pt-BR', { day: 'numeric', month: 'long' })}</p>
                    </div>
                  </div>
                ))}
                {birthdaysThisMonth.length === 0 && (
                  <p className="text-slate-400 italic">Ninguém assoprando velinhas este mês.</p>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Students List View */}
        {view === AppView.Students && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <h2 className="text-2xl font-bold text-slate-800">Gestão de Alunos</h2>
              <button 
                onClick={() => setIsStudentModalOpen(true)}
                className="flex items-center justify-center space-x-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl hover:bg-indigo-700 shadow-md transition"
              >
                <Plus size={20} />
                <span>Novo Aluno</span>
              </button>
            </div>

            <div className="relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input 
                type="text" 
                placeholder="Pesquisar por nome do aluno..." 
                className="w-full pl-12 pr-4 py-3 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none transition"
              />
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b text-slate-500 text-xs uppercase tracking-wider font-semibold">
                    <tr>
                      <th className="px-6 py-4">Nome</th>
                      <th className="px-6 py-4">Nascimento</th>
                      <th className="px-6 py-4">Dia Pagto</th>
                      <th className="px-6 py-4">Frequência</th>
                      <th className="px-6 py-4">Status</th>
                      <th className="px-6 py-4 text-right">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {students.map(student => (
                      <tr key={student.id} className="hover:bg-slate-50/50 transition-colors">
                        <td className="px-6 py-4">
                          <div className="flex items-center space-x-3">
                            <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-xs">
                              {student.name.charAt(0)}
                            </div>
                            <span className="font-medium text-slate-800">{student.name}</span>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-slate-600 text-sm">
                          {new Date(student.birthDate).toLocaleDateString()}
                        </td>
                        <td className="px-6 py-4 text-slate-600 text-sm">{student.paymentDay}</td>
                        <td className="px-6 py-4">
                          <span className="px-2.5 py-1 bg-indigo-50 text-indigo-700 rounded-full text-xs font-bold">
                            {student.attendanceCount} aulas
                          </span>
                        </td>
                        <td className="px-6 py-4">
                          <span className={`px-2.5 py-1 rounded-full text-xs font-bold ${
                            student.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                          }`}>
                            {student.status === 'active' ? 'Ativo' : 'Inativo'}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <button className="text-slate-400 hover:text-indigo-600 transition p-1">Editar</button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {/* Attendance View */}
        {view === AppView.Attendance && (
          <div className="space-y-6 animate-in fade-in duration-300">
            <header>
              <h2 className="text-2xl font-bold text-slate-800">Lista de Presença</h2>
              <p className="text-slate-500">Marque a presença dos alunos para hoje ({new Date().toLocaleDateString()}).</p>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {students.filter(s => s.status === 'active').map(student => (
                <div key={student.id} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 flex items-center justify-between">
                  <div className="flex items-center space-x-3">
                    <div className="w-10 h-10 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center font-bold">
                      {student.name.charAt(0)}
                    </div>
                    <div>
                      <p className="font-bold text-slate-800">{student.name}</p>
                      <p className="text-xs text-slate-400">Total: {student.attendanceCount} aulas</p>
                    </div>
                  </div>
                  <button 
                    onClick={() => markAttendance(student.id)}
                    className="p-3 bg-indigo-50 text-indigo-600 rounded-xl hover:bg-indigo-600 hover:text-white transition group"
                  >
                    <CalendarCheck size={20} className="group-active:scale-90" />
                  </button>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Finance View */}
        {view === AppView.Finance && (
          <div className="space-y-8 animate-in fade-in duration-300">
            <header className="flex items-center justify-between">
              <div>
                <h2 className="text-2xl font-bold text-slate-800">Fluxo de Caixa</h2>
                <p className="text-slate-500">Controle suas receitas e despesas.</p>
              </div>
              <button className="flex items-center space-x-2 bg-indigo-600 text-white px-5 py-2.5 rounded-xl hover:bg-indigo-700 shadow-md">
                <Plus size={20} />
                <span>Novo Registro</span>
              </button>
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="lg:col-span-2 space-y-8">
                {/* Financial Summary Chart */}
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm h-80">
                  <h3 className="font-bold text-slate-700 mb-6 uppercase text-xs tracking-widest">Resumo Financeiro</h3>
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={[
                      { name: 'Entradas', value: stats.income, fill: '#10b981' },
                      { name: 'Saídas', value: stats.expense, fill: '#ef4444' },
                      { name: 'Saldo', value: stats.balance, fill: '#6366f1' }
                    ]}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                      <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                      <Tooltip 
                        contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} 
                        cursor={{fill: '#f8fafc'}}
                      />
                      <Bar dataKey="value" radius={[8, 8, 0, 0]} barSize={50} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>

                {/* Recent Transactions */}
                <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
                  <div className="p-6 border-b flex justify-between items-center">
                    <h3 className="font-bold text-slate-800">Transações Recentes</h3>
                    <button className="text-indigo-600 text-sm font-semibold">Ver tudo</button>
                  </div>
                  <div className="divide-y divide-slate-100">
                    {transactions.map(t => (
                      <div key={t.id} className="p-4 px-6 flex items-center justify-between hover:bg-slate-50 transition">
                        <div className="flex items-center space-x-4">
                          <div className={`p-2.5 rounded-xl ${
                            t.type === 'income' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'
                          }`}>
                            {t.type === 'income' ? <ArrowUpCircle size={20} /> : <ArrowDownCircle size={20} />}
                          </div>
                          <div>
                            <p className="font-semibold text-slate-800">{t.description}</p>
                            <p className="text-xs text-slate-400">{t.category} • {new Date(t.date).toLocaleDateString()}</p>
                          </div>
                        </div>
                        <p className={`font-bold ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                          {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString()}
                        </p>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="space-y-6">
                 {/* Expense Categories Distribution */}
                 <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm">
                  <h3 className="font-bold text-slate-700 mb-6 uppercase text-xs tracking-widest">Despesas por Categoria</h3>
                  <div className="h-64">
                    <ResponsiveContainer width="100%" height="100%">
