              </div>
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-2">Dia do Vencimento</label>
                <input type="number" min="1" max="28" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl focus:ring-2 focus:ring-amber-500 outline-none text-white font-bold" />
              </div>
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-2">Faixa</label>
                <select className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl focus:ring-2 focus:ring-amber-500 outline-none text-white font-bold appearance-none">
                  <option>Branca</option>
                  <option>Azul</option>
                  <option>Roxa</option>
                  <option>Marrom</option>
                  <option>Preta</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-slate-500 mb-2">Graus</label>
                <select className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl focus:ring-2 focus:ring-amber-500 outline-none text-white font-bold appearance-none">
                  <option>0 Graus</option>
                  <option>1 Grau</option>
                  <option>2 Graus</option>
                  <option>3 Graus</option>
                  <option>4 Graus</option>
                </select>
              </div>
            </div>

            <button className="w-full bg-amber-500 text-slate-950 font-black py-5 rounded-[1.5rem] hover:bg-amber-400 shadow-xl shadow-amber-900/20 transition mt-10 uppercase tracking-widest italic">
              Concluir Matrícula
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

