  'Roxa': '#7e22ce',
  'Marrom': '#78350f',
  'Preta': '#000000'
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [athletes, setAthletes] = useState<Athlete[]>(MOCK_ATHLETES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_FINANCE);
  const [muralPhotos, setMuralPhotos] = useState<MuralPhoto[]>(MOCK_MURAL);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [financeInsight, setFinanceInsight] = useState<string>('');
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // Modais
  const [isAthleteModalOpen, setIsAthleteModalOpen] = useState(false);
  const [isReceiptModalOpen, setIsReceiptModalOpen] = useState(false);
  const [isMuralModalOpen, setIsMuralModalOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const muralInputRef = useRef<HTMLInputElement>(null);

  const login = (role: UserRole) => {
    const user: User = {
      id: role === 'student' ? '2' : 'u1', // Simula Ana Souza se for estudante
      name: role === 'admin' ? 'Mestre Hélio' : role === 'professor' ? 'Prof. Carlos' : 'Atleta Ana',
      email: `${role}@escola.com`,
      role: role,
      belt: role === 'admin' ? 'Preta' : role === 'professor' ? 'Preta' : 'Azul',
      degrees: role === 'student' ? 4 : 0
    };
    setCurrentUser(user);
    setView(AppView.Dashboard);
  };

  useEffect(() => {
    if (currentUser?.role === 'admin') {
      const fetchInsight = async () => {
        setIsLoadingInsight(true);
        const advice = await getFinancialAdvice(transactions);
        setFinanceInsight(advice || '');
        setIsLoadingInsight(false);
      };
      fetchInsight();
    }
  }, [currentUser, transactions]);

  const stats = useMemo(() => {
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [transactions]);

  const toggleAttendance = (athleteId: string) => {
    setAttendanceRecords(prev => {
      const recordIndex = prev.findIndex(r => r.date === selectedDate);
      if (recordIndex === -1) {
        return [...prev, { id: Date.now().toString(), date: selectedDate, athleteIds: [athleteId] }];
      }
      const newRecords = [...prev];
      const currentIds = newRecords[recordIndex].athleteIds;
      if (currentIds.includes(athleteId)) {
        newRecords[recordIndex].athleteIds = currentIds.filter(id => id !== athleteId);
      } else {
        newRecords[recordIndex].athleteIds = [...currentIds, athleteId];
      }
      return newRecords;
    });

    // Incrementa contador visual
    setAthletes(prev => prev.map(a => a.id === athleteId ? { ...a, attendanceCount: a.attendanceCount + 1 } : a));
  };

  const handleReceiptUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && currentUser) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const newTransaction: Transaction = {
          id: 't' + Date.now(),
          type: 'income',
          amount: 150, // Exemplo valor fixo mensalidade
          date: new Date().toISOString().split('T')[0],
          description: `Mensalidade - ${currentUser.name}`,
          category: 'Mensalidade',
          status: 'pending',
          athleteId: currentUser.id,
          receiptUrl: reader.result as string
        };
        setTransactions([newTransaction, ...transactions]);
        setIsReceiptModalOpen(false);
        alert("Comprovante enviado com sucesso para análise do mestre!");
      };
      reader.readAsDataURL(file);
    }
  };

  const handleMuralUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && currentUser) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const newPhoto: MuralPhoto = {
          id: 'm' + Date.now(),
          url: reader.result as string,
          caption: 'Novo registro de treino! OSS!',
          date: new Date().toISOString().split('T')[0],
          postedBy: currentUser.name
        };
        setMuralPhotos([newPhoto, ...muralPhotos]);
        setIsMuralModalOpen(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const canAccess = (roles: UserRole[]) => currentUser && roles.includes(currentUser.role);

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div 
        className={`h-6 w-20 rounded shadow-sm border border-slate-300 relative overflow-hidden flex items-center justify-end px-1`}
        style={{ backgroundColor: BELT_COLORS[belt] }}
      >
        <div className="absolute left-0 h-full w-4 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => (
            <div key={i} className="h-4 w-1 bg-white"></div>
          ))}
        </div>
      </div>
      <span className="text-[10px] font-bold uppercase text-slate-500 mt-1">{belt}</span>
    </div>
  );

  const NavItem = ({ target, icon: Icon, label, roles }: { target: AppView, icon: any, label: string, roles: UserRole[] }) => {
    if (!canAccess(roles)) return null;
    return (
      <button
        onClick={() => { setView(target); setIsSidebarOpen(false); }}
        className={`flex items-center space-x-3 w-full p-4 rounded-xl transition-all ${
          view === target ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:bg-slate-800'
        }`}
      >
        <Icon size={20} />
        <span className="font-bold uppercase text-xs tracking-widest">{label}</span>
      </button>
    );
  };

  if (view === AppView.Login) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950 p-6 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-full opacity-20 pointer-events-none grayscale">
           <img src="https://images.unsplash.com/photo-1552072092-7f9b8d63efcb?q=80&w=2070&auto=format&fit=crop" alt="BJJ" className="w-full h-full object-cover" />
        </div>
        <div className="bg-slate-900/90 backdrop-blur-md border border-slate-800 p-12 rounded-[3rem] shadow-2xl w-full max-w-md relative z-10 text-center">
          <div className="w-24 h-24 bg-amber-500 rounded-[2rem] flex items-center justify-center text-slate-950 mx-auto mb-8 shadow-2xl shadow-amber-500/20">
            <Medal size={48} strokeWidth={2.5} />
          </div>
          <h1 className="text-4xl font-black text-white mb-2 uppercase tracking-tighter italic leading-none">DOJÔ MASTER</h1>
          <p className="text-slate-500 mb-10 font-bold uppercase text-xs tracking-[0.3em]">Gestão Elite Jiu-Jitsu</p>

          <div className="space-y-4">
            <button onClick={() => login('admin')} className="w-full flex items-center justify-center space-x-3 bg-white text-slate-950 font-black py-5 rounded-2xl hover:bg-slate-100 transition shadow-xl">
              <ShieldCheck size={20} />
              <span className="uppercase text-sm tracking-wider">Mestre (Admin)</span>
            </button>
            <button onClick={() => login('professor')} className="w-full flex items-center justify-center space-x-3 bg-slate-800 text-white font-black py-5 rounded-2xl hover:bg-slate-700 transition">
              <UserIcon size={20} />
              <span className="uppercase text-sm tracking-wider">Professor</span>
            </button>
            <button onClick={() => login('student')} className="w-full flex items-center justify-center space-x-3 bg-slate-800 text-white font-black py-5 rounded-2xl hover:bg-slate-700 transition">
              <Users size={20} />
              <span className="uppercase text-sm tracking-wider">Atleta</span>
            </button>
          </div>
        </div>
      </div>
    );
  }

  const currentAttendance = attendanceRecords.find(r => r.date === selectedDate)?.athleteIds || [];

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-950 text-slate-100 selection:bg-amber-500 selection:text-slate-950">
      {/* Mobile Header */}
      <div className="md:hidden flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800 sticky top-0 z-40">
        <div className="flex items-center space-x-2">
          <Medal className="text-amber-500" size={24} />
