                <button onClick={() => setIsMuralModalOpen(false)} className="w-full text-slate-500 font-black py-4 uppercase text-[10px] tracking-widest">
                  Cancelar
                </button>
              </div>
            </div>
          </div>
        )}

      </main>
    </div>
  );
};

