  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [athletes, setAthletes] = useState<Athlete[]>(MOCK_ATHLETES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_FINANCE);
  const [muralPhotos, setMuralPhotos] = useState<MuralPhoto[]>(MOCK_MURAL);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [athleteFilter, setAthleteFilter] = useState<AgeCategory | 'Todos'>('Todos');
  const [financeInsight, setFinanceInsight] = useState<string>('');
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // Modais e Forms
  const [isAthleteModalOpen, setIsAthleteModalOpen] = useState(false);
  const [isReceiptModalOpen, setIsReceiptModalOpen] = useState(false);
  const [isMuralModalOpen, setIsMuralModalOpen] = useState(false);

  const [newAthleteData, setNewAthleteData] = useState<Partial<Athlete>>({
    name: '',
    birthDate: '',
    paymentDay: 10,
    status: 'active',
    belt: 'Branca',
    degrees: 0,
    category: 'Adulto',
    phone: '',
    emergencyContact: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);
  const muralInputRef = useRef<HTMLInputElement>(null);
  const medicalDocInputRef = useRef<HTMLInputElement>(null);

  const login = (role: UserRole) => {
    const user: User = {
      id: role === 'student' ? '2' : 'u1',
      name: role === 'admin' ? 'Mestre Hélio' : role === 'professor' ? 'Prof. Carlos' : 'Atleta Ana',
      email: `${role}@escola.com`,
      role: role,
      belt: role === 'admin' ? 'Preta' : role === 'professor' ? 'Preta' : 'Azul',
      degrees: role === 'student' ? 4 : 0
    };
    setCurrentUser(user);
    setView(AppView.Dashboard);
  };

  useEffect(() => {
    if (currentUser?.role === 'admin' && view === AppView.Dashboard) {
      const fetchInsight = async () => {
        setIsLoadingInsight(true);
        const advice = await getFinancialAdvice(transactions);
        setFinanceInsight(advice || '');
        setIsLoadingInsight(false);
      };
      fetchInsight();
    }
  }, [currentUser, transactions, view]);

  const stats = useMemo(() => {
    const income = transactions.filter(t => t.type === 'income' && t.status === 'verified').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { income, expense, balance: income - expense };
  }, [transactions]);

  const paymentAlerts = useMemo(() => {
    const today = new Date().getDate();
    return athletes.filter(a => a.status === 'active' && Math.abs(a.paymentDay - today) <= 3);
  }, [athletes]);

  const birthdaysThisMonth = useMemo(() => {
    const currentMonth = new Date().getUTCMonth() + 1;
    return athletes.filter(a => (new Date(a.birthDate).getUTCMonth() + 1) === currentMonth);
  }, [athletes]);

  const toggleAttendance = (athleteId: string) => {
    setAttendanceRecords(prev => {
      const recordIndex = prev.findIndex(r => r.date === selectedDate);
      if (recordIndex === -1) {
        return [...prev, { id: Date.now().toString(), date: selectedDate, athleteIds: [athleteId] }];
      }
      const newRecords = [...prev];
      const currentIds = newRecords[recordIndex].athleteIds;
      if (currentIds.includes(athleteId)) {
        newRecords[recordIndex].athleteIds = currentIds.filter(id => id !== athleteId);
      } else {
        newRecords[recordIndex].athleteIds = [...currentIds, athleteId];
      }
      return newRecords;
    });
    setAthletes(prev => prev.map(a => a.id === athleteId ? { ...a, attendanceCount: a.attendanceCount + 1 } : a));
  };

  const handleCreateAthlete = () => {
    if (!newAthleteData.name || !newAthleteData.birthDate) {
      alert("Preencha o nome e data de nascimento!");
      return;
    }
    const athlete: Athlete = {
      id: Date.now().toString(),
      name: newAthleteData.name,
      birthDate: newAthleteData.birthDate,
      joinDate: new Date().toISOString().split('T')[0],
      paymentDay: newAthleteData.paymentDay || 10,
      status: 'active',
      attendanceCount: 0,
      lastPaymentDate: '',
      belt: (newAthleteData.belt as Belt) || 'Branca',
      degrees: newAthleteData.degrees || 0,
      category: (newAthleteData.category as AgeCategory) || 'Adulto',
      phone: newAthleteData.phone,
      emergencyContact: newAthleteData.emergencyContact,
      medicalDocUrl: newAthleteData.medicalDocUrl
    };
    setAthletes([...athletes, athlete]);
    setIsAthleteModalOpen(false);
    setNewAthleteData({ name: '', birthDate: '', paymentDay: 10, status: 'active', belt: 'Branca', degrees: 0, category: 'Adulto', phone: '', emergencyContact: '', medicalDocUrl: undefined });
  };

  const handleMedicalDocUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Simulação de upload salvando como DataURL
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewAthleteData(prev => ({ ...prev, medicalDocUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div 
        className={`h-6 w-20 rounded shadow-sm border border-slate-300 relative overflow-hidden flex items-center justify-end px-1`}
        style={{ backgroundColor: BELT_COLORS[belt] }}
      >
        <div className="absolute left-0 h-full w-4 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => (
            <div key={i} className="h-4 w-1 bg-white"></div>
          ))}
        </div>
      </div>
      <span className="text-[10px] font-bold uppercase text-slate-500 mt-1">{belt}</span>
    </div>
  );

  const canAccess = (roles: UserRole[]) => currentUser && roles.includes(currentUser.role);

  const NavItem = ({ target, icon: Icon, label, roles }: { target: AppView, icon: any, label: string, roles: UserRole[] }) => {
    if (!canAccess(roles)) return null;
    return (
      <button
        onClick={() => { setView(target); setIsSidebarOpen(false); }}
        className={`flex items-center space-x-3 w-full p-4 rounded-xl transition-all ${
          view === target ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:bg-slate-800'
        }`}
      >
        <Icon size={20} />
        <span className="font-bold uppercase text-xs tracking-widest">{label === 'Dashboard' ? 'Sala de Entrada' : label}</span>
      </button>
    );
  };

  if (view === AppView.Login) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950 p-6 relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none grayscale">
           <img src="https://images.unsplash.com/photo-1552072092-7f9b8d63efcb?q=80&w=2070&auto=format&fit=crop" alt="BJJ" className="w-full h-full object-cover" />
        </div>

        <div className="bg-slate-900/90 backdrop-blur-md border border-slate-800 p-10 rounded-[2.5rem] shadow-2xl w-full max-w-md relative z-10">
          <div className="w-20 h-20 bg-amber-500 rounded-3xl flex items-center justify-center text-slate-950 mx-auto mb-8 shadow-2xl shadow-amber-500/10">
            <Medal size={40} strokeWidth={2.5} />
          </div>

          <h1 className="text-3xl font-black text-white text-center mb-1 uppercase tracking-tighter italic">DOJÔ MASTER</h1>
          <p className="text-slate-500 text-center mb-10 font-bold uppercase text-[10px] tracking-[0.4em]">Gestão Elite Jiu-Jitsu</p>

          {!isRegistering ? (
            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">E-mail</label>
                <input type="email" placeholder="seu@email.com" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-amber-500/50" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">Senha</label>
                <input type="password" placeholder="••••••••" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-amber-500/50" />
              </div>
              <button onClick={() => login('admin')} className="w-full bg-white text-slate-950 font-black py-5 rounded-2xl hover:bg-slate-100 transition shadow-xl uppercase tracking-widest text-xs mt-4">
                Entrar no Dojô
              </button>
              <p className="text-center text-slate-500 text-xs mt-6 font-bold">
                Não tem conta? <button onClick={() => setIsRegistering(true)} className="text-amber-500 hover:underline">Cadastre-se</button>
              </p>
            </div>
          ) : (
            <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">Nome Completo</label>
                <input type="text" placeholder="Nome Completo" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">E-mail</label>
                <input type="email" placeholder="seu@email.com" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">Senha</label>
                  <input type="password" placeholder="••••••••" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-2">Nível</label>
                  <select className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none appearance-none font-bold text-xs uppercase">
                    <option value="student">Atleta</option>
                    <option value="professor">Professor</option>
                  </select>
                </div>
              </div>
              <button onClick={() => setIsRegistering(false)} className="w-full bg-amber-500 text-slate-950 font-black py-5 rounded-2xl hover:bg-amber-400 transition shadow-xl uppercase tracking-widest text-xs mt-4">
                Criar Minha Conta
              </button>
              <p className="text-center text-slate-500 text-xs mt-6 font-bold">
                Já tem conta? <button onClick={() => setIsRegistering(false)} className="text-amber-500 hover:underline">Faça Login</button>
              </p>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-slate-950 text-slate-100">
      {/* Mobile Sidebar Toggle */}
      <div className="md:hidden flex items-center justify-between p-4 bg-slate-900 border-b border-slate-800 sticky top-0 z-40">
        <div className="flex items-center space-x-2">
          <Medal className="text-amber-500" size={24} />
          <h1 className="text-lg font-black tracking-tighter uppercase italic text-white">Dojô Master</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-400">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 transition-transform duration-200 ease-in-out
        w-72 bg-slate-900 border-r border-slate-800 p-8 z-50 flex flex-col gap-8
      `}>
        <div className="hidden md:flex items-center space-x-4 mb-4">
          <div className="w-12 h-12 bg-amber-500 rounded-2xl flex items-center justify-center text-slate-950 shadow-xl shadow-amber-500/10">
            <Medal size={28} strokeWidth={2} />
          </div>
          <h1 className="text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">Dojô<br/>Master</h1>
        </div>

        <nav className="flex-1 space-y-3">
          <NavItem target={AppView.Dashboard} icon={Home} label="Dashboard" roles={['admin', 'professor', 'student']} />
          <NavItem target={AppView.Athletes} icon={Users} label="Atletas" roles={['admin', 'professor']} />
          <NavItem target={AppView.Attendance} icon={CalendarCheck} label="Treinos" roles={['admin', 'professor']} />
          <NavItem target={AppView.Finance} icon={DollarSign} label="Financeiro" roles={['admin', 'student']} />
          <NavItem target={AppView.Mural} icon={Camera} label="Mural" roles={['admin', 'professor', 'student']} />
          <NavItem target={AppView.Ranking} icon={Trophy} label="Ranking" roles={['admin', 'professor', 'student']} />
        </nav>

        <div className="mt-auto pt-8 border-t border-slate-800">
          <div className="flex items-center space-x-4 mb-6 p-3 bg-slate-800/50 rounded-2xl border border-slate-700/50">
            <div className="w-10 h-10 rounded-xl bg-slate-700 flex items-center justify-center border border-amber-500/20">
              <UserIcon size={20} className="text-amber-500" />
            </div>
            <div className="overflow-hidden">
              <p className="text-[11px] font-black truncate text-white uppercase italic">{currentUser?.name}</p>
              <p className="text-[9px] text-slate-500 font-bold uppercase tracking-widest">{currentUser?.role}</p>
            </div>
          </div>
          <button onClick={() => { setCurrentUser(null); setView(AppView.Login); }} className="flex items-center justify-center space-x-3 text-slate-500 hover:text-red-500 transition-all text-[10px] font-black uppercase tracking-widest w-full py-2">
            <LogOut size={16} />
            <span>Sair do Sistema</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-y-auto p-4 md:p-12">

        {/* Sala de Entrada (Dashboard) */}
        {view === AppView.Dashboard && (
          <div className="space-y-10 animate-in fade-in duration-500">
            <header>
              <h2 className="text-4xl font-black text-white uppercase italic tracking-tighter leading-none">Sala de Entrada</h2>
              <p className="text-slate-500 mt-2 font-bold uppercase text-[10px] tracking-[0.2em]">Visão Geral do Dojô</p>
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              {/* Mix Column 1: Stats & Alerts */}
              <div className="lg:col-span-2 space-y-8">
                {/* Info Mix Cards */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                  {canAccess(['admin']) && (
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 flex items-center space-x-6">
                      <div className="p-4 bg-emerald-500/10 text-emerald-500 rounded-2xl"><TrendingUp size={24} /></div>
                      <div>
                        <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-1">Saldo Caixa</p>
                        <p className="text-2xl font-black text-white">R$ {stats.balance.toLocaleString()}</p>
                      </div>
                    </div>
                  )}
                  <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 flex items-center space-x-6">
                    <div className="p-4 bg-amber-500/10 text-amber-500 rounded-2xl"><Users size={24} /></div>
                    <div>
                      <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-1">Atletas</p>
                      <p className="text-2xl font-black text-white">{athletes.length}</p>
                    </div>
                  </div>
                </div>

                {/* Gemini Insights */}
                {canAccess(['admin']) && (
                  <div className="bg-amber-500 text-slate-950 p-10 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
                    <div className="relative z-10">
                      <h3 className="text-xl font-black uppercase italic tracking-tighter mb-4 flex items-center space-x-2">
                        <Star size={24} />
                        <span>Insight Estratégico AI</span>
                      </h3>
                      <p className="text-slate-900 font-bold leading-relaxed italic text-lg">
                        "{financeInsight || "Processando dados do tatame para otimizar sua gestão..."}"
                      </p>
                    </div>
                    <Medal size={160} className="absolute -bottom-10 -right-10 opacity-20 transform rotate-12" />
                  </div>
                )}

                {/* Recent Mural Snapshot */}
                <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800">
                  <div className="flex items-center justify-between mb-6">
                    <h3 className="text-lg font-black uppercase italic tracking-tighter text-white">Últimos Registros</h3>
                    <button onClick={() => setView(AppView.Mural)} className="text-[10px] font-black text-amber-500 uppercase tracking-widest hover:underline">Ver Mural</button>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    {muralPhotos.slice(0, 2).map(p => (
                      <div key={p.id} className="relative h-40 rounded-2xl overflow-hidden group">
                        <img src={p.url} className="w-full h-full object-cover group-hover:scale-110 transition duration-500" alt="Mural" />
                        <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent p-4 flex items-end">
                          <p className="text-white text-[10px] font-bold italic truncate">{p.caption}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              {/* Mix Column 2: Side Activities */}
              <div className="space-y-8">
                {/* Birthdays */}
                <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800">
                  <h3 className="text-lg font-black uppercase italic tracking-tighter text-white mb-6 flex items-center space-x-2">
                    <Cake className="text-pink-500" size={20} />
                    <span>Aniversariantes</span>
                  </h3>
                  <div className="space-y-4">
                    {birthdaysThisMonth.map(a => (
                      <div key={a.id} className="flex items-center space-x-4">
                        <div className="w-10 h-10 rounded-xl bg-pink-500/10 text-pink-500 flex items-center justify-center font-black">
                          {a.name.charAt(0)}
                        </div>
                        <div>
                          <p className="text-sm font-bold text-white leading-none">{a.name}</p>
                          <p className="text-[10px] text-slate-500 font-bold uppercase mt-1">Dia {new Date(a.birthDate).getUTCDate()}</p>
                        </div>
                      </div>
                    ))}
                    {birthdaysThisMonth.length === 0 && <p className="text-slate-500 text-xs italic">Nenhum atleta este mês.</p>}
                  </div>
                </div>

                {/* Training Stats (Individual or General) */}
                <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800">
                  <h3 className="text-lg font-black uppercase italic tracking-tighter text-white mb-6 flex items-center space-x-2">
                    <Activity className="text-indigo-500" size={20} />
                    <span>Frequência Elite</span>
                  </h3>
                  <div className="space-y-6">
                    {athletes.sort((a,b) => b.attendanceCount - a.attendanceCount).slice(0, 3).map((a, i) => (
                      <div key={a.id} className="flex items-center justify-between">
                        <div className="flex items-center space-x-3">
                          <span className="text-xs font-black text-slate-500">#{i+1}</span>
                          <p className="text-xs font-bold text-white uppercase italic">{a.name}</p>
                        </div>
                        <span className="text-[10px] font-black bg-indigo-500/10 text-indigo-500 px-2 py-1 rounded-lg">
                          {a.attendanceCount} TREINOS
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Atletas - CATEGORIZADO */}
        {view === AppView.Athletes && canAccess(['admin', 'professor']) && (
          <div className="space-y-8 animate-in fade-in duration-300">
            <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
              <div>
                <h2 className="text-3xl font-black text-white uppercase italic tracking-tighter">Gestão de Atletas</h2>
                <div className="flex items-center space-x-4 mt-2">
                  <button 
                    onClick={() => setAthleteFilter('Todos')}
                    className={`text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-xl transition ${athleteFilter === 'Todos' ? 'bg-amber-500 text-slate-950' : 'bg-slate-900 text-slate-500'}`}
                  >
                    Todos
                  </button>
                  <button 
                    onClick={() => setAthleteFilter('Adulto')}
                    className={`text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-xl transition ${athleteFilter === 'Adulto' ? 'bg-indigo-500 text-white' : 'bg-slate-900 text-slate-500'}`}
                  >
                    Adultos
                  </button>
                  <button 
                    onClick={() => setAthleteFilter('Infantil')}
                    className={`text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-xl transition ${athleteFilter === 'Infantil' ? 'bg-emerald-500 text-white' : 'bg-slate-900 text-slate-500'}`}
                  >
                    Infantil
                  </button>
                </div>
              </div>
              <button onClick={() => setIsAthleteModalOpen(true)} className="flex items-center justify-center space-x-3 bg-amber-500 text-slate-950 px-8 py-4 rounded-2xl font-black uppercase text-xs shadow-xl hover:bg-amber-400 transition">
                <UserPlus size={18} />
                <span>Novo Aluno</span>
              </button>
            </header>

            <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-800/50 text-[10px] uppercase font-black tracking-widest text-slate-500 border-b border-slate-800">
                    <tr>
                      <th className="px-8 py-6">Atleta</th>
                      <th className="px-8 py-6 text-center">Faixa</th>
                      <th className="px-8 py-6">Categoria</th>
                      <th className="px-8 py-6">Contato</th>
                      <th className="px-8 py-6">Doc. Médico</th>
                      <th className="px-8 py-6 text-right">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-800/50">
                    {athletes
                      .filter(a => athleteFilter === 'Todos' || a.category === athleteFilter)
                      .map(athlete => (
                      <tr key={athlete.id} className="hover:bg-slate-800/30 transition-colors group">
                        <td className="px-8 py-6">
                          <div className="flex items-center space-x-5">
                            <div className="w-12 h-12 rounded-2xl bg-slate-800 flex items-center justify-center font-black text-slate-500 border border-slate-700">
                              {athlete.name.charAt(0)}
                            </div>
                            <div>
                              <p className="font-black text-white uppercase italic tracking-tighter">{athlete.name}</p>
                              <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">{new Date(athlete.birthDate).toLocaleDateString()}</p>
                            </div>
                          </div>
                        </td>
                        <td className="px-8 py-6">
