                  <button onClick={() => setAthleteFilter('Adulto')} className={`text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-xl transition ${athleteFilter === 'Adulto' ? 'bg-indigo-500 text-white' : 'bg-slate-900 text-slate-500'}`}>Adultos</button>
                  <button onClick={() => setAthleteFilter('Infantil')} className={`text-[10px] font-black uppercase tracking-widest px-4 py-2 rounded-xl transition ${athleteFilter === 'Infantil' ? 'bg-emerald-500 text-white' : 'bg-slate-900 text-slate-500'}`}>Infantil</button>
