                            </div>
                          </div>
                        </td>
                        <td className="px-8 py-6">
                          <BeltBadge belt={athlete.belt} degrees={athlete.degrees} />
                        </td>
                        <td className="px-8 py-6">
                          <span className={`px-3 py-1 rounded-lg text-[10px] font-black uppercase ${
                            athlete.category === 'Adulto' ? 'bg-indigo-500/10 text-indigo-400' : 'bg-emerald-500/10 text-emerald-400'
