              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] px-2">Data de Nascimento</label>
                <input 
                  type="date" 
                  value={newAthleteData.birthDate}
                  onChange={e => setNewAthleteData({...newAthleteData, birthDate: e.target.value})}
                  className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-amber-500" 
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] px-2">Categoria</label>
                <select 
                  value={newAthleteData.category}
                  onChange={e => setNewAthleteData({...newAthleteData, category: e.target.value as AgeCategory, belt: 'Branca'})}
                  className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none appearance-none font-bold uppercase text-xs"
                >
                  <option value="Adulto">Adulto</option>
                  <option value="Infantil">Infantil (Kids)</option>
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] px-2">Faixa Atual</label>
                <select 
                  value={newAthleteData.belt}
                  onChange={e => setNewAthleteData({...newAthleteData, belt: e.target.value as Belt})}
                  className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none appearance-none font-bold uppercase text-xs"
                >
                  {newAthleteData.category === 'Adulto' 
                    ? ADULTO_BELTS.map(b => <option key={b} value={b}>{b}</option>)
                    : INFANTIL_BELTS.map(b => <option key={b} value={b}>{b}</option>)
                  }
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] px-2">Graus</label>
                <select 
                  value={newAthleteData.degrees}
                  onChange={e => setNewAthleteData({...newAthleteData, degrees: parseInt(e.target.value)})}
                  className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none appearance-none font-bold uppercase text-xs"
                >
                  {[0,1,2,3,4].map(d => <option key={d} value={d}>{d} Graus</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] px-2">Telefone</label>
                <input 
                  type="text" 
                  value={newAthleteData.phone}
                  onChange={e => setNewAthleteData({...newAthleteData, phone: e.target.value})}
                  className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" 
                  placeholder="(00) 00000-0000"
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] px-2">Vencimento Mensalidade</label>
                <input 
                  type="number" 
                  min="1" max="28"
                  value={newAthleteData.paymentDay}
                  onChange={e => setNewAthleteData({...newAthleteData, paymentDay: parseInt(e.target.value)})}
                  className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" 
                />
              </div>

              <div className="md:col-span-2 space-y-2">
                <label className="text-[10px] font-black uppercase text-slate-500 tracking-[0.2em] px-2">Atestado Médico / Termo Responsabilidade</label>
                <div 
                  onClick={() => medicalDocInputRef.current?.click()}
                  className={`w-full p-8 border-2 border-dashed rounded-[2rem] flex flex-col items-center justify-center cursor-pointer transition ${
                    newAthleteData.medicalDocUrl ? 'bg-emerald-500/10 border-emerald-500' : 'bg-slate-800 border-slate-700 hover:border-amber-500'
                  }`}
                >
                  <input type="file" ref={medicalDocInputRef} className="hidden" onChange={handleMedicalDocUpload} accept="image/*,application/pdf" />
                  {newAthleteData.medicalDocUrl ? (
                    <>
                      <CheckCircle2 className="text-emerald-500 mb-2" size={32} />
                      <p className="text-emerald-500 font-black uppercase text-[10px]">Documento Anexado</p>
                    </>
                  ) : (
                    <>
                      <Upload className="text-slate-500 mb-2" size={32} />
                      <p className="text-slate-500 font-black uppercase text-[10px]">Clique para enviar arquivo</p>
                    </>
                  )}
                </div>
              </div>
            </div>

            <button onClick={handleCreateAthlete} className="w-full bg-amber-500 text-slate-950 font-black py-6 rounded-[2rem] hover:bg-amber-400 shadow-2xl shadow-amber-900/20 transition mt-10 uppercase tracking-widest italic text-sm">Matricular Guerreiro</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type UserRole = 'admin' | 'professor' | 'student';

export type AgeCategory = 'Infantil' | 'Adulto';

export type Belt = 
  | 'Branca' | 'Cinza' | 'Amarela' | 'Laranja' | 'Verde' // Infantil
  | 'Azul' | 'Roxa' | 'Marrom' | 'Preta'; // Adulto

export type User = {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  belt?: Belt;
  degrees?: number;
  password?: string;
};

export type Athlete = {
  id: string;
  name: string;
  cpf?: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  lastPaymentDate: string;
  belt: Belt;
  degrees: number; // 0 a 4
  category: AgeCategory;
  userId?: string;
  medicalDocUrl?: string; // URL do atestado ou termo
  phone?: string;
