import { GoogleGenAI, Type } from "@google/genai";

export const getFinancialAdvice = async (transactions: any[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Você é um consultor financeiro para academias de artes marciais. Analise estas transações e forneça 3 pontos: 1. Saúde do caixa, 2. Alerta sobre inadimplência (se houver), 3. Uma estratégia de crescimento. Responda em Português de forma direta. Dados: ${JSON.stringify(transactions)}`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Aguardando processamento de dados financeiros...";
  }
};

