                    <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-1">Dia de Pagamento</label>
                    <input type="number" min="1" max="31" value={form.paymentDay} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-slate-500 tracking-widest px-1">Endereço (Rua, Número)</label>
                  <input type="text" value={form.address?.street} onChange={e => setForm({...form, address: {...form.address!, street: e.target.value}})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
                </div>
                <div className="space-y-4 pt-4">
                  <label className="flex items-start gap-3 cursor-pointer group">
                    <input type="checkbox" checked={form.termsAccepted} onChange={e => setForm({...form, termsAccepted: e.target.checked})} className="mt-1 h-5 w-5 rounded border-slate-700 bg-slate-800 text-amber-500" />
                    <div className="flex-1">
                      <p className="text-[10px] font-black text-white uppercase tracking-widest">Termo de Responsabilidade</p>
                      <p className="text-[9px] text-slate-500 uppercase leading-relaxed mt-1">Declaro estar apto para atividades físicas de alto impacto e ciente dos riscos inerentes ao Jiu-Jitsu.</p>
                    </div>
                  </label>
                </div>
              </div>
            </div>

            <div className="flex gap-4 mt-12">
              <button onClick={() => setIsModalOpen(false)} className="flex-1 p-6 border border-slate-800 rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-slate-800 transition">Cancelar</button>
              <button onClick={saveAthlete} className="flex-[2] bg-amber-500 text-slate-950 font-black p-6 rounded-2xl hover:bg-amber-400 shadow-2xl transition uppercase tracking-widest italic text-sm flex items-center justify-center gap-2">
                <Save size={18} /> {editId ? 'Atualizar Guerreiro' : 'Matricular Guerreiro'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

