        const updatedRecords = [...prev];
        const currentIds = updatedRecords[recordIndex].athleteIds;
        if (currentIds.includes(athleteId)) {
          updatedRecords[recordIndex].athleteIds = currentIds.filter(id => id !== athleteId);
        } else {
          updatedRecords[recordIndex].athleteIds = [...currentIds, athleteId];
