  { id: 't2', type: 'expense', amount: 1200, date: '2024-05-20', description: 'Aluguel do Dojô', category: 'Fixa', status: 'verified' },
  { id: 't3', type: 'income', amount: 350, date: '2024-05-24', description: 'Mensalidade - Ana Souza', category: 'Mensalidade', status: 'verified', athleteId: '2' },
];

const BELT_COLORS: Record<Belt, string> = {
  'Branca': '#ffffff', 'Cinza': '#94a3b8', 'Amarela': '#facc15', 'Laranja': '#fb923c', 'Verde': '#22c55e',
  'Azul': '#1d4ed8', 'Roxa': '#7e22ce', 'Marrom': '#78350f', 'Preta': '#000000'
};

const GoogleIcon = () => (
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
    <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
    <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
    <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/>
    <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
  </svg>
);

const App: React.FC = () => {
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [athletes, setAthletes] = useState<Athlete[]>(MOCK_ATHLETES);
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_FINANCE);
  const [muralPhotos, setMuralPhotos] = useState<MuralPhoto[]>(MOCK_MURAL);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');

  // Athlete Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<Partial<Athlete>>({});

  // Finance Modal
  const [isFinanceModalOpen, setIsFinanceModalOpen] = useState(false);
  const [financeForm, setFinanceForm] = useState<Partial<Transaction>>({ type: 'income', category: 'Mensalidade', date: new Date().toISOString().split('T')[0] });

  // Mural Modal
  const [isMuralModalOpen, setIsMuralModalOpen] = useState(false);
  const [muralForm, setMuralForm] = useState<Partial<MuralPhoto>>({ date: new Date().toISOString().split('T')[0] });

  const [selectedAttendanceDate, setSelectedAttendanceDate] = useState<string>(new Date().toISOString().split('T')[0]);

  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin') {
      getFinancialAdvice(transactions).then(setAiInsight);
    }
  }, [view, transactions, user]);

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const latePayments = athletes.filter(a => a.status === 'active' && (today > a.paymentDay));
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, latePayments, income, expense, balance: income - expense };
  }, [athletes, transactions]);

  const ranking = useMemo(() => {
    return [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
  }, [athletes]);

  const loggedInAthlete = useMemo(() => {
    if (user?.role === 'student' && user?.athleteId) {
      return athletes.find(a => a.id === user.athleteId);
    }
    return null;
  }, [user, athletes]);

  const currentAttendance = useMemo(() => {
    return attendanceRecords.find(r => r.date === selectedAttendanceDate)?.athleteIds || [];
  }, [attendanceRecords, selectedAttendanceDate]);

  const handleLogin = (role: string, athleteId?: string) => {
    if (role === 'admin') {
      setUser({ name: 'Mestre Hélio', role: 'admin' });
    } else {
      const ath = athletes.find(a => a.id === athleteId) || athletes[1]; // Fallback para Ana Souza
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
    }
    setView(AppView.Dashboard);
  };

  const openModal = (ath?: Athlete) => {
    if (ath) {
      setEditId(ath.id);
      setForm(ath);
    } else {
      setEditId(null);
      setForm({
        name: '', birthDate: '', paymentDay: 10, category: 'Adulto', belt: 'Branca',
        degrees: 0, phone: '', termsAccepted: false, address: INITIAL_ADDRESS, 
        emergencyContact: '', emergencyPhone: '', bloodType: '', cpf: '', medicalNotes: ''
      });
    }
    setIsModalOpen(true);
  };

  const saveAthlete = () => {
    if (!form.name || !form.cpf || !form.termsAccepted) return alert("Nome, CPF e Termos são obrigatórios!");

    if (editId) {
      setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } as Athlete : a));
    } else {
      const newAth = { ...form, id: Date.now().toString(), joinDate: new Date().toISOString().split('T')[0], attendanceCount: 0, status: 'active' } as Athlete;
      setAthletes(prev => [...prev, newAth]);
    }
    setIsModalOpen(false);
  };

  const saveTransaction = () => {
    if (!financeForm.amount || !financeForm.description) return alert("Valor e descrição são obrigatórios!");
    const newTrans = { ...financeForm, id: Date.now().toString(), status: 'verified' } as Transaction;
    setTransactions(prev => [newTrans, ...prev]);
    setIsFinanceModalOpen(false);
  };

  const saveMuralPost = () => {
    if (!muralForm.url || !muralForm.caption) return alert("URL da imagem e legenda são obrigatórios!");
    const newPost = { ...muralForm, id: Date.now().toString(), postedBy: user?.name || 'Mestre' } as MuralPhoto;
    setMuralPhotos(prev => [newPost, ...prev]);
    setIsMuralModalOpen(false);
  };

  const toggleAttendance = (athleteId: string) => {
    setAttendanceRecords(prev => {
      const recordIndex = prev.findIndex(r => r.date === selectedAttendanceDate);
      if (recordIndex === -1) {
        return [...prev, { id: Date.now().toString(), date: selectedAttendanceDate, athleteIds: [athleteId] }];
      } else {
        const updatedRecords = [...prev];
        const currentIds = updatedRecords[recordIndex].athleteIds;
        if (currentIds.includes(athleteId)) {
          updatedRecords[recordIndex].athleteIds = currentIds.filter(id => id !== athleteId);
        } else {
          updatedRecords[recordIndex].athleteIds = [...currentIds, athleteId];
        }
        return updatedRecords;
      }
    });

    setAthletes(prev => prev.map(a => {
      if (a.id === athleteId) {
        const isCurrentlyPresent = currentAttendance.includes(athleteId);
        return { ...a, attendanceCount: isCurrentlyPresent ? a.attendanceCount - 1 : a.attendanceCount + 1 };
      }
      return a;
    }));
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-5 w-16 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-1" style={{ backgroundColor: BELT_COLORS[belt] }}>
        <div className="absolute left-0 h-full w-3 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-3 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[8px] font-bold uppercase text-slate-500 mt-1">{belt}</span>
    </div>
  );

  const NavItem = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => {
    const active = view === target;
    return (
      <button onClick={() => { setView(target); setIsSidebarOpen(false); }} className={`w-full flex items-center space-x-3 p-4 rounded-xl transition font-black uppercase text-[10px] tracking-widest ${active ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}>
        <Icon size={18} /> <span>{label}</span>
      </button>
    );
  };

  if (view === AppView.Login) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 font-['Inter']">
        <div className="max-w-md w-full bg-slate-900 rounded-[2.5rem] border border-slate-800 p-10 shadow-2xl">
          <Medal className="text-amber-500 mx-auto mb-6" size={56} />
          <h1 className="text-3xl font-black text-white text-center tracking-tighter italic uppercase mb-12">Dojô Master</h1>
          <div className="space-y-4">
            <button onClick={() => handleLogin('student', '2')} className="w-full flex items-center justify-center space-x-3 bg-white text-slate-950 font-black py-4 rounded-2xl hover:bg-slate-100 transition shadow-xl border-b-4 border-slate-300">
              <GoogleIcon /> <span className="uppercase text-xs tracking-widest">Entrar como Aluno</span>
            </button>
            <div className="text-center text-[10px] font-black text-slate-600 uppercase py-2">ACESSO ADMINISTRATIVO</div>
            <button onClick={() => handleLogin('admin')} className="w-full bg-amber-500 text-slate-950 font-black py-5 rounded-2xl hover:bg-amber-400 transition uppercase text-xs tracking-widest italic">Acesso Mestre</button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter'] relative">
      <div className="md:hidden fixed top-4 right-4 z-[110]">
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-3 bg-slate-900 rounded-2xl text-amber-500 shadow-xl border border-slate-800">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      <aside className={`fixed inset-y-0 left-0 transform ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition-transform w-72 bg-slate-900 border-r border-slate-800 p-8 z-50 flex flex-col gap-8`}>
        <div className="flex items-center space-x-3">
          <Medal className="text-amber-500" size={32} />
          <span className="text-xl font-black uppercase italic tracking-tighter">Dojô Master</span>
        </div>
        <nav className="flex-1 space-y-2">
          <NavItem target={AppView.Dashboard} icon={Home} label="Sala de Entrada" />
          {user?.role === 'admin' && (
            <>
              <NavItem target={AppView.Athletes} icon={Users} label="Atletas" />
              <NavItem target={AppView.Attendance} icon={CalendarCheck} label="Treinos" />
              <NavItem target={AppView.Finance} icon={DollarSign} label="Financeiro" />
            </>
          )}
          <NavItem target={AppView.Mural} icon={Camera} label="Mural" />
          <NavItem target={AppView.Ranking} icon={Trophy} label="Ranking" />
        </nav>
        <button onClick={() => setView(AppView.Login)} className="flex items-center space-x-2 text-slate-500 hover:text-red-500 transition font-black text-[10px] uppercase"><LogOut size={16} /> <span>Encerrar</span></button>
      </aside>

      <main className="flex-1 overflow-y-auto p-6 md:p-12 relative">
        {view === AppView.Dashboard && (
          <div className="space-y-10 animate-in fade-in duration-500">
            <header className="flex flex-col md:flex-row justify-between md:items-end gap-4">
              <div>
                <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter">Sala de Entrada</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-[0.3em] mt-1">
                  {user?.role === 'admin' ? 'Painel do Mestre' : 'Área do Aluno'}
                </p>
              </div>
              <div className="text-left md:text-right">
                <p className="text-xs font-black text-amber-500 uppercase italic">Oss, {user?.name}</p>
                <p className="text-[10px] text-slate-600 font-bold uppercase">{new Date().toLocaleDateString('pt-BR', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</p>
              </div>
            </header>

            {user?.role === 'admin' ? (
              /* DASHBOARD MESTRE (ORIGINAL) */
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 relative overflow-hidden group">
                  <div className="relative z-10">
                    <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-2">Total de Atletas</p>
                    <p className="text-3xl font-black text-white">{athletes.length}</p>
                  </div>
                  <Users className="absolute -bottom-4 -right-4 text-slate-800 opacity-20 group-hover:scale-110 transition" size={100} />
                </div>
                <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 relative overflow-hidden group border-b-amber-500/50">
                  <div className="relative z-10">
                    <p className="text-[10px] font-black uppercase text-amber-500 tracking-widest mb-2">Alertas de Pagamento</p>
                    <p className="text-3xl font-black text-white">{stats.imminentPayments.length}</p>
                    <p className="text-[9px] font-bold text-slate-500 uppercase mt-1">Vencimento próximo</p>
                  </div>
                  <AlertTriangle className="absolute -bottom-4 -right-4 text-amber-500 opacity-10" size={100} />
                </div>
                <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 relative overflow-hidden group border-b-emerald-500/50">
                  <div className="relative z-10">
                    <p className="text-[10px] font-black uppercase text-emerald-500 tracking-widest mb-2">Fluxo de Caixa</p>
                    <p className="text-3xl font-black text-white">R$ {stats.balance.toLocaleString()}</p>
                    <p className="text-[9px] font-bold text-slate-500 uppercase mt-1">Saldo Atual</p>
                  </div>
                  <TrendingUp className="absolute -bottom-4 -right-4 text-emerald-500 opacity-10" size={100} />
                </div>
              </div>
            ) : (
              /* DASHBOARD ALUNO (SOLICITADO) */
              <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
                {/* Perfil e Foto do Aluno */}
                <div className="md:col-span-4 bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 text-center flex flex-col items-center">
                  <div className="w-32 h-32 rounded-[2.5rem] bg-slate-800 border-4 border-amber-500/30 overflow-hidden mb-6 shadow-2xl relative">
                    <img 
                      src={`https://ui-avatars.com/api/?name=${encodeURIComponent(user?.name || '')}&background=f59e0b&color=fff&size=256&bold=true`} 
                      alt="Profile" 
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute bottom-2 right-2 bg-amber-500 p-1.5 rounded-lg text-slate-950">
                      <Camera size={14} />
                    </div>
                  </div>
                  <h3 className="text-xl font-black text-white uppercase italic tracking-tighter mb-2">{user?.name}</h3>
                  <div className="mb-4">
                    <BeltBadge belt={loggedInAthlete?.belt || 'Branca'} degrees={loggedInAthlete?.degrees || 0} />
                  </div>
                  <div className="w-full bg-slate-800/50 p-4 rounded-2xl flex justify-around mt-4">
                    <div className="text-center">
                      <p className="text-[9px] font-black uppercase text-slate-500 tracking-widest">Treinos</p>
                      <p className="text-lg font-black text-white">{loggedInAthlete?.attendanceCount || 0}</p>
                    </div>
                    <div className="w-[1px] bg-slate-700"></div>
                    <div className="text-center">
                      <p className="text-[9px] font-black uppercase text-slate-500 tracking-widest">Status</p>
                      <p className="text-lg font-black text-emerald-500 uppercase italic">Ativo</p>
                    </div>
                  </div>
                </div>

                {/* Ranking e Pagamento */}
                <div className="md:col-span-8 flex flex-col gap-8">
                  {/* Alerta de Pagamento Individual */}
                  <div className={`p-8 rounded-[2.5rem] border relative overflow-hidden flex items-center gap-6 ${
                    (loggedInAthlete?.paymentDay || 1) < new Date().getDate() 
                    ? 'bg-red-500/10 border-red-500 text-red-500' 
                    : 'bg-emerald-500/10 border-emerald-500 text-emerald-500'
                  }`}>
                    <div className={`p-5 rounded-3xl ${
                      (loggedInAthlete?.paymentDay || 1) < new Date().getDate() 
                      ? 'bg-red-500 text-white' 
                      : 'bg-emerald-500 text-white'
                    }`}>
                      <CreditCard size={32} />
                    </div>
                    <div>
                      <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1">Status da Mensalidade</p>
                      <h4 className="text-2xl font-black uppercase italic tracking-tighter text-white">
                        {(loggedInAthlete?.paymentDay || 1) < new Date().getDate() 
                          ? `Atrasada desde o dia ${loggedInAthlete?.paymentDay}` 
                          : `Vence no dia ${loggedInAthlete?.paymentDay}`
                        }
                      </h4>
                      <p className={`text-[11px] font-bold uppercase mt-1 ${
                        (loggedInAthlete?.paymentDay || 1) < new Date().getDate() ? 'text-red-400' : 'text-emerald-400'
                      }`}>
                        {(loggedInAthlete?.paymentDay || 1) < new Date().getDate() 
                          ? 'Por favor, regularize na secretaria do Dojô.' 
                          : 'Tudo em ordem! Continue treinando firme.'
                        }
                      </p>
                    </div>
                    <AlertTriangle className="absolute -bottom-4 -right-4 opacity-10" size={120} />
                  </div>

                  {/* Seu Ranking Mensal */}
                  <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 relative overflow-hidden flex-1">
                    <div className="relative z-10">
                      <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xl font-black text-white italic uppercase tracking-tighter flex items-center gap-2">
                          <Trophy size={20} className="text-amber-500" />
                          Ranking de Frequência
                        </h3>
                        <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Maio 2024</span>
                      </div>

                      <div className="space-y-4">
                        {ranking.slice(0, 3).map((ath, idx) => (
                          <div key={ath.id} className={`flex items-center justify-between p-4 rounded-2xl ${
                            ath.id === loggedInAthlete?.id ? 'bg-amber-500/10 border border-amber-500/30' : 'bg-slate-800/30'
                          }`}>
                            <div className="flex items-center gap-4">
                              <span className={`text-sm font-black italic ${
                                idx === 0 ? 'text-amber-500' : idx === 1 ? 'text-slate-300' : 'text-orange-500'
                              }`}>#{idx + 1}</span>
                              <p className="text-xs font-black text-white uppercase italic">{ath.name}</p>
                            </div>
                            <span className="text-[10px] font-black text-amber-500 uppercase">{ath.attendanceCount} TREINOS</span>
                          </div>
                        ))}

                        {/* Se o aluno não estiver no Top 3, mostra a posição dele separada */}
                        {ranking.findIndex(a => a.id === loggedInAthlete?.id) > 2 && (
                          <>
                            <div className="flex justify-center"><span className="text-slate-600 font-black">...</span></div>
                            <div className="flex items-center justify-between p-4 rounded-2xl bg-amber-500 border border-amber-400 shadow-xl shadow-amber-900/20">
                              <div className="flex items-center gap-4">
                                <span className="text-sm font-black italic text-slate-950">#{ranking.findIndex(a => a.id === loggedInAthlete?.id) + 1}</span>
                                <p className="text-xs font-black text-slate-950 uppercase italic">{loggedInAthlete?.name} (Você)</p>
                              </div>
                              <span className="text-[10px] font-black text-slate-950 uppercase">{loggedInAthlete?.attendanceCount} TREINOS</span>
                            </div>
                          </>
                        )}
                      </div>
                    </div>
                    <Medal className="absolute -bottom-10 -right-10 text-slate-800 opacity-20" size={180} />
                  </div>
                </div>
              </div>
            )}

            {/* AI Advisor - Apenas Admin */}
            {user?.role === 'admin' && (
              <div className="bg-amber-500 text-slate-950 p-10 rounded-[2.5rem] shadow-2xl relative overflow-hidden">
                <div className="relative z-10">
                  <h3 className="text-xl font-black uppercase italic tracking-tighter mb-4 flex items-center gap-2"><Star size={24} /> Consultoria Inteligente AI</h3>
                  <p className="text-sm font-bold italic leading-relaxed">"{aiInsight || "Processando dados do tatame para otimizar sua gestão..."}"</p>
                </div>
                <Medal size={200} className="absolute -bottom-20 -right-20 opacity-20 transform rotate-12" />
              </div>
            )}
          </div>
        )}

        {/* Mantenha as outras visualizações conforme implementado anteriormente */}
        {view === AppView.Athletes && user?.role === 'admin' && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-300">
            <header className="flex justify-between items-center">
              <div>
                <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Quadro de Atletas</h2>
                <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Controle de Membros</p>
              </div>
              <button onClick={() => openModal()} className="bg-amber-500 text-slate-950 px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl flex items-center gap-2 hover:bg-amber-400 transition">
                <Plus size={18} /> Nova Matrícula
              </button>
            </header>

            <div className="bg-slate-900 rounded-[2rem] border border-slate-800 overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-800/50 text-[10px] uppercase font-black tracking-widest text-slate-500">
                    <tr>
                      <th className="px-8 py-6">Nome</th>
                      <th className="px-8 py-6">Faixa / Graus</th>
                      <th className="px-8 py-6">Categoria</th>
                      <th className="px-8 py-6">Vencimento</th>
                      <th className="px-8 py-6 text-right">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-800/50">
                    {athletes.map(ath => (
                      <tr key={ath.id} className="hover:bg-slate-800/30 transition group">
                        <td className="px-8 py-6">
                          <p className="font-black text-white uppercase italic tracking-tight">{ath.name}</p>
                          <p className="text-[10px] text-slate-500 font-bold">{ath.cpf}</p>
                        </td>
                        <td className="px-8 py-6"><BeltBadge belt={ath.belt} degrees={ath.degrees} /></td>
                        <td className="px-8 py-6">
                          <span className={`text-[9px] font-black uppercase px-3 py-1 rounded-full ${ath.category === 'Adulto' ? 'bg-indigo-500/10 text-indigo-400' : 'bg-emerald-500/10 text-emerald-400'}`}>{ath.category}</span>
                        </td>
                        <td className="px-8 py-6">
                          <div className="flex items-center gap-2">
                             <span className="text-[10px] font-black text-white">Dia {ath.paymentDay}</span>
