                      {['Branca', 'Azul', 'Roxa', 'Marrom', 'Preta', 'Cinza', 'Amarela', 'Laranja', 'Verde'].map(b => <option key={b} value={b}>{b}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-slate-500 px-1">Dia de Vencimento</label>
                    <input type="number" min="1" max="31" value={form.paymentDay} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
                  </div>
                </div>
                <div className="space-y-2 pt-4">
                  <label className="flex items-start gap-3 cursor-pointer">
                    <input type="checkbox" checked={form.termsAccepted} onChange={e => setForm({...form, termsAccepted: e.target.checked})} className="mt-1 h-5 w-5 rounded bg-slate-800 border-slate-700 text-amber-500" />
