                    </div>
                  </label>
                </div>
              </div>
            </div>
            <div className="flex gap-4 mt-12">
               <button onClick={saveAthlete} className="w-full bg-amber-500 text-slate-950 font-black p-6 rounded-2xl hover:bg-amber-400 shadow-2xl transition uppercase tracking-widest italic text-sm">Salvar Registro</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type UserRole = 'admin' | 'professor' | 'student';
export type AgeCategory = 'Infantil' | 'Adulto';
export type Belt = 
  | 'Branca' | 'Cinza' | 'Amarela' | 'Laranja' | 'Verde' 
  | 'Azul' | 'Roxa' | 'Marrom' | 'Preta';

export interface Address {
  street: string;
  number: string;
  neighborhood: string;
  city: string;
  cep: string;
}

export interface Athlete {
  id: string;
  accessId: string; // ID gerado para login do aluno
  name: string;
  email: string;
  cpf: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  belt: Belt;
  degrees: number;
  category: AgeCategory;
  phone: string;
  emergencyContact: string;
  emergencyPhone: string;
  bloodType: string;
  medicalNotes: string;
  address: Address;
  medicalDocUrl?: string;
  termsAccepted: boolean;
  profileComplete: boolean; // Flag para forçar preenchimento de dados
  lastPaymentDate?: string;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  date: string;
  description: string;
  category: string;
  athleteId?: string;
  status: 'pending' | 'verified';
  receiptUrl?: string;
}

export interface MuralPhoto {
  id: string;
  url: string;
  caption: string;
  date: string;
  postedBy: string;
}

export interface AttendanceRecord {
  id: string;
  date: string;
  athleteIds: string[];
}

export enum AppView {
  Login = 'login',
  Dashboard = 'dashboard', 
  Athletes = 'athletes',
  Attendance = 'attendance',
  Finance = 'finance',
  Ranking = 'ranking',
  Mural = 'mural',
  ProfileCompletion = 'profile-completion'
}

