                  className="w-full p-4 pl-12 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase placeholder-slate-600 outline-none focus:ring-2 focus:ring-amber-500"
                />
              </div>
            </div>
            <button 
              onClick={() => handleLogin(loginId)}
              className="w-full bg-amber-500 text-slate-950 font-black py-5 rounded-2xl hover:bg-amber-400 transition uppercase text-xs tracking-widest italic flex items-center justify-center gap-2"
            >
              Entrar no Tatame <ArrowRight size={18} />
            </button>
            <p className="text-[9px] text-slate-600 font-bold uppercase leading-relaxed">Esqueceu seu ID? Solicite ao seu professor na recepção.</p>
          </div>
        </div>
      </div>
    );
  }

  if (view === AppView.ProfileCompletion) {
    return (
      <div className="min-h-screen bg-slate-950 p-6 md:p-12 flex items-center justify-center">
        <div className="max-w-4xl w-full bg-slate-900 border border-slate-800 rounded-[3rem] p-10 md:p-16 shadow-2xl">
          <header className="mb-12 text-center">
            <div className="w-20 h-20 bg-amber-500/10 text-amber-500 rounded-3xl flex items-center justify-center mx-auto mb-6">
              <ClipboardCheck size={40} />
            </div>
            <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">Concluir Cadastro</h2>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Precisamos de algumas informações para sua segurança</p>
          </header>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <h4 className="text-[10px] font-black text-amber-500 uppercase tracking-[0.2em] border-b border-slate-800 pb-2">Dados do Aluno</h4>
              <div className="space-y-4">
                <input type="text" placeholder="CPF" value={form.cpf} onChange={e => setForm({...form, cpf: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
                <input type="date" placeholder="Nascimento" value={form.birthDate} onChange={e => setForm({...form, birthDate: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
                <input type="text" placeholder="WhatsApp" value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              </div>
            </div>

            <div className="space-y-6">
              <h4 className="text-[10px] font-black text-red-500 uppercase tracking-[0.2em] border-b border-slate-800 pb-2">Saúde & Emergência</h4>
              <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                  <input type="text" placeholder="Tipo Sanguíneo" value={form.bloodType} onChange={e => setForm({...form, bloodType: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white text-sm" />
