                </div>
                <textarea placeholder="Observações Médicas (Alergias, Lesões...)" value={form.medicalNotes} onChange={e => setForm({...form, medicalNotes: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white min-h-[100px]" />
              </div>
            </div>
          </div>

          <div className="mt-12 bg-slate-800/30 p-8 rounded-3xl border border-slate-800 flex items-start gap-4">
            <input type="checkbox" checked={form.termsAccepted} onChange={e => setForm({...form, termsAccepted: e.target.checked})} className="mt-1 h-6 w-6 rounded bg-slate-800 border-slate-700 text-amber-500" />
            <div>
              <p className="text-xs font-black text-white uppercase mb-1">Termo de Responsabilidade Médica</p>
              <p className="text-[10px] text-slate-500 uppercase leading-relaxed font-bold">Confirmo que as informações acima são verdadeiras e que estou apto a realizar atividades de alto impacto. Comprometo-me a seguir as regras do Dojô.</p>
            </div>
          </div>

          <button onClick={finalizeStudentProfile} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-2xl hover:bg-amber-400 transition uppercase tracking-widest italic shadow-2xl">Finalizar e Acessar o Portal</button>
        </div>
      </div>
    );
  }

  return (
