            <input type="checkbox" checked={form.termsAccepted} onChange={e => setForm({...form, termsAccepted: e.target.checked})} className="mt-1 h-6 w-6 rounded bg-slate-800 border-slate-700 text-amber-500" />
            <p className="text-[10px] text-slate-400 uppercase font-black">Declaro estar em perfeitas condições de saúde para prática de Jiu-Jitsu.</p>
          </div>
          <button onClick={finalizeStudentProfile} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-2xl hover:bg-amber-400 uppercase tracking-widest">Acessar Meu Painel</button>
        </div>
      </div>
