                <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 flex items-center gap-8">
                  <div className="w-24 h-24 bg-slate-800 rounded-3xl flex items-center justify-center border-2 border-amber-500/30">
                    <UserIcon size={40} className="text-amber-500" />
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">{loggedInAthlete?.name}</h3>
                    <p className="text-[10px] font-black text-amber-500 uppercase mb-4">ID: {loggedInAthlete?.accessId}</p>
                    <BeltBadge belt={loggedInAthlete?.belt || 'Branca'} degrees={loggedInAthlete?.degrees || 0} />
                  </div>
                </div>
                <div className={`p-10 rounded-[3rem] border flex items-center gap-6 relative overflow-hidden ${loggedInAthlete?.paymentDay > new Date().getDate() ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-red-500/10 border-red-500/30'}`}>
                  <div className={`p-4 rounded-2xl ${loggedInAthlete?.paymentDay > new Date().getDate() ? 'bg-emerald-500' : 'bg-red-500'}`}>
                    <CreditCard className="text-white" size={24} />
                  </div>
                  <div>
                    <h4 className="text-xl font-black text-white uppercase italic">Financeiro</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Vencimento: Dia {loggedInAthlete?.paymentDay}</p>
                  </div>
                </div>
              </div>
            ) : (
              /* DASHBOARD MESTRE */
              <div className="space-y-10">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800">
                    <p className="text-[10px] font-black text-slate-500 uppercase mb-2">Total de Alunos</p>
                    <p className="text-3xl font-black text-white">{athletes.length}</p>
                  </div>
                  <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-amber-500">
                    <p className="text-[10px] font-black text-amber-500 uppercase mb-2">Pagamentos Próximos</p>
                    <p className="text-3xl font-black text-white">{stats.imminentPayments.length}</p>
                  </div>
                  <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-indigo-500">
                    <p className="text-[10px] font-black text-indigo-500 uppercase mb-2">Aniversários do Mês</p>
                    <p className="text-3xl font-black text-white">{stats.birthdays.length}</p>
                  </div>
                </div>

                {/* Lista de Aniversariantes */}
                <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800">
                  <h3 className="text-xl font-black text-white uppercase italic flex items-center gap-2 mb-6"><Cake size={20} className="text-indigo-500" /> Guerreiros Aniversariantes</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                    {stats.birthdays.length > 0 ? stats.birthdays.map(ath => (
                      <div key={ath.id} className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 flex items-center gap-4">
                        <div className="w-10 h-10 bg-indigo-500/10 rounded-xl flex items-center justify-center text-indigo-500 font-black">{ath.name.charAt(0)}</div>
                        <div>
                          <p className="text-[10px] font-black text-white uppercase">{ath.name}</p>
                          <p className="text-[8px] font-bold text-slate-500 uppercase">Dia {new Date(ath.birthDate).getDate() + 1}</p>
                        </div>
                      </div>
                    )) : <p className="text-xs text-slate-500 uppercase font-black">Nenhum aniversário este mês.</p>}
                  </div>
                </div>

                {/* Gemini Insight */}
                <div className="bg-amber-500 text-slate-950 p-8 rounded-[2.5rem] shadow-xl relative overflow-hidden">
                  <Star size={150} className="absolute -bottom-10 -right-10 opacity-10 rotate-12" />
                  <h3 className="text-xl font-black uppercase italic mb-2">Insight Estratégico AI</h3>
                  <p className="text-sm font-bold italic leading-relaxed">"{aiInsight || "Analisando o fluxo do tatame..."}"</p>
                </div>
              </div>
            )}
          </div>
        )}

        {view === AppView.Athletes && user?.role === 'admin' && (
          <div className="space-y-8">
            <header className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Gestão de Atletas</h2>
              <button onClick={() => openAdminModal()} className="bg-amber-500 text-slate-950 px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center gap-2 shadow-xl hover:bg-amber-400 transition">
                <UserPlus size={18} /> Nova Matrícula
              </button>
            </header>
            <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-800/50 text-[10px] font-black uppercase text-slate-500 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nome / ID</th>
                    <th className="px-8 py-6">Faixa</th>
                    <th className="px-8 py-6">Vencimento</th>
                    <th className="px-8 py-6">Status Cadastro</th>
                    <th className="px-8 py-6 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {athletes.map(ath => (
                    <tr key={ath.id} className="hover:bg-slate-800/30 transition">
                      <td className="px-8 py-6">
                        <p className="font-black text-white uppercase italic">{ath.name}</p>
                        <p className="text-[10px] font-black text-amber-500">ID: {ath.accessId}</p>
                      </td>
                      <td className="px-8 py-6"><BeltBadge belt={ath.belt} degrees={ath.degrees} /></td>
                      <td className="px-8 py-6 text-[10px] font-black text-white">Dia {ath.paymentDay}</td>
                      <td className="px-8 py-6">
                        {ath.profileComplete ? 
                          <span className="text-[8px] font-black uppercase bg-emerald-500/10 text-emerald-500 px-3 py-1 rounded-full">Completo</span> :
                          <span className="text-[8px] font-black uppercase bg-red-500/10 text-red-500 px-3 py-1 rounded-full">Pendente</span>
                        }
                      </td>
                      <td className="px-8 py-6 text-right">
                        <button onClick={() => openAdminModal(ath)} className="p-2 text-slate-600 hover:text-white"><Edit size={18} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {/* MODAL ADMIN */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[3rem] w-full max-w-md p-10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-white italic uppercase">{editId ? 'Editar Aluno' : 'Novo Aluno'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-500 hover:text-white"><X size={32} /></button>
            </div>
            <div className="space-y-6">
              <div className="bg-slate-950 p-4 rounded-2xl border border-slate-800 flex justify-between items-center">
                <span className="text-[10px] font-black text-slate-500 uppercase">ID de Acesso:</span>
                <span className="text-sm font-black text-amber-500">{form.accessId}</span>
              </div>
              <input type="text" placeholder="Nome" value={form.name} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase" />
              <input type="email" placeholder="E-mail" value={form.email} onChange={e => setForm({...form, email: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <div className="grid grid-cols-2 gap-4">
                <select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white uppercase text-[10px] font-black">
                  {['Branca', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)}
                </select>
                <input type="number" placeholder="Vencimento" value={form.paymentDay} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              </div>
              <button onClick={saveAthleteAdmin} className="w-full bg-amber-500 text-slate-950 font-black p-5 rounded-2xl hover:bg-amber-400 transition uppercase tracking-widest italic text-sm shadow-xl">Salvar Registro</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type UserRole = 'admin' | 'professor' | 'student';
export type AgeCategory = 'Infantil' | 'Adulto';
export type Belt = 
  | 'Branca' | 'Cinza' | 'Amarela' | 'Laranja' | 'Verde' 
  | 'Azul' | 'Roxa' | 'Marrom' | 'Preta';

export interface Address {
  street: string;
  number: string;
  neighborhood: string;
  city: string;
  cep: string;
}

export interface Athlete {
  id: string;
  accessId: string; // ID gerado para login do aluno
  name: string;
  email: string;
  cpf: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  belt: Belt;
  degrees: number;
  category: AgeCategory;
  phone: string;
  emergencyContact: string;
  emergencyPhone: string;
  bloodType: string;
  medicalNotes: string;
  address: Address;
  medicalDocUrl?: string;
  termsAccepted: boolean;
  profileComplete: boolean; // Flag para forçar preenchimento de dados
  lastPaymentDate?: string;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  date: string;
  description: string;
  category: string;
  athleteId?: string;
  status: 'pending' | 'verified';
  receiptUrl?: string;
}

export interface MuralPhoto {
  id: string;
  url: string;
  caption: string;
  date: string;
  postedBy: string;
}

export interface AttendanceRecord {
  id: string;
  date: string;
  athleteIds: string[];
}

export enum AppView {
  Login = 'login',
  Dashboard = 'dashboard', 
  Athletes = 'athletes',
  Attendance = 'attendance',
  Finance = 'finance',
  Ranking = 'ranking',
  Mural = 'mural',
  ProfileCompletion = 'profile-completion',
  AdminRegistration = 'admin-registration'
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, Camera, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, TrendingUp, Lock, ShieldCheck, Mail
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, MuralPhoto, AttendanceRecord, Address } from './types';
import { getFinancialAdvice } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

const MOCK_ATHLETES: Athlete[] = [
  { 
    id: '1', accessId: 'BJJ-1001', name: 'Ricardo Almeida', email: 'ricardo@bjj.com', birthDate: '1990-05-15', joinDate: '2023-01-10', 
    paymentDay: 10, status: 'active', attendanceCount: 124, belt: 'Roxa', degrees: 2, category: 'Adulto', 
    phone: '(11) 98888-7777', bloodType: 'O+', termsAccepted: true, cpf: '123.456.789-00', address: INITIAL_ADDRESS,
    emergencyContact: 'Maria Almeida', emergencyPhone: '(11) 90000-0000', medicalNotes: 'Nenhuma.', profileComplete: true
  },
  { 
    id: '2', accessId: 'BJJ-1002', name: 'Ana Souza', email: 'ana@bjj.com', birthDate: '1995-03-20', joinDate: '2023-02-15', 
    paymentDay: 5, status: 'active', attendanceCount: 152, belt: 'Azul', degrees: 4, category: 'Adulto', 
    phone: '', bloodType: '', termsAccepted: false, cpf: '', address: INITIAL_ADDRESS,
    emergencyContact: '', emergencyPhone: '', medicalNotes: '', profileComplete: false
  }
];

const BELT_COLORS: Record<Belt, string> = {
  'Branca': '#ffffff', 'Cinza': '#94a3b8', 'Amarela': '#facc15', 'Laranja': '#fb923c', 'Verde': '#22c55e',
  'Azul': '#1d4ed8', 'Roxa': '#7e22ce', 'Marrom': '#78350f', 'Preta': '#000000'
};

const App: React.FC = () => {
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [athletes, setAthletes] = useState<Athlete[]>(MOCK_ATHLETES);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');

  // Admin Persisted Data (Mocking backend/localStorage)
  const [adminProfile, setAdminProfile] = useState<{name: string, password: string, email: string, registered: boolean} | null>(() => {
    const saved = localStorage.getItem('admin_profile');
    return saved ? JSON.parse(saved) : null;
  });

  // Modals
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<Partial<Athlete>>({});

  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin') {
      getFinancialAdvice(transactions).then(setAiInsight);
    }
  }, [view, transactions, user]);

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const latePayments = athletes.filter(a => a.status === 'active' && (today > a.paymentDay));
    const birthdays = athletes.filter(a => new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    return { imminentPayments, latePayments, birthdays, ranking };
  }, [athletes]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (isAdminLogin) {
      if (!adminProfile?.registered) {
        setView(AppView.AdminRegistration);
        return;
      }

      if (password === adminProfile.password) {
        setUser({ name: adminProfile.name, role: 'admin' });
        setView(AppView.Dashboard);
      } else {
        alert("Senha administrativa incorreta!");
      }
      return;
    }

    const ath = athletes.find(a => a.accessId.toUpperCase() === loginId.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      setView(ath.profileComplete ? AppView.Dashboard : AppView.ProfileCompletion);
    } else {
      alert("ID de Acesso não encontrado.");
    }
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const name = formData.get('name') as string;
    const email = formData.get('email') as string;
    const pass = formData.get('password') as string;
    const confirm = formData.get('confirm_password') as string;

    if (!name || !email || !pass) return alert("Preencha todos os campos.");
    if (pass !== confirm) return alert("As senhas não conferem.");

    const newProfile = { name, email, password: pass, registered: true };
    setAdminProfile(newProfile);
    localStorage.setItem('admin_profile', JSON.stringify(newProfile));

    setUser({ name, role: 'admin' });
    setView(AppView.Dashboard);
    alert("Conta de Mestre criada com sucesso! Oss.");
  };

  const generateAccessId = () => `BJJ-${Math.floor(1000 + Math.random() * 9000)}`;

  const openAdminModal = (ath?: Athlete) => {
    if (ath) {
      setEditId(ath.id);
      setForm(ath);
    } else {
      setEditId(null);
      setForm({
        name: '', email: '', belt: 'Branca', paymentDay: 10, category: 'Adulto', accessId: generateAccessId()
      });
    }
    setIsModalOpen(true);
  };

  const saveAthleteAdmin = () => {
    if (!form.name || !form.email) return alert("Nome e E-mail são obrigatórios!");
    if (editId) {
      setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } as Athlete : a));
    } else {
      const newAth = { 
        ...form, 
        id: Date.now().toString(), 
        joinDate: new Date().toISOString().split('T')[0], 
        attendanceCount: 0, 
        status: 'active',
        profileComplete: false,
        address: INITIAL_ADDRESS,
        termsAccepted: false
      } as Athlete;
      setAthletes(prev => [...prev, newAth]);
      alert(`Matrícula Criada! ID do Aluno: ${newAth.accessId}`);
    }
    setIsModalOpen(false);
  };

  const finalizeStudentProfile = () => {
    if (!form.cpf || !form.birthDate || !form.phone || !form.termsAccepted) {
      return alert("Complete os dados obrigatórios.");
    }
    setAthletes(prev => prev.map(a => a.id === user?.athleteId ? { ...a, ...form, profileComplete: true } as Athlete : a));
    setView(AppView.Dashboard);
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-4 w-14 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-0.5" style={{ backgroundColor: BELT_COLORS[belt] }}>
        <div className="absolute left-0 h-full w-2.5 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-2 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[7px] font-bold uppercase text-slate-500 mt-0.5">{belt}</span>
    </div>
  );

  if (view === AppView.Login) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-slate-900 rounded-[3rem] border border-slate-800 p-12 shadow-2xl text-center">
          <Medal className="text-amber-500 mx-auto mb-6" size={64} />
          <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter mb-2">Dojô Master</h1>

          <div className="mt-8 space-y-6">
            <div className="flex bg-slate-800 p-1.5 rounded-2xl">
              <button onClick={() => setIsAdminLogin(false)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${!isAdminLogin ? 'bg-amber-500 text-slate-950' : 'text-slate-500'}`}>Aluno</button>
              <button onClick={() => setIsAdminLogin(true)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${isAdminLogin ? 'bg-indigo-600 text-white' : 'text-slate-500'}`}>Mestre</button>
            </div>

            <div className="text-left space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">{isAdminLogin ? 'Senha de Mestre' : 'ID de Acesso'}</label>
              <div className="relative">
                {isAdminLogin ? <Lock className="absolute left-4 top-4 text-slate-600" size={20} /> : <Key className="absolute left-4 top-4 text-slate-600" size={20} />}
                <input 
                  type={isAdminLogin ? "password" : "text"}
                  value={isAdminLogin ? password : loginId}
                  onChange={e => isAdminLogin ? setPassword(e.target.value) : setLoginId(e.target.value)}
                  placeholder={isAdminLogin ? (adminProfile?.registered ? "Digite sua senha" : "Definir senha (1º Acesso)") : "Ex: BJJ-1234"}
                  className="w-full p-4 pl-12 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500"
                />
              </div>
            </div>

            <button onClick={handleLogin} className={`w-full ${isAdminLogin ? 'bg-indigo-600 hover:bg-indigo-500 text-white' : 'bg-amber-500 hover:bg-amber-400 text-slate-950'} font-black py-5 rounded-2xl transition uppercase text-xs tracking-widest italic flex items-center justify-center gap-2 shadow-lg`}>
              {isAdminLogin && !adminProfile?.registered ? "Criar Cadastro de Mestre" : "Entrar no Tatame"} <ArrowRight size={18} />
            </button>

            {!isAdminLogin && (
              <p className="text-[9px] text-slate-600 font-bold uppercase tracking-widest">Esqueceu seu ID? Fale com seu professor.</p>
            )}
          </div>
        </div>
      </div>
    );
  }

  if (view === AppView.AdminRegistration) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="max-w-xl w-full bg-slate-900 rounded-[3rem] border border-slate-800 p-12 shadow-2xl">
          <header className="text-center mb-10">
            <ShieldCheck className="text-indigo-500 mx-auto mb-4" size={56} />
            <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Primeiro Acesso: Mestre</h2>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-2">Defina seu cadastro administrativo</p>
          </header>

          <form onSubmit={registerAdmin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">Seu Nome / Título</label>
              <div className="relative">
                <UserIcon className="absolute left-4 top-4 text-slate-600" size={20} />
                <input name="name" type="text" placeholder="Ex: Mestre Carlos" className="w-full p-4 pl-12 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">E-mail Profissional</label>
              <div className="relative">
                <Mail className="absolute left-4 top-4 text-slate-600" size={20} />
                <input name="email" type="email" placeholder="mestre@dojo.com" className="w-full p-4 pl-12 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase px-1">Criar Senha</label>
                <input name="password" type="password" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-500 uppercase px-1">Confirmar Senha</label>
                <input name="confirm_password" type="password" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
            </div>
            <button type="submit" className="w-full bg-indigo-600 text-white font-black py-5 rounded-2xl hover:bg-indigo-500 transition uppercase text-xs tracking-widest italic flex items-center justify-center gap-2 shadow-2xl">
              Salvar Cadastro e Entrar <CheckCircle2 size={18} />
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (view === AppView.ProfileCompletion) {
    return (
      <div className="min-h-screen bg-slate-950 p-6 flex items-center justify-center">
        <div className="max-w-4xl w-full bg-slate-900 border border-slate-800 rounded-[3rem] p-10 md:p-16">
          <header className="mb-10 text-center">
            <ClipboardCheck size={48} className="text-amber-500 mx-auto mb-4" />
            <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Concluir Cadastro Aluno</h2>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Complete seus dados de saúde e residência</p>
          </header>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-4">
              <input type="text" placeholder="CPF" value={form.cpf} onChange={e => setForm({...form, cpf: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <input type="date" placeholder="Nascimento" value={form.birthDate} onChange={e => setForm({...form, birthDate: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <input type="text" placeholder="WhatsApp" value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
            </div>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <input type="text" placeholder="Sangue" value={form.bloodType} onChange={e => setForm({...form, bloodType: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
                <input type="text" placeholder="Emergência Tel" value={form.emergencyPhone} onChange={e => setForm({...form, emergencyPhone: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              </div>
              <textarea placeholder="Observações de Saúde" value={form.medicalNotes} onChange={e => setForm({...form, medicalNotes: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white min-h-[100px]" />
            </div>
          </div>
          <div className="mt-8 flex items-start gap-4 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
            <input type="checkbox" checked={form.termsAccepted} onChange={e => setForm({...form, termsAccepted: e.target.checked})} className="mt-1 h-6 w-6 rounded bg-slate-800 border-slate-700 text-amber-500" />
            <p className="text-[10px] text-slate-400 uppercase font-black">Declaro estar em perfeitas condições de saúde para a prática esportiva.</p>
          </div>
          <button onClick={finalizeStudentProfile} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-2xl hover:bg-amber-400 uppercase tracking-widest italic shadow-xl">Confirmar Cadastro</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter']">
      <aside className="w-72 bg-slate-900 border-r border-slate-800 p-8 hidden md:flex flex-col gap-8">
        <div className="flex items-center space-x-3 mb-4">
          <Medal className="text-amber-500" size={32} />
          <span className="text-xl font-black uppercase italic tracking-tighter">Dojô Master</span>
        </div>
        <nav className="flex-1 space-y-2">
          <button onClick={() => setView(AppView.Dashboard)} className={`w-full flex items-center space-x-3 p-4 rounded-xl font-black uppercase text-[10px] tracking-widest ${view === AppView.Dashboard ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}>
            <Home size={18} /> <span>Início</span>
          </button>
          {user?.role === 'admin' && (
            <button onClick={() => setView(AppView.Athletes)} className={`w-full flex items-center space-x-3 p-4 rounded-xl font-black uppercase text-[10px] tracking-widest ${view === AppView.Athletes ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}>
              <Users size={18} /> <span>Gestão de Alunos</span>
            </button>
          )}
        </nav>
        <button onClick={() => { setUser(null); setView(AppView.Login); }} className="text-[10px] font-black uppercase text-slate-600 flex items-center gap-2 hover:text-red-500 transition"><LogOut size={16}/> Sair</button>
      </aside>

      <main className="flex-1 p-6 md:p-12 overflow-y-auto">
        {view === AppView.Dashboard && (
          <div className="space-y-10 animate-in fade-in duration-500">
            <header className="flex justify-between items-end">
              <div>
                <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter">Sala de Entrada</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-1">{user?.role === 'admin' ? 'Painel Administrativo' : 'Seu Perfil'}</p>
              </div>
            </header>

            {user?.role === 'student' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 flex items-center gap-8">
                  <div className="w-24 h-24 bg-slate-800 rounded-3xl flex items-center justify-center border-2 border-amber-500/30">
                    <UserIcon size={40} className="text-amber-500" />
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">{loggedInAthlete?.name}</h3>
                    <p className="text-[10px] font-black text-amber-500 uppercase mb-4">ID: {loggedInAthlete?.accessId}</p>
                    <BeltBadge belt={loggedInAthlete?.belt || 'Branca'} degrees={loggedInAthlete?.degrees || 0} />
                  </div>
                </div>
                <div className={`p-10 rounded-[3rem] border flex items-center gap-6 relative overflow-hidden ${loggedInAthlete && loggedInAthlete.paymentDay > new Date().getDate() ? 'bg-emerald-500/10 border-emerald-500/30 text-emerald-500' : 'bg-red-500/10 border-red-500/30 text-red-500'}`}>
                   <div className={`p-4 rounded-2xl ${loggedInAthlete && loggedInAthlete.paymentDay > new Date().getDate() ? 'bg-emerald-500' : 'bg-red-500'}`}>
                    <CreditCard className="text-white" size={24} />
                  </div>
                  <div>
                    <h4 className="text-xl font-black text-white uppercase italic">Financeiro</h4>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">Vencimento: Dia {loggedInAthlete?.paymentDay}</p>
                  </div>
                </div>
              </div>
            ) : (
              <div className="space-y-10">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800">
                    <p className="text-[10px] font-black text-slate-500 uppercase mb-2">Total de Alunos</p>
                    <p className="text-3xl font-black text-white">{athletes.length}</p>
                  </div>
                  <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-amber-500">
                    <p className="text-[10px] font-black text-amber-500 uppercase mb-2">Pagamentos Próximos</p>
                    <p className="text-3xl font-black text-white">{stats.imminentPayments.length}</p>
                  </div>
                  <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-indigo-500">
                    <p className="text-[10px] font-black text-indigo-500 uppercase mb-2">Aniversários do Mês</p>
                    <p className="text-3xl font-black text-white">{stats.birthdays.length}</p>
                  </div>
                </div>

                <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800">
                  <h3 className="text-xl font-black text-white uppercase italic flex items-center gap-2 mb-6"><Cake size={20} className="text-indigo-500" /> Guerreiros Aniversariantes</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                    {stats.birthdays.length > 0 ? stats.birthdays.map(ath => (
                      <div key={ath.id} className="bg-slate-800/50 p-4 rounded-2xl border border-slate-700 flex items-center gap-4">
                        <div className="w-10 h-10 bg-indigo-500/10 rounded-xl flex items-center justify-center text-indigo-500 font-black">{ath.name.charAt(0)}</div>
                        <div>
                          <p className="text-[10px] font-black text-white uppercase">{ath.name}</p>
                          <p className="text-[8px] font-bold text-slate-500 uppercase">Dia {new Date(ath.birthDate).getDate() + 1}</p>
                        </div>
                      </div>
                    )) : <p className="text-xs text-slate-500 uppercase font-black">Nenhum aniversário este mês.</p>}
                  </div>
                </div>

                <div className="bg-amber-500 text-slate-950 p-8 rounded-[2.5rem] shadow-xl relative overflow-hidden">
                  <Star size={150} className="absolute -bottom-10 -right-10 opacity-10 rotate-12" />
                  <h3 className="text-xl font-black uppercase italic mb-2">Insight Estratégico AI</h3>
                  <p className="text-sm font-bold italic leading-relaxed">"{aiInsight || "Processando dados do tatame..."}"</p>
                </div>
              </div>
            )}
          </div>
        )}

        {view === AppView.Athletes && user?.role === 'admin' && (
          <div className="space-y-8">
            <header className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Gestão de Alunos</h2>
              <button onClick={() => openAdminModal()} className="bg-amber-500 text-slate-950 px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center gap-2 shadow-xl hover:bg-amber-400 transition">
                <UserPlus size={18} /> Nova Matrícula
              </button>
            </header>
            <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl">
              <table className="w-full text-left">
                <thead className="bg-slate-800/50 text-[10px] font-black uppercase text-slate-500 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nome / ID</th>
                    <th className="px-8 py-6">Faixa</th>
                    <th className="px-8 py-6">Vencimento</th>
                    <th className="px-8 py-6">Cadastro</th>
                    <th className="px-8 py-6 text-right">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {athletes.map(ath => (
                    <tr key={ath.id} className="hover:bg-slate-800/30 transition">
                      <td className="px-8 py-6">
                        <p className="font-black text-white uppercase italic">{ath.name}</p>
                        <p className="text-[10px] font-black text-amber-500">ID: {ath.accessId}</p>
                      </td>
                      <td className="px-8 py-6"><BeltBadge belt={ath.belt} degrees={ath.degrees} /></td>
                      <td className="px-8 py-6 text-[10px] font-black text-white">Dia {ath.paymentDay}</td>
                      <td className="px-8 py-6">
                        {ath.profileComplete ? 
                          <span className="text-[8px] font-black uppercase bg-emerald-500/10 text-emerald-500 px-3 py-1 rounded-full">Completo</span> :
                          <span className="text-[8px] font-black uppercase bg-red-500/10 text-red-500 px-3 py-1 rounded-full">Pendente</span>
                        }
                      </td>
                      <td className="px-8 py-6 text-right">
                        <button onClick={() => openAdminModal(ath)} className="p-2 text-slate-600 hover:text-white"><Edit size={18} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}
      </main>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[3rem] w-full max-w-md p-10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-white italic uppercase">{editId ? 'Editar Aluno' : 'Novo Aluno'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-500 hover:text-white"><X size={32} /></button>
            </div>
            <div className="space-y-6">
              <div className="bg-slate-950 p-4 rounded-2xl border border-slate-800 flex justify-between items-center">
                <span className="text-[10px] font-black text-slate-500 uppercase">ID de Acesso:</span>
                <span className="text-sm font-black text-amber-500">{form.accessId}</span>
              </div>
              <input type="text" placeholder="Nome" value={form.name} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
              <input type="email" placeholder="E-mail" value={form.email} onChange={e => setForm({...form, email: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-amber-500" />
              <div className="grid grid-cols-2 gap-4">
                <select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white uppercase text-[10px] font-black outline-none focus:ring-2 focus:ring-amber-500">
                  {['Branca', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)}
                </select>
                <input type="number" placeholder="Vencimento" value={form.paymentDay} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-amber-500" />
              </div>
              <button onClick={saveAthleteAdmin} className="w-full bg-amber-500 text-slate-950 font-black p-5 rounded-2xl hover:bg-amber-400 transition uppercase tracking-widest italic text-sm shadow-xl flex items-center justify-center gap-2">
                <Save size={18} /> Salvar Cadastro
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type UserRole = 'admin' | 'professor' | 'student';
export type AgeCategory = 'Infantil' | 'Adulto';
export type Belt = 
  | 'Branca' | 'Cinza' | 'Amarela' | 'Laranja' | 'Verde' 
  | 'Azul' | 'Roxa' | 'Marrom' | 'Preta';

export interface Address {
  street: string;
  number: string;
  neighborhood: string;
  city: string;
  cep: string;
}

export interface AdminProfile {
  name: string;
  dojoName: string;
  email: string;
  password: string;
  phone: string;
  address: string;
  registered: boolean;
}

export interface Athlete {
  id: string;
  accessId: string;
  name: string;
  email: string;
  cpf: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  belt: Belt;
  degrees: number;
  category: AgeCategory;
  phone: string;
  emergencyContact: string;
  emergencyPhone: string;
  bloodType: string;
  medicalNotes: string;
  allergies: string;
  medications: string;
  address: Address;
  termsAccepted: boolean;
  profileComplete: boolean;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  date: string;
  description: string;
  category: string;
  athleteId?: string;
  status: 'pending' | 'verified';
  receiptUrl?: string;
}

export interface MuralPhoto {
  id: string;
  url: string;
  caption: string;
  date: string;
  postedBy: string;
}

export interface AttendanceRecord {
  id: string;
  date: string;
  athleteIds: string[];
}

export enum AppView {
  Login = 'login',
  Dashboard = 'dashboard', 
  Athletes = 'athletes',
  Attendance = 'attendance',
  Finance = 'finance',
  Ranking = 'ranking',
  Mural = 'mural',
  ProfileCompletion = 'profile-completion',
  AdminRegistration = 'admin-registration'
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, Camera, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, Lock, ShieldCheck, Mail, MapPin, Phone, Briefcase
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address } from './types';
import { getFinancialAdvice } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

const MOCK_ATHLETES: Athlete[] = [
  { 
    id: '1', accessId: 'BJJ-1001', name: 'Ricardo Almeida', email: 'ricardo@bjj.com', birthDate: '1990-05-15', joinDate: '2023-01-10', 
    paymentDay: 10, status: 'active', attendanceCount: 124, belt: 'Roxa', degrees: 2, category: 'Adulto', 
    phone: '(11) 98888-7777', bloodType: 'O+', termsAccepted: true, cpf: '123.456.789-00', address: INITIAL_ADDRESS,
    emergencyContact: 'Maria Almeida', emergencyPhone: '(11) 90000-0000', medicalNotes: 'Nenhuma.', 
    allergies: '', medications: '', profileComplete: true
  },
  { 
    id: '2', accessId: 'BJJ-1002', name: 'Ana Souza', email: 'ana@bjj.com', birthDate: '1995-03-20', joinDate: '2023-02-15', 
    paymentDay: 5, status: 'active', attendanceCount: 152, belt: 'Azul', degrees: 4, category: 'Adulto', 
    phone: '', bloodType: '', termsAccepted: false, cpf: '', address: INITIAL_ADDRESS,
    emergencyContact: '', emergencyPhone: '', medicalNotes: '', allergies: '', medications: '', profileComplete: false
  }
];

const BELT_COLORS: Record<Belt, string> = {
  'Branca': '#ffffff', 'Cinza': '#94a3b8', 'Amarela': '#facc15', 'Laranja': '#fb923c', 'Verde': '#22c55e',
  'Azul': '#1d4ed8', 'Roxa': '#7e22ce', 'Marrom': '#78350f', 'Preta': '#000000'
};

const App: React.FC = () => {
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [athletes, setAthletes] = useState<Athlete[]>(MOCK_ATHLETES);
  const [transactions] = useState<Transaction[]>([]);
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('admin_profile_v2');
    return saved ? JSON.parse(saved) : null;
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<Partial<Athlete>>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin') {
      getFinancialAdvice(transactions).then(setAiInsight);
    }
  }, [view, transactions, user]);

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    return { imminentPayments, birthdays, ranking };
  }, [athletes]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (isAdminLogin) {
      if (!adminProfile?.registered) {
        setView(AppView.AdminRegistration);
        return;
      }
      if (password === adminProfile.password) {
        setUser({ name: adminProfile.name, role: 'admin' });
        setView(AppView.Dashboard);
      } else {
        alert("Senha incorreta!");
      }
      return;
    }

    const ath = athletes.find(a => a.accessId.toUpperCase() === loginId.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      if (!ath.profileComplete) {
        setOnboardingForm({...ath});
        setView(AppView.ProfileCompletion);
      } else {
        setView(AppView.Dashboard);
      }
    } else {
      alert("ID não encontrado.");
    }
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    const pass = fd.get('password') as string;
    const confirm = fd.get('confirm_password') as string;

    if (pass !== confirm) return alert("Senhas não conferem.");

    const newProfile: AdminProfile = {
      name: fd.get('name') as string,
      dojoName: fd.get('dojoName') as string,
      email: fd.get('email') as string,
      phone: fd.get('phone') as string,
      address: fd.get('address') as string,
      password: pass,
      registered: true
    };

    setAdminProfile(newProfile);
    localStorage.setItem('admin_profile_v2', JSON.stringify(newProfile));
    setUser({ name: newProfile.name, role: 'admin' });
    setView(AppView.Dashboard);
  };

  const finalizeStudentProfile = () => {
    if (!onboardingForm.cpf || !onboardingForm.phone || !onboardingForm.termsAccepted) {
      return alert("Campos CPF, WhatsApp e Termos são obrigatórios.");
    }

    setAthletes(prev => prev.map(a => a.id === user?.athleteId ? { 
      ...a, 
      ...onboardingForm, 
      profileComplete: true 
    } as Athlete : a));

    setView(AppView.Dashboard);
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-4 w-14 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-0.5" style={{ backgroundColor: BELT_COLORS[belt] }}>
        <div className="absolute left-0 h-full w-2.5 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-2 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[7px] font-bold uppercase text-slate-500 mt-0.5">{belt}</span>
    </div>
  );

  if (view === AppView.Login) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-slate-900 rounded-[3rem] border border-slate-800 p-12 shadow-2xl text-center">
          <Medal className="text-amber-500 mx-auto mb-6" size={64} />
          <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter mb-2">
            {adminProfile?.dojoName || "Dojô Master"}
          </h1>

          <div className="mt-8 space-y-6">
            <div className="flex bg-slate-800 p-1.5 rounded-2xl">
              <button onClick={() => setIsAdminLogin(false)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${!isAdminLogin ? 'bg-amber-500 text-slate-950' : 'text-slate-400'}`}>Aluno</button>
              <button onClick={() => setIsAdminLogin(true)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${isAdminLogin ? 'bg-indigo-600 text-white' : 'text-slate-400'}`}>Mestre</button>
            </div>

            <div className="text-left space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">{isAdminLogin ? 'Acesso Mestre' : 'Seu ID de Acesso'}</label>
              <div className="relative">
