                <input type={isAdminLogin ? "password" : "text"} value={isAdminLogin ? password : loginId} onChange={e => isAdminLogin ? setPassword(e.target.value) : setLoginId(e.target.value)} placeholder={isAdminLogin ? "Senha de acesso" : "Ex: BJJ-1234"} className="w-full p-4 pl-12 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
              </div>
            </div>
            <button onClick={handleLogin} className={`w-full ${isAdminLogin ? 'bg-indigo-600 hover:bg-indigo-500 text-white' : 'bg-amber-500 hover:bg-amber-400 text-slate-950'} font-black py-5 rounded-2xl transition uppercase text-xs flex items-center justify-center gap-2 shadow-lg`}>
              {isAdminLogin && !adminProfile?.registered ? "Configurar Academia" : "Entrar Agora"} <ArrowRight size={18} />
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (view === AppView.AdminRegistration) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 py-12">
        <div className="max-w-2xl w-full bg-slate-900 rounded-[3rem] border border-slate-800 p-10 md:p-14 shadow-2xl">
          <header className="text-center mb-10">
            <ShieldCheck className="text-indigo-500 mx-auto mb-4" size={56} />
            <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Primeiro Acesso: Mestre</h2>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-2">Configure sua Academia</p>
          </header>
          <form onSubmit={registerAdmin} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2 space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase">Nome do Dojô</label>
