            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase">Confirmar Senha</label>
              <input name="confirm_password" required type="password" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
            </div>
            <button type="submit" className="md:col-span-2 w-full bg-indigo-600 text-white font-black py-5 rounded-2xl hover:bg-indigo-500 transition uppercase text-xs flex items-center justify-center gap-2 shadow-2xl mt-4">
              Finalizar Cadastro <CheckCircle2 size={18} />
            </button>
          </form>
        </div>
