              <input type="text" placeholder="WhatsApp" value={onboardingForm.phone || ''} onChange={e => setOnboardingForm({...onboardingForm, phone: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <input type="date" placeholder="Data de Nascimento" value={onboardingForm.birthDate || ''} onChange={e => setOnboardingForm({...onboardingForm, birthDate: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <h4 className="text-[10px] font-black text-amber-500 uppercase border-b border-slate-800 pb-2 mt-8">Endereço</h4>
              <input type="text" placeholder="Rua e Número" value={onboardingForm.address?.street || ''} onChange={e => setOnboardingForm({...onboardingForm, address: {...(onboardingForm.address || INITIAL_ADDRESS), street: e.target.value}})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <input type="text" placeholder="Bairro" value={onboardingForm.address?.neighborhood || ''} onChange={e => setOnboardingForm({...onboardingForm, address: {...(onboardingForm.address || INITIAL_ADDRESS), neighborhood: e.target.value}})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
