                <input type="text" placeholder="Tel. Emergência" value={onboardingForm.emergencyPhone || ''} onChange={e => setOnboardingForm({...onboardingForm, emergencyPhone: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              </div>
              <input type="text" placeholder="Nome do Contato de Emergência" value={onboardingForm.emergencyContact || ''} onChange={e => setOnboardingForm({...onboardingForm, emergencyContact: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <textarea placeholder="Alergias ou Problemas de Saúde" value={onboardingForm.medicalNotes || ''} onChange={e => setOnboardingForm({...onboardingForm, medicalNotes: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white min-h-[100px]" />
            </div>
          </div>
          <div className="mt-8 flex items-start gap-4 bg-slate-800/50 p-6 rounded-2xl border border-slate-700">
            <input type="checkbox" checked={onboardingForm.termsAccepted || false} onChange={e => setOnboardingForm({...onboardingForm, termsAccepted: e.target.checked})} className="mt-1 h-6 w-6 rounded bg-slate-800 border-slate-700 text-amber-500" />
            <p className="text-[10px] text-slate-400 uppercase font-black leading-relaxed">Confirmo que as informações acima são reais e que aceito as normas de segurança e conduta do tatame.</p>
          </div>
          <button onClick={finalizeOnboarding} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-2xl hover:bg-amber-400 uppercase tracking-widest italic shadow-xl">Finalizar Cadastro e Treinar</button>
        </div>
      </div>
    );
  }

  return (
