              <div>
                <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter">Olá, {user?.name}</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-1">{user?.role === 'admin' ? adminProfile?.dojoName : 'Quadro Pessoal'}</p>
              </div>
            </header>

            {user?.role === 'student' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 flex items-center gap-8 shadow-2xl">
                  <div className="w-24 h-24 bg-slate-800 rounded-3xl flex items-center justify-center border-2 border-amber-500/30">
                    <UserIcon size={40} className="text-amber-500" />
