                <thead className="bg-slate-800/50 text-[10px] font-black uppercase text-slate-500 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Nome / ID</th>
                    <th className="px-8 py-6">Faixa</th>
                    <th className="px-8 py-6">Vencimento</th>
                    <th className="px-8 py-6">Status</th>
                    {user?.role === 'admin' && <th className="px-8 py-6 text-right">Ações</th>}
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {athletes.map(ath => (
                    <tr key={ath.id} className="hover:bg-slate-800/30 transition">
                      <td className="px-8 py-6">
                        <p className="font-black text-white uppercase italic">{ath.name}</p>
                        <p className="text-[10px] font-black text-amber-500">{ath.accessId}</p>
                      </td>
                      <td className="px-8 py-6"><BeltBadge belt={ath.belt} degrees={ath.degrees} /></td>
                      <td className="px-8 py-6 text-[10px] font-black text-white">Dia {ath.paymentDay}</td>
                      <td className="px-8 py-6">
                        {ath.profileComplete ? 
                          <span className="text-[8px] font-black uppercase bg-emerald-500/10 text-emerald-500 px-3 py-1 rounded-full border border-emerald-500/20">Ativo</span> :
                          <span className="text-[8px] font-black uppercase bg-red-500/10 text-red-500 px-3 py-1 rounded-full border border-red-500/20">Pendente</span>
                        }
                      </td>
                      {user?.role === 'admin' && (
                        <td className="px-8 py-6 text-right">
                          <button onClick={() => { setForm(ath); setEditId(ath.id); setModalType('athlete'); setIsModalOpen(true); }} className="p-2 text-slate-600 hover:text-white transition transform hover:scale-110"><Edit size={18} /></button>
                        </td>
                      )}
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {view === AppView.Finance && user?.role === 'admin' && (
          <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-300">
            <header className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Controle Financeiro</h2>
              <button onClick={() => { setForm({ date: new Date().toISOString().split('T')[0], type: 'income', amount: 0 }); setEditId(null); setModalType('transaction'); setIsModalOpen(true); }} className="bg-emerald-500 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center gap-2 shadow-xl hover:bg-emerald-400 transition">
                <Plus size={18} /> Nova Transação
              </button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
               <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 flex items-center justify-between">
                  <div>
                    <p className="text-[10px] font-black text-emerald-500 uppercase">Receitas</p>
                    <p className="text-3xl font-black text-white">R$ {stats.income}</p>
                  </div>
                  <TrendingUp className="text-emerald-500" size={40} />
               </div>
               <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 flex items-center justify-between">
                  <div>
                    <p className="text-[10px] font-black text-red-500 uppercase">Despesas</p>
                    <p className="text-3xl font-black text-white">R$ {stats.expense}</p>
                  </div>
                  <TrendingDown className="text-red-500" size={40} />
               </div>
            </div>
            <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-slate-800/50 text-[10px] font-black uppercase text-slate-500 tracking-widest">
                  <tr>
                    <th className="px-8 py-6">Data</th>
                    <th className="px-8 py-6">Descrição</th>
                    <th className="px-8 py-6">Tipo</th>
                    <th className="px-8 py-6 text-right">Valor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {transactions.map(t => (
                    <tr key={t.id} className="hover:bg-slate-800/30 transition">
                      <td className="px-8 py-6 text-[10px] font-black text-slate-500 uppercase">{t.date}</td>
                      <td className="px-8 py-6 text-[11px] font-black text-white uppercase">{t.description}</td>
                      <td className="px-8 py-6">
                        <span className={`text-[8px] font-black uppercase px-2 py-1 rounded-full ${t.type === 'income' ? 'bg-emerald-500/10 text-emerald-500' : 'bg-red-500/10 text-red-500'}`}>
                          {t.type === 'income' ? 'Receita' : 'Despesa'}
                        </span>
                      </td>
                      <td className={`px-8 py-6 text-right font-black ${t.type === 'income' ? 'text-emerald-500' : 'text-red-500'}`}>
                        {t.type === 'income' ? '+' : '-'} R$ {t.amount}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {view === AppView.Attendance && user?.role === 'admin' && (
          <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-300">
            <header className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Lista de Presença</h2>
              <div className="flex items-center gap-3">
                 <input type="date" className="bg-slate-800 border-none p-3 rounded-xl text-white font-black text-[10px] uppercase" defaultValue={new Date().toISOString().split('T')[0]} />
                 <button className="bg-amber-500 text-slate-950 p-3 rounded-xl font-black uppercase text-[10px]">Filtrar</button>
              </div>
            </header>
            <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl p-8">
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {athletes.map(ath => (
                    <div key={ath.id} className="bg-slate-800 p-6 rounded-3xl border border-slate-700 flex items-center justify-between group hover:border-amber-500 transition-all">
                       <div className="flex items-center gap-4">
                          <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center font-black text-amber-500 border border-slate-800">{ath.name.charAt(0)}</div>
                          <div>
                            <p className="text-[10px] font-black text-white uppercase">{ath.name}</p>
                            <BeltBadge belt={ath.belt} degrees={ath.degrees} />
                          </div>
                       </div>
                       <button onClick={() => {
                         setAthletes(prev => prev.map(a => a.id === ath.id ? {...a, attendanceCount: a.attendanceCount + 1} : a));
                         alert(`Presença marcada para ${ath.name}!`);
                       }} className="w-10 h-10 bg-slate-700 rounded-full flex items-center justify-center text-slate-400 group-hover:bg-amber-500 group-hover:text-slate-950 transition-all"><CheckCircle2 size={24} /></button>
                    </div>
                  ))}
               </div>
            </div>
          </div>
        )}

        {view === AppView.Ranking && (
          <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-300">
            <header className="text-center">
              <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">Ranking de Frequência</h2>
              <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest">Os guerreiros mais constantes do tatame</p>
            </header>
            <div className="max-w-3xl mx-auto space-y-4">
               {stats.ranking.map((ath, index) => (
                 <div key={ath.id} className={`flex items-center gap-6 p-6 rounded-[2rem] border transition-all ${index === 0 ? 'bg-amber-500/10 border-amber-500 scale-105 shadow-amber-500/10 shadow-2xl' : 'bg-slate-900 border-slate-800'}`}>
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black italic text-xl ${index === 0 ? 'bg-amber-500 text-slate-950' : 'bg-slate-800 text-slate-500'}`}>
                      {index + 1}º
                    </div>
                    <div className="flex-1 flex items-center gap-4">
                       <div className="w-10 h-10 bg-slate-800 rounded-full flex items-center justify-center text-slate-400 font-black">{ath.name.charAt(0)}</div>
                       <div>
                          <p className="font-black text-white uppercase italic">{ath.name}</p>
                          <BeltBadge belt={ath.belt} degrees={ath.degrees} />
                       </div>
                    </div>
                    <div className="text-right">
                       <p className="text-3xl font-black text-white tracking-tighter">{ath.attendanceCount}</p>
                       <p className="text-[8px] font-bold text-slate-500 uppercase">Aulas</p>
                    </div>
                 </div>
               ))}
            </div>
          </div>
        )}
      </main>

      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[3rem] w-full max-w-md p-10 shadow-2xl">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-white italic uppercase">{editId ? 'Editar' : 'Novo'} {modalType === 'athlete' ? 'Aluno' : 'Registro'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-500 hover:text-white transition hover:rotate-90"><X size={32} /></button>
            </div>

            {modalType === 'athlete' && (
              <div className="space-y-5">
                <input type="text" placeholder="Nome Completo" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
                <input type="email" placeholder="E-mail" value={form.email || ''} onChange={e => setForm({...form, email: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-amber-500" />
                <div className="grid grid-cols-2 gap-4">
                  <select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white uppercase text-[10px] font-black outline-none focus:ring-2 focus:ring-amber-500">
                    {['Branca', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)}
                  </select>
                  <input type="number" placeholder="Vencimento" value={form.paymentDay || ''} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-amber-500" />
                </div>
              </div>
            )}

            {modalType === 'transaction' && (
              <div className="space-y-5">
                <div className="flex bg-slate-800 p-1 rounded-2xl">
                   <button onClick={() => setForm({...form, type: 'income'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${form.type === 'income' ? 'bg-emerald-500 text-white' : 'text-slate-500'}`}>Receita</button>
                   <button onClick={() => setForm({...form, type: 'expense'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${form.type === 'expense' ? 'bg-red-500 text-white' : 'text-slate-500'}`}>Despesa</button>
                </div>
                <input type="text" placeholder="Descrição" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none" />
                <input type="number" placeholder="Valor R$" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
                <input type="date" value={form.date || ''} onChange={e => setForm({...form, date: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
              </div>
            )}

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: false, address: INITIAL_ADDRESS }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString() }]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-8 bg-amber-500 text-slate-950 font-black p-5 rounded-2xl hover:bg-amber-400 transition uppercase tracking-widest italic text-sm shadow-xl flex items-center justify-center gap-2">
              <Save size={18} /> Salvar Registro
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type UserRole = 'admin' | 'professor' | 'student';
export type AgeCategory = 'Infantil' | 'Adulto';

export type AdultBelt = 'Branca' | 'Azul' | 'Roxa' | 'Marrom' | 'Preta';
export type KidsBelt = 'Branca' | 'Cinza' | 'Amarela' | 'Laranja' | 'Verde';
export type Belt = AdultBelt | KidsBelt;

export interface Address {
  street: string;
  number: string;
  neighborhood: string;
  city: string;
  cep: string;
}

export interface AdminProfile {
  name: string;
  dojoName: string;
  email: string;
  password: string;
  phone: string;
  address: string;
  registered: boolean;
}

export interface Athlete {
  id: string;
  accessId: string;
  name: string;
  email: string;
  cpf: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  belt: Belt;
  degrees: number;
  category: AgeCategory;
  phone: string;
  emergencyContact: string;
  emergencyPhone: string;
  bloodType: string;
  medicalNotes: string;
  allergies: string;
  medications: string;
  address: Address;
  termsAccepted: boolean;
  profileComplete: boolean;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  date: string;
  description: string;
  category: string;
  athleteId?: string;
  status: 'pending' | 'verified';
}

export interface MuralPhoto {
  id: string;
  url: string;
  caption: string;
  date: string;
  postedBy: string;
}

export enum AppView {
  Login = 'login',
  Dashboard = 'dashboard', 
  Athletes = 'athletes',
  Attendance = 'attendance',
  Finance = 'finance',
  Ranking = 'ranking',
  Mural = 'mural',
  ProfileCompletion = 'profile-completion',
  AdminRegistration = 'admin-registration'
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, Lock, ShieldCheck, Mail, MapPin, Phone, Briefcase,
  TrendingDown, TrendingUp, Camera, Image as ImageIcon, Info
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address, MuralPhoto } from './types';
import { getFinancialAdvice } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

const MOCK_ATHLETES: Athlete[] = [
  { 
    id: '1', accessId: 'BJJ-1001', name: 'Ricardo Almeida', email: 'ricardo@bjj.com', birthDate: '1990-05-15', joinDate: '2023-01-10', 
    paymentDay: 10, status: 'active', attendanceCount: 42, belt: 'Roxa', degrees: 2, category: 'Adulto', 
    phone: '(11) 98888-7777', bloodType: 'O+', termsAccepted: true, cpf: '123.456.789-00', address: INITIAL_ADDRESS,
    emergencyContact: 'Maria Almeida', emergencyPhone: '(11) 90000-0000', medicalNotes: 'Nenhuma.', 
    allergies: '', medications: '', profileComplete: true
  },
  { 
    id: '2', accessId: 'BJJ-1002', name: 'Pedro Silva', email: 'pedro@bjj.com', birthDate: '2015-08-20', joinDate: '2023-02-15', 
    paymentDay: 5, status: 'active', attendanceCount: 56, belt: 'Cinza', degrees: 1, category: 'Infantil', 
    phone: '', bloodType: '', termsAccepted: false, cpf: '', address: INITIAL_ADDRESS,
    emergencyContact: '', emergencyPhone: '', medicalNotes: '', allergies: '', medications: '', profileComplete: false
  }
];

const BELT_COLORS: Record<string, string> = {
  'Branca': '#ffffff', 'Cinza': '#94a3b8', 'Amarela': '#facc15', 'Laranja': '#fb923c', 'Verde': '#22c55e',
  'Azul': '#1d4ed8', 'Roxa': '#7e22ce', 'Marrom': '#78350f', 'Preta': '#000000'
};

const App: React.FC = () => {
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [athletes, setAthletes] = useState<Athlete[]>(MOCK_ATHLETES);
  const [transactions, setTransactions] = useState<Transaction[]>([
    { id: 't1', type: 'income', amount: 150, date: '2024-05-01', description: 'Mensalidade Ricardo', category: 'Mensalidade' },
    { id: 't2', type: 'expense', amount: 400, date: '2024-05-02', description: 'Aluguel Tatame', category: 'Infraestrutura' }
  ]);
  const [mural, setMural] = useState<MuralPhoto[]>([
    { id: 'm1', url: 'https://images.unsplash.com/photo-1555597673-b21d5c935865?auto=format&fit=crop&w=800', caption: 'Treino de Sexta!', date: '2024-05-10', postedBy: 'Mestre' }
  ]);

  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('admin_profile_v4');
    return saved ? JSON.parse(saved) : null;
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin') {
      getFinancialAdvice(transactions).then(setAiInsight);
    }
  }, [view, transactions, user]);

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (isAdminLogin) {
      if (!adminProfile?.registered) {
        setView(AppView.AdminRegistration);
        return;
      }
      if (password === adminProfile.password) {
        setUser({ name: adminProfile.name, role: 'admin' });
        setView(AppView.Dashboard);
      } else {
        alert("Senha incorreta!");
      }
      return;
    }

    const ath = athletes.find(a => a.accessId.toUpperCase() === loginId.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      if (!ath.profileComplete) {
        setOnboardingForm({...ath, address: ath.address || INITIAL_ADDRESS});
        setView(AppView.ProfileCompletion);
      } else {
        setView(AppView.Dashboard);
      }
    } else {
      alert("ID não encontrado. Solicite ao seu professor.");
    }
  };

  const finalizeOnboarding = () => {
    if (!onboardingForm.cpf || !onboardingForm.phone || !onboardingForm.termsAccepted) {
      return alert("Campos CPF, WhatsApp e Termos são obrigatórios.");
    }
    const updatedAthletes = athletes.map(a => a.id === user?.athleteId ? { ...a, ...onboardingForm, profileComplete: true } as Athlete : a);
    setAthletes(updatedAthletes);
    setView(AppView.Dashboard);
    alert("Perfil concluído! Bem-vindo ao tatame.");
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    if (fd.get('password') !== fd.get('confirm_password')) return alert("Senhas não conferem.");
    const newProfile: AdminProfile = {
      name: fd.get('name') as string,
      dojoName: fd.get('dojoName') as string,
      email: fd.get('email') as string,
      phone: fd.get('phone') as string,
      address: fd.get('address') as string,
      password: fd.get('password') as string,
      registered: true
    };
    setAdminProfile(newProfile);
    localStorage.setItem('admin_profile_v4', JSON.stringify(newProfile));
    setUser({ name: newProfile.name, role: 'admin' });
    setView(AppView.Dashboard);
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-4 w-14 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-0.5" style={{ backgroundColor: BELT_COLORS[belt] }}>
        <div className="absolute left-0 h-full w-2.5 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-2 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[7px] font-bold uppercase text-slate-500 mt-0.5">{belt}</span>
    </div>
  );

  const NavButton = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => {
    // Restrição de abas para o aluno
    const allowedForStudent = [AppView.Dashboard, AppView.Ranking, AppView.Mural];
    if (user?.role === 'student' && !allowedForStudent.includes(target)) return null;

    return (
      <button onClick={() => setView(target)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === target ? 'bg-amber-500 text-slate-950 shadow-lg scale-105' : 'text-slate-400 hover:bg-slate-800'}`}>
        <Icon size={18} /> <span>{label}</span>
      </button>
    );
  };

  if (view === AppView.Login) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-slate-900 rounded-[3rem] border border-slate-800 p-12 shadow-2xl text-center">
          <Medal className="text-amber-500 mx-auto mb-6" size={64} />
          <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter mb-2">{adminProfile?.dojoName || "Dojô Master"}</h1>
          <div className="mt-8 space-y-6">
            <div className="flex bg-slate-800 p-1.5 rounded-2xl">
