                  <span className="text-sm font-black text-amber-500">{form.accessId}</span>
                </div>
                <input type="text" placeholder="Nome do Aluno" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
                <input type="email" placeholder="E-mail" value={form.email || ''} onChange={e => setForm({...form, email: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-500 uppercase px-1">Categoria</label>
                    <select value={form.category} onChange={e => setForm({...form, category: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white uppercase text-[10px] font-black">
                      <option value="Adulto">Adulto (IBJJF)</option>
                      <option value="Infantil">Infantil (IBJJF)</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[8px] font-black text-slate-500 uppercase px-1">Vencimento</label>
                    <input type="number" placeholder="Dia" value={form.paymentDay || ''} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[8px] font-black text-slate-500 uppercase px-1">Faixa (Padrão IBJJF)</label>
                  <select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white uppercase text-[10px] font-black">
                    {form.category === 'Adulto' ? (
                      ['Branca', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)
                    ) : (
                      ['Branca', 'Cinza', 'Amarela', 'Laranja', 'Verde'].map(b => <option key={b} value={b}>{b}</option>)
                    )}
                  </select>
                </div>
              </div>
            )}

            {modalType === 'transaction' && (
              <div className="space-y-4">
                <div className="flex bg-slate-800 p-1 rounded-2xl">
                   <button onClick={() => setForm({...form, type: 'income'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${form.type === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500'}`}>Receita</button>
                   <button onClick={() => setForm({...form, type: 'expense'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition ${form.type === 'expense' ? 'bg-red-500 text-white shadow-lg' : 'text-slate-500'}`}>Despesa</button>
                </div>
                <input type="text" placeholder="Descrição do Fluxo" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none" />
                <input type="number" placeholder="Valor em R$" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
              </div>
            )}

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: false, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString() }]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-5 rounded-2xl hover:bg-amber-400 transition uppercase tracking-widest italic text-sm shadow-xl flex items-center justify-center gap-2">
              <Save size={18} /> Confirmar Registro
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

