            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase">Endereço Físico</label>
              <input name="address" required type="text" placeholder="Rua das Lutas, 123" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase">Senha Administrativa</label>
