              <input type="text" placeholder="Endereço Completo" value={onboardingForm.address?.street || ''} onChange={e => setOnboardingForm({...onboardingForm, address: {...(onboardingForm.address || INITIAL_ADDRESS), street: e.target.value}})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
