                <input type="date" value={form.date || ''} onChange={e => setForm({...form, date: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white outline-none" />
              </div>
            )}

            {modalType === 'photo' && (
              <div className="space-y-6">
                <div className="relative group cursor-pointer border-2 border-dashed border-slate-700 rounded-[2.5rem] p-10 hover:border-amber-500/50 transition-all text-center bg-slate-800/30 overflow-hidden">
                  <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer z-10" />
                  {form.url ? (
                    <div className="space-y-2">
                       <img src={form.url} className="w-full h-48 object-cover rounded-3xl border border-slate-700" alt="Preview" />
                       <p className="text-[8px] font-black text-amber-500 uppercase tracking-widest">Clique para trocar a imagem</p>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center py-4">
                      <div className="bg-slate-900 p-4 rounded-3xl mb-4 text-slate-600"><Upload size={48} /></div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Selecionar da Galeria</p>
                    </div>
                  )}
                </div>
                <input type="text" placeholder="Escreva uma legenda OSS..." value={form.caption || ''} onChange={e => setForm({...form, caption: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
              </div>
            )}

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: false, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString(), amount: Number(form.amount) }]);
              } else if (modalType === 'photo') {
                if (!form.url) return alert("Escolha uma imagem!");
                setMural(prev => [{ ...form, id: Date.now().toString(), date: new Date().toLocaleDateString(), postedBy: user?.name || 'Mestre' }, ...prev]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-400 transition-all uppercase tracking-widest italic text-sm shadow-2xl shadow-amber-500/10 flex items-center justify-center gap-2">
              <Save size={20} /> {modalType === 'photo' ? 'Publicar no Dojô' : 'Salvar Informações'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, Lock, ShieldCheck, Mail, MapPin, Phone, Briefcase,
  TrendingDown, TrendingUp, Camera, Image as ImageIcon, Info, Upload, ChevronRight
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address, MuralPhoto, AgeCategory } from './types';
import { getDojoInsights } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

// Define colors for BJJ belts to fix the missing BELT_COLORS constant error
const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78350f',
  'Preta': '#0f172a'
};

const App: React.FC = () => {
  // --- STATE PERSISTENCE ---
  const [athletes, setAthletes] = useState<Athlete[]>(() => {
    const saved = localStorage.getItem('bjj_athletes_v5');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('bjj_transactions_v5');
    return saved ? JSON.parse(saved) : [];
  });

  const [mural, setMural] = useState<MuralPhoto[]>(() => {
    const saved = localStorage.getItem('bjj_mural_v5');
    return saved ? JSON.parse(saved) : [
      { id: 'm1', url: 'https://images.unsplash.com/photo-1555597673-b21d5c935865?auto=format&fit=crop&w=800', caption: 'Primeiro Treino!', date: '2024-01-01', postedBy: 'Sistema' }
    ];
  });

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('bjj_admin_v5');
    return saved ? JSON.parse(saved) : null;
  });

  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  // --- AUTO-SAVE ---
  useEffect(() => {
    localStorage.setItem('bjj_athletes_v5', JSON.stringify(athletes));
  }, [athletes]);

  useEffect(() => {
    localStorage.setItem('bjj_transactions_v5', JSON.stringify(transactions));
  }, [transactions]);

  useEffect(() => {
    localStorage.setItem('bjj_mural_v5', JSON.stringify(mural));
  }, [mural]);

  useEffect(() => {
    if (adminProfile) localStorage.setItem('bjj_admin_v5', JSON.stringify(adminProfile));
  }, [adminProfile]);

  // --- AI INSIGHTS ---
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, transactions, athletes, user]);

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (isAdminLogin) {
      if (!adminProfile?.registered) {
        setView(AppView.AdminRegistration);
        return;
      }
      if (password === adminProfile.password) {
        setUser({ name: adminProfile.name, role: 'admin' });
        setView(AppView.Dashboard);
      } else {
        alert("Senha administrativa incorreta!");
      }
      return;
    }

    const ath = athletes.find(a => a.accessId.toUpperCase() === loginId.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      if (!ath.profileComplete) {
        setOnboardingForm({...ath, address: ath.address || INITIAL_ADDRESS});
        setView(AppView.ProfileCompletion);
      } else {
        setView(AppView.Dashboard);
      }
    } else {
      alert("ID de Aluno não encontrado. Verifique com seu Professor.");
    }
  };

  const finalizeOnboarding = () => {
    if (!onboardingForm.cpf || !onboardingForm.phone || !onboardingForm.termsAccepted) {
      return alert("Campos CPF, WhatsApp e Termos são obrigatórios.");
    }
    setAthletes(prev => prev.map(a => a.id === user?.athleteId ? { 
      ...a, 
      ...onboardingForm, 
      profileComplete: true 
    } as Athlete : a));
    setView(AppView.Dashboard);
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    if (fd.get('password') !== fd.get('confirm_password')) return alert("As senhas não conferem.");

    const newProfile: AdminProfile = {
      name: fd.get('name') as string,
      dojoName: fd.get('dojoName') as string,
      email: fd.get('email') as string,
      phone: fd.get('phone') as string,
      address: fd.get('address') as string,
      password: fd.get('password') as string,
      registered: true
    };
    setAdminProfile(newProfile);
    setUser({ name: newProfile.name, role: 'admin' });
    setView(AppView.Dashboard);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setForm({ ...form, url: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-4 w-14 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-0.5" style={{ backgroundColor: BELT_COLORS[belt] || '#ffffff' }}>
        <div className="absolute left-0 h-full w-2.5 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-2 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[7px] font-bold uppercase text-slate-500 mt-0.5">{belt}</span>
    </div>
  );

  const NavButton = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => {
    const allowedForStudent = [AppView.Dashboard, AppView.Ranking, AppView.Mural];
    if (user?.role === 'student' && !allowedForStudent.includes(target)) return null;

    return (
      <button onClick={() => setView(target)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === target ? 'bg-amber-500 text-slate-950 shadow-lg scale-105' : 'text-slate-400 hover:bg-slate-800'}`}>
        <Icon size={18} /> <span>{label}</span>
      </button>
    );
  };

  // --- VIEWS ---

  if (view === AppView.Login) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="max-w-md w-full bg-slate-900 rounded-[3rem] border border-slate-800 p-10 md:p-14 shadow-2xl text-center">
          <div className="w-20 h-20 bg-amber-500 rounded-3xl mx-auto flex items-center justify-center mb-8 shadow-amber-500/20 shadow-2xl rotate-3">
             <Medal className="text-slate-900" size={44} />
          </div>
          <h1 className="text-3xl font-black text-white italic uppercase tracking-tighter mb-2 leading-none">{adminProfile?.dojoName || "BJJ CONTROL"}</h1>
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Oss! Bem-vindo ao Sistema</p>

          <div className="mt-10 space-y-6">
            <div className="flex bg-slate-800/50 p-1.5 rounded-2xl border border-slate-700/50">
              <button onClick={() => setIsAdminLogin(false)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all duration-300 ${!isAdminLogin ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-500'}`}>Aluno</button>
              <button onClick={() => setIsAdminLogin(true)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all duration-300 ${isAdminLogin ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500'}`}>Mestre</button>
            </div>

            <div className="text-left space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">{isAdminLogin ? 'Senha de Segurança' : 'Identificação de Acesso'}</label>
              <div className="relative">
                {isAdminLogin ? <Lock className="absolute left-4 top-4 text-slate-600" size={20} /> : <Key className="absolute left-4 top-4 text-slate-600" size={20} />}
                <input 
                  type={isAdminLogin ? "password" : "text"} 
                  value={isAdminLogin ? password : loginId} 
                  onChange={e => isAdminLogin ? setPassword(e.target.value) : setLoginId(e.target.value)} 
                  placeholder={isAdminLogin ? "Digite sua senha" : "Ex: BJJ-1234"} 
                  className="w-full p-4 pl-12 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500 transition-all" 
                />
              </div>
            </div>

            <button onClick={handleLogin} className={`w-full ${isAdminLogin ? 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-500/10' : 'bg-amber-500 hover:bg-amber-400 text-slate-950 shadow-amber-500/10'} font-black py-5 rounded-2xl transition-all uppercase text-xs flex items-center justify-center gap-2 shadow-2xl hover:-translate-y-1`}>
              {isAdminLogin && !adminProfile?.registered ? "Iniciar Configuração" : "Confirmar e Entrar"} <ArrowRight size={18} />
            </button>
          </div>
        </div>
      </div>
    );
  }

  if (view === AppView.AdminRegistration) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6 py-12">
        <div className="max-w-2xl w-full bg-slate-900 rounded-[3rem] border border-slate-800 p-10 md:p-14 shadow-2xl">
          <header className="text-center mb-10">
            <ShieldCheck className="text-indigo-500 mx-auto mb-4" size={64} />
            <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Primeiro Passo: Dojô</h2>
            <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-2">Personalize o sistema com sua marca</p>
          </header>
          <form onSubmit={registerAdmin} className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2 space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">Nome da Academia</label>
              <input name="dojoName" required type="text" placeholder="Ex: Gracie Barra Matriz" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">Nome do Responsável</label>
              <input name="name" required type="text" placeholder="Mestre Fulano" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">WhatsApp</label>
              <input name="phone" required type="text" placeholder="(11) 99999-9999" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none" />
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">Senha Mestra</label>
              <input name="password" required type="password" placeholder="Defina sua senha" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" />
            </div>
            <div className="md:col-span-2 space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase px-1">Confirmar Senha</label>
              <input name="confirm_password" required type="password" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white outline-none focus:ring-2 focus:ring-indigo-500" />
            </div>
            <button type="submit" className="md:col-span-2 w-full bg-indigo-600 text-white font-black py-5 rounded-2xl hover:bg-indigo-500 transition-all uppercase text-xs flex items-center justify-center gap-2 shadow-2xl mt-4">
              Salvar e Entrar <CheckCircle2 size={18} />
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (view === AppView.ProfileCompletion) {
    return (
      <div className="min-h-screen bg-slate-950 p-6 flex items-center justify-center py-12">
        <div className="max-w-4xl w-full bg-slate-900 border border-slate-800 rounded-[3rem] p-10 md:p-14 shadow-2xl overflow-y-auto max-h-[90vh]">
          <header className="mb-10 text-center">
            <ClipboardCheck size={56} className="text-amber-500 mx-auto mb-4" />
            <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Conclua sua Matrícula</h2>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest">Segurança e saúde em primeiro lugar no tatame</p>
          </header>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
            <div className="space-y-6">
              <h4 className="text-[10px] font-black text-amber-500 uppercase border-b border-slate-800 pb-2">Dados Pessoais</h4>
              <input type="text" placeholder="CPF" value={onboardingForm.cpf || ''} onChange={e => setOnboardingForm({...onboardingForm, cpf: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <input type="text" placeholder="WhatsApp (DDD)" value={onboardingForm.phone || ''} onChange={e => setOnboardingForm({...onboardingForm, phone: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              <div className="space-y-1">
                <label className="text-[8px] font-black text-slate-500 uppercase ml-2">Data de Nascimento</label>
                <input type="date" value={onboardingForm.birthDate || ''} onChange={e => setOnboardingForm({...onboardingForm, birthDate: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              </div>
            </div>
            <div className="space-y-6">
              <h4 className="text-[10px] font-black text-red-500 uppercase border-b border-slate-800 pb-2">Informações de Saúde</h4>
              <div className="grid grid-cols-2 gap-4">
                <input type="text" placeholder="Tipo Sanguíneo" value={onboardingForm.bloodType || ''} onChange={e => setOnboardingForm({...onboardingForm, bloodType: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white uppercase" />
                <input type="text" placeholder="Tel Emergência" value={onboardingForm.emergencyPhone || ''} onChange={e => setOnboardingForm({...onboardingForm, emergencyPhone: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white" />
              </div>
              <textarea placeholder="Possui Alergias ou problemas cardíacos/respiratórios?" value={onboardingForm.medicalNotes || ''} onChange={e => setOnboardingForm({...onboardingForm, medicalNotes: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-2xl text-white min-h-[140px]" />
            </div>
          </div>
          <div className="mt-8 flex items-start gap-4 bg-slate-800/50 p-6 rounded-3xl border border-slate-700/50">
            <input type="checkbox" checked={onboardingForm.termsAccepted || false} onChange={e => setOnboardingForm({...onboardingForm, termsAccepted: e.target.checked})} className="mt-1 h-6 w-6 rounded bg-slate-800 border-slate-700 text-amber-500 focus:ring-amber-500 transition-all" />
            <p className="text-[10px] text-slate-400 uppercase font-bold leading-relaxed">Confirmo que as informações acima são reais. Declaro estar apto para a prática de atividades físicas de alta intensidade e assumo total responsabilidade pelos riscos inerentes ao esporte.</p>
          </div>
          <button onClick={finalizeOnboarding} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-2xl hover:bg-amber-400 transition-all uppercase tracking-widest italic shadow-xl shadow-amber-500/10">Finalizar e Começar o Treino</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter']">
      {/* Sidebar for Desktop */}
      <aside className="w-72 bg-slate-900 border-r border-slate-800 p-8 hidden md:flex flex-col gap-6">
        <div className="flex items-center space-x-3 mb-8">
          <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg shadow-amber-500/20">
            <Medal className="text-slate-900" size={24} />
          </div>
          <span className="text-xl font-black uppercase italic tracking-tighter">BJJ CONTROL</span>
        </div>
        <nav className="flex-1 space-y-1.5">
          <NavButton target={AppView.Dashboard} icon={Home} label="Início" />
          <NavButton target={AppView.Athletes} icon={Users} label="Alunos" />
          <NavButton target={AppView.Attendance} icon={CalendarCheck} label="Frequência" />
          <NavButton target={AppView.Finance} icon={DollarSign} label="Financeiro" />
          <NavButton target={AppView.Ranking} icon={Trophy} label="Ranking" />
          <NavButton target={AppView.Mural} icon={ImageIcon} label="Mural" />
        </nav>
        <button onClick={() => { setUser(null); setView(AppView.Login); }} className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-2 hover:text-red-500 transition-colors p-4"><LogOut size={16}/> Sair do Sistema</button>
      </aside>

      {/* Main Content */}
      <main className="flex-1 p-6 md:p-12 overflow-y-auto">
        {view === AppView.Dashboard && (
          <div className="space-y-10 animate-in fade-in slide-in-from-top-4 duration-500">
            <header className="flex justify-between items-center">
              <div>
                <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">OSS, {user?.name}</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2">{user?.role === 'admin' ? adminProfile?.dojoName : 'Quadro Pessoal'}</p>
              </div>
            </header>

            {user?.role === 'student' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Financial Alert for Student */}
                <div className={`p-10 rounded-[3rem] border flex items-center gap-6 relative overflow-hidden shadow-2xl transition-all ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-red-500/10 border-red-500/30 shadow-red-500/5 animate-pulse'}`}>
                   <div className={`p-5 rounded-3xl ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500 shadow-emerald-500/20' : 'bg-red-500 shadow-red-500/20'} shadow-xl`}>
                    <CreditCard className="text-white" size={28} />
                  </div>
                  <div>
                    <h4 className="text-xl font-black text-white uppercase italic">Financeiro</h4>
