                   <button onClick={() => setForm({...form, type: 'income'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all duration-300 ${form.type === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500'}`}>Receita</button>
                   <button onClick={() => setForm({...form, type: 'expense'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all duration-300 ${form.type === 'expense' ? 'bg-red-500 text-white shadow-lg' : 'text-slate-500'}`}>Despesa</button>
                </div>
                <input type="text" placeholder="Nome da Transação" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-emerald-500" />
                <div className="relative">
                  <span className="absolute left-5 top-5 text-slate-500 font-black">R$</span>
                  <input type="number" placeholder="0,00" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-5 pl-12 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black outline-none tabular-nums" />
                </div>
                <input type="date" value={form.date || ''} onChange={e => setForm({...form, date: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white outline-none" />
              </div>
            )}

            {modalType === 'photo' && (
              <div className="space-y-6">
                <div className="relative group cursor-pointer border-2 border-dashed border-slate-700 rounded-[2.5rem] p-10 hover:border-amber-500/50 transition-all text-center bg-slate-800/30 overflow-hidden">
                  <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer z-10" />
                  {form.url ? (
                    <div className="space-y-2">
                       <img src={form.url} className="w-full h-48 object-cover rounded-3xl border border-slate-700" alt="Preview" />
                       <p className="text-[8px] font-black text-amber-500 uppercase tracking-widest">Clique para trocar a imagem</p>
                    </div>
                  ) : (
                    <div className="flex flex-col items-center py-4">
                      <div className="bg-slate-900 p-4 rounded-3xl mb-4 text-slate-600"><Upload size={48} /></div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Selecionar da Galeria</p>
                    </div>
                  )}
                </div>
                <input type="text" placeholder="Escreva uma legenda OSS..." value={form.caption || ''} onChange={e => setForm({...form, caption: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
              </div>
            )}

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: false, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString(), amount: Number(form.amount) }]);
              } else if (modalType === 'photo') {
                if (!form.url) return alert("Escolha uma imagem!");
                setMural(prev => [{ ...form, id: Date.now().toString(), date: new Date().toLocaleDateString(), postedBy: user?.name || 'Mestre' }, ...prev]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-400 transition-all uppercase tracking-widest italic text-sm shadow-2xl shadow-amber-500/10 flex items-center justify-center gap-2">
              <Save size={20} /> {modalType === 'photo' ? 'Publicar no Dojô' : 'Salvar Informações'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export type UserRole = 'admin' | 'professor' | 'student';
export type AgeCategory = 'Infantil' | 'Adulto';

export type AdultBelt = 'Branca' | 'Azul' | 'Roxa' | 'Marrom' | 'Preta';
export type KidsBelt = 'Branca' | 'Cinza' | 'Amarela' | 'Laranja' | 'Verde';
export type Belt = AdultBelt | KidsBelt;

export interface Address {
  street: string;
  number: string;
  neighborhood: string;
  city: string;
  cep: string;
}

export interface AdminProfile {
  name: string;
  dojoName: string;
  email: string;
  password: string;
  phone: string;
  address: string;
  registered: boolean;
}

export interface TrainingClass {
  id: string;
  name: string;
  schedule: string;
  days: string;
  color: string;
}

export interface Athlete {
  id: string;
  accessId: string;
  name: string;
  email: string;
  cpf: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  belt: Belt;
  degrees: number;
  category: AgeCategory;
  classId?: string; // ID da Turma
  phone: string;
  emergencyContact: string;
  emergencyPhone: string;
  bloodType: string;
  medicalNotes: string;
  allergies: string;
  medications: string;
  address: Address;
  termsAccepted: boolean;
  profileComplete: boolean;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  date: string;
  description: string;
  category: string;
  athleteId?: string;
  status: 'pending' | 'verified';
}

export interface MuralPhoto {
  id: string;
  url: string;
  caption: string;
  date: string;
  postedBy: string;
}

export enum AppView {
  Login = 'login',
  Dashboard = 'dashboard', 
  Athletes = 'athletes',
  Classes = 'classes',
  Attendance = 'attendance',
  Finance = 'finance',
  Ranking = 'ranking',
  Mural = 'mural',
  ProfileCompletion = 'profile-completion',
  AdminRegistration = 'admin-registration'
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, Lock, ShieldCheck, Mail, MapPin, Phone, Briefcase,
  TrendingDown, TrendingUp, Camera, Image as ImageIcon, Info, Upload, ChevronRight,
  Clock, Filter, LayoutGrid, Trash2
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address, MuralPhoto, AgeCategory, TrainingClass } from './types';
import { getDojoInsights } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78350f',
  'Preta': '#0f172a'
};

const CLASS_COLORS = [
  'bg-blue-500', 'bg-purple-500', 'bg-orange-500', 'bg-emerald-500', 'bg-pink-500', 'bg-indigo-500'
];

const App: React.FC = () => {
  // --- STATE PERSISTENCE ---
  const [athletes, setAthletes] = useState<Athlete[]>(() => {
    const saved = localStorage.getItem('bjj_athletes_v6');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('bjj_transactions_v6');
    return saved ? JSON.parse(saved) : [];
  });

  const [classes, setClasses] = useState<TrainingClass[]>(() => {
    const saved = localStorage.getItem('bjj_classes_v6');
    return saved ? JSON.parse(saved) : [
      { id: 'c1', name: 'Iniciantes Noite', schedule: '19:00', days: 'Seg/Qua/Sex', color: 'bg-blue-500' },
      { id: 'c2', name: 'Competição', schedule: '20:30', days: 'Ter/Qui', color: 'bg-purple-500' }
    ];
  });

  const [mural, setMural] = useState<MuralPhoto[]>(() => {
    const saved = localStorage.getItem('bjj_mural_v6');
    return saved ? JSON.parse(saved) : [
      { id: 'm1', url: 'https://images.unsplash.com/photo-1555597673-b21d5c935865?auto=format&fit=crop&w=800', caption: 'OSS! Família reunida!', date: '2024-01-01', postedBy: 'Sistema' }
    ];
  });

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('bjj_admin_v6');
    return saved ? JSON.parse(saved) : null;
  });

  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');

  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo' | 'class'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  // --- AUTO-SAVE ---
  useEffect(() => localStorage.setItem('bjj_athletes_v6', JSON.stringify(athletes)), [athletes]);
  useEffect(() => localStorage.setItem('bjj_transactions_v6', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('bjj_classes_v6', JSON.stringify(classes)), [classes]);
  useEffect(() => localStorage.setItem('bjj_mural_v6', JSON.stringify(mural)), [mural]);
  useEffect(() => { if (adminProfile) localStorage.setItem('bjj_admin_v6', JSON.stringify(adminProfile)); }, [adminProfile]);

  // --- AI INSIGHTS ---
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, transactions, athletes, user]);

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (isAdminLogin) {
      if (!adminProfile?.registered) { setView(AppView.AdminRegistration); return; }
      if (password === adminProfile.password) { setUser({ name: adminProfile.name, role: 'admin' }); setView(AppView.Dashboard); }
      else alert("Senha incorreta!");
      return;
    }
    const ath = athletes.find(a => a.accessId.toUpperCase() === loginId.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      if (!ath.profileComplete) { setOnboardingForm({...ath, address: ath.address || INITIAL_ADDRESS}); setView(AppView.ProfileCompletion); }
      else setView(AppView.Dashboard);
    } else alert("ID não encontrado.");
  };

  const finalizeOnboarding = () => {
    if (!onboardingForm.cpf || !onboardingForm.phone || !onboardingForm.termsAccepted) return alert("Campos obrigatórios pendentes.");
    setAthletes(prev => prev.map(a => a.id === user?.athleteId ? { ...a, ...onboardingForm, profileComplete: true } as Athlete : a));
    setView(AppView.Dashboard);
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const fd = new FormData(e.currentTarget);
    if (fd.get('password') !== fd.get('confirm_password')) return alert("Senhas não conferem.");
    const newProfile: AdminProfile = {
      name: fd.get('name') as string, dojoName: fd.get('dojoName') as string,
      email: fd.get('email') as string, phone: fd.get('phone') as string,
      address: fd.get('address') as string, password: fd.get('password') as string, registered: true
    };
    setAdminProfile(newProfile); setUser({ name: newProfile.name, role: 'admin' }); setView(AppView.Dashboard);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setForm({ ...form, url: reader.result as string });
      reader.readAsDataURL(file);
    }
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-4 w-14 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-0.5" style={{ backgroundColor: BELT_COLORS[belt] || '#ffffff' }}>
        <div className="absolute left-0 h-full w-2.5 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-2 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[7px] font-bold uppercase text-slate-500 mt-0.5">{belt}</span>
    </div>
  );

  const filteredAttendanceList = useMemo(() => {
    if (selectedClassFilter === 'all') return athletes;
    return athletes.filter(a => a.classId === selectedClassFilter);
  }, [athletes, selectedClassFilter]);

  const NavButton = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => {
    const allowedForStudent = [AppView.Dashboard, AppView.Ranking, AppView.Mural];
    if (user?.role === 'student' && !allowedForStudent.includes(target)) return null;
    return (
      <button onClick={() => setView(target)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === target ? 'bg-amber-500 text-slate-950 shadow-lg scale-105' : 'text-slate-400 hover:bg-slate-800'}`}>
        <Icon size={18} /> <span>{label}</span>
      </button>
    );
  };

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter']">
      {/* Sidebar */}
      <aside className="w-72 bg-slate-900 border-r border-slate-800 p-8 hidden md:flex flex-col gap-6">
        <div className="flex items-center space-x-3 mb-8">
          <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg shadow-amber-500/20"><Medal className="text-slate-900" size={24} /></div>
          <span className="text-xl font-black uppercase italic tracking-tighter">BJJ CONTROL</span>
        </div>
        <nav className="flex-1 space-y-1.5">
          <NavButton target={AppView.Dashboard} icon={Home} label="Início" />
          <NavButton target={AppView.Athletes} icon={Users} label="Alunos" />
          <NavButton target={AppView.Classes} icon={LayoutGrid} label="Turmas" />
          <NavButton target={AppView.Attendance} icon={CalendarCheck} label="Frequência" />
          <NavButton target={AppView.Finance} icon={DollarSign} label="Financeiro" />
          <NavButton target={AppView.Ranking} icon={Trophy} label="Ranking" />
          <NavButton target={AppView.Mural} icon={ImageIcon} label="Mural" />
        </nav>
        <button onClick={() => { setUser(null); setView(AppView.Login); }} className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-2 hover:text-red-500 p-4"><LogOut size={16}/> Sair</button>
      </aside>

      <main className="flex-1 p-6 md:p-12 overflow-y-auto pb-24 md:pb-12">
        {view === AppView.Dashboard && (
          <div className="space-y-10 animate-in fade-in duration-500">
             {/* ... Dashboard code ... */}
             <header className="flex justify-between items-center">
              <div>
                <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">OSS, {user?.name}</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2">{user?.role === 'admin' ? adminProfile?.dojoName : 'Painel do Aluno'}</p>
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {user?.role === 'student' ? (
                  <>
                    <div className={`p-10 rounded-[3rem] border flex items-center gap-6 relative overflow-hidden shadow-2xl transition-all ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-red-500/10 border-red-500/30 shadow-red-500/5'}`}>
                      <div className={`p-5 rounded-3xl ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500' : 'bg-red-500'} shadow-xl`}><CreditCard className="text-white" size={28} /></div>
                      <div>
                        <h4 className="text-xl font-black text-white uppercase italic">Financeiro</h4>
                        <p className={`text-[11px] font-black uppercase ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'text-emerald-500' : 'text-red-500'}`}>
                          {loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? `Em dia (Vence dia ${loggedInAthlete.paymentDay})` : `PAGAMENTO PENDENTE (Venceu dia ${loggedInAthlete?.paymentDay})`}
                        </p>
                      </div>
                    </div>
                    <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 flex items-center gap-8 shadow-2xl">
                      <div className="w-24 h-24 bg-slate-800 rounded-3xl flex items-center justify-center border-2 border-amber-500/20"><UserIcon size={40} className="text-amber-500" /></div>
                      <div>
                        <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">{loggedInAthlete?.name}</h3>
                        <BeltBadge belt={loggedInAthlete?.belt || 'Branca'} degrees={loggedInAthlete?.degrees || 0} />
                        <p className="text-[10px] font-black text-slate-500 uppercase mt-4">Sua Turma: {classes.find(c => c.id === loggedInAthlete?.classId)?.name || 'Não definida'}</p>
                      </div>
                    </div>
                  </>
                ) : (
                  <div className="md:col-span-2 grid grid-cols-2 md:grid-cols-4 gap-6">
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 shadow-xl"><p className="text-[10px] font-black text-slate-500 uppercase mb-2">Total Alunos</p><p className="text-3xl font-black text-white">{athletes.length}</p></div>
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-emerald-500 shadow-xl"><p className="text-[10px] font-black text-emerald-500 uppercase mb-2">Caixa</p><p className="text-3xl font-black text-white">R$ {stats.balance}</p></div>
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-amber-500 shadow-xl"><p className="text-[10px] font-black text-amber-500 uppercase mb-2">Cobrança</p><p className="text-3xl font-black text-white">{stats.imminentPayments.length}</p></div>
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-indigo-500 shadow-xl"><p className="text-[10px] font-black text-indigo-500 uppercase mb-2">B-Day</p><p className="text-3xl font-black text-white">{stats.birthdays.length}</p></div>
                  </div>
                )}
            </div>

            {user?.role === 'admin' && (
              <div className="bg-amber-500 text-slate-950 p-10 rounded-[3rem] shadow-2xl relative overflow-hidden group">
                <Star size={180} className="absolute -bottom-10 -right-10 opacity-10 group-hover:rotate-45 transition-all duration-1000" />
                <h3 className="text-xl font-black uppercase italic mb-4 flex items-center gap-2"><Star size={24}/> Sensei IA</h3>
                <p className="text-sm font-bold italic leading-relaxed">"{aiInsight || "Processando estatísticas..."}"</p>
              </div>
            )}
          </div>
        )}

        {view === AppView.Classes && user?.role === 'admin' && (
          <div className="space-y-10 animate-in slide-in-from-bottom-4 duration-300">
            <header className="flex justify-between items-center">
              <div>
                <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Gestão de Turmas</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-1">Organize horários e dias de treino</p>
              </div>
              <button onClick={() => { setForm({ color: CLASS_COLORS[0] }); setEditId(null); setModalType('class'); setIsModalOpen(true); }} className="bg-amber-500 text-slate-950 px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center gap-2 shadow-xl hover:scale-105 transition-all">
                <Plus size={18} /> Nova Turma
              </button>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {classes.map(c => (
                <div key={c.id} className="bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 shadow-2xl relative overflow-hidden group">
                  <div className={`absolute top-0 right-0 w-2 h-full ${c.color}`}></div>
                  <div className="flex justify-between items-start mb-6">
                    <div className={`${c.color} p-3 rounded-2xl shadow-lg`}><Users className="text-white" size={24} /></div>
                    <div className="flex gap-2">
                       <button onClick={() => { setForm(c); setEditId(c.id); setModalType('class'); setIsModalOpen(true); }} className="p-2 text-slate-600 hover:text-white transition-all"><Edit size={18} /></button>
                       <button onClick={() => setClasses(prev => prev.filter(item => item.id !== c.id))} className="p-2 text-slate-600 hover:text-red-500 transition-all"><Trash2 size={18} /></button>
                    </div>
                  </div>
                  <h4 className="text-xl font-black text-white uppercase italic mb-2 leading-tight">{c.name}</h4>
                  <div className="space-y-3">
                    <div className="flex items-center gap-2 text-slate-500">
                      <Clock size={14} /> <span className="text-[10px] font-black uppercase">{c.schedule}</span>
                    </div>
                    <div className="flex items-center gap-2 text-slate-500">
                      <CalendarCheck size={14} /> <span className="text-[10px] font-black uppercase">{c.days}</span>
                    </div>
                  </div>
                  <div className="mt-8 pt-6 border-t border-slate-800 flex justify-between items-center">
                    <p className="text-[10px] font-black text-slate-500 uppercase">Total Alunos</p>
                    <p className="text-2xl font-black text-white">{athletes.filter(a => a.classId === c.id).length}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {view === AppView.Attendance && user?.role === 'admin' && (
          <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-300">
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div>
                <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Lista de Presença</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-1">Sincronize a frequência da turma</p>
              </div>
              <div className="flex flex-wrap gap-2">
