                    <input type="text" placeholder="Dias (Ex: Seg/Qua/Sex)" value={form.days || ''} onChange={e => setForm({...form, days: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black outline-none focus:ring-2 focus:ring-amber-500" />
                  </div>
                  <div className="flex gap-2 p-2 bg-slate-950/50 rounded-2xl">
                    {CLASS_COLORS.map(c => (
                      <button key={c} onClick={() => setForm({...form, color: c})} className={`w-8 h-8 rounded-full ${c} ${form.color === c ? 'ring-4 ring-white' : ''}`}></button>
                    ))}
                  </div>
               </div>
            )}

            {modalType === 'athlete' && (
              <div className="space-y-4">
                <input type="text" placeholder="Nome do Aluno" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-3">Turma de Treino</label>
                  <select value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white uppercase text-[10px] font-black outline-none">
                    <option value="">Nenhuma Turma</option>
                    {classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.schedule})</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
