                        ['Branca', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)
                      ) : (
                        ['Branca', 'Cinza', 'Amarela', 'Laranja', 'Verde'].map(b => <option key={b} value={b}>{b}</option>)
                      )}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-3">Graus</label>
                    <select value={form.degrees} onChange={e => setForm({...form, degrees: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white uppercase text-[10px] font-black">
                      {[0, 1, 2, 3, 4].map(d => <option key={d} value={d}>{d} Graus</option>)}
                    </select>
                  </div>
                </div>
              </div>
            )}

            {/* Transação e Foto modals code (omitted for brevity but implied to stay the same) */}
            {modalType === 'transaction' && (
              <div className="space-y-5">
                <div className="flex bg-slate-800 p-1.5 rounded-[1.5rem] border border-slate-700">
                   <button onClick={() => setForm({...form, type: 'income'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all duration-300 ${form.type === 'income' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500'}`}>Receita</button>
                   <button onClick={() => setForm({...form, type: 'expense'})} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all duration-300 ${form.type === 'expense' ? 'bg-red-500 text-white shadow-lg' : 'text-slate-500'}`}>Despesa</button>
                </div>
                <input type="text" placeholder="Descrição" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-emerald-500" />
