              </div>
            )}

            {modalType === 'photo' && (
              <div className="space-y-6">
                <div className="relative group cursor-pointer border-2 border-dashed border-slate-700 rounded-[2.5rem] p-10 hover:border-amber-500/50 transition-all text-center bg-slate-800/30 overflow-hidden">
                  <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer z-10" />
                  {form.url ? (
                    <img src={form.url} className="w-full h-48 object-cover rounded-3xl" alt="Preview" />
                  ) : (
                    <div className="flex flex-col items-center py-4">
                      <Upload className="text-slate-600 mb-2" size={48} />
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Galeria</p>
                    </div>
                  )}
                </div>
                <input type="text" placeholder="Legenda..." value={form.caption || ''} onChange={e => setForm({...form, caption: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500" />
              </div>
            )}

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: false, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              } else if (modalType === 'class') {
                if (editId) setClasses(prev => prev.map(c => c.id === editId ? { ...c, ...form } : c));
                else setClasses(prev => [...prev, { ...form, id: Date.now().toString() }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString(), amount: Number(form.amount) }]);
              } else if (modalType === 'photo') {
                setMural(prev => [{ ...form, id: Date.now().toString(), date: new Date().toLocaleDateString(), postedBy: user?.name || 'Mestre' }, ...prev]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-400 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-2">
              <Save size={20} /> Confirmar OSS
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

