  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78350f',
  'Preta': '#0f172a'
};

