    if (fd.get('password') !== fd.get('confirm_password')) return alert("Senhas não conferem.");
    const newProfile: AdminProfile = {
      name: fd.get('name') as string, dojoName: fd.get('dojoName') as string,
      email: fd.get('email') as string, phone: fd.get('phone') as string,
      address: fd.get('address') as string, password: fd.get('password') as string, registered: true
