          <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg"><Medal className="text-slate-900" size={24} /></div>
          <span className="text-xl font-black uppercase italic tracking-tighter">BJJ CONTROL</span>
