                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2">{user?.role === 'admin' ? adminProfile?.dojoName : 'Painel do Aluno'}</p>
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {user?.role === 'student' ? (
                  <>
                    <div className={`p-10 rounded-[3rem] border flex items-center gap-6 relative overflow-hidden shadow-2xl transition-all ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-red-500/10 border-red-500/30 shadow-red-500/5 animate-pulse'}`}>
                      <div className={`p-5 rounded-3xl ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500' : 'bg-red-500'} shadow-xl`}><CreditCard className="text-white" size={28} /></div>
                      <div>
                        <h4 className="text-xl font-black text-white uppercase italic">Financeiro</h4>
                        <p className={`text-[11px] font-black uppercase ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'text-emerald-500' : 'text-red-500'}`}>
                          {loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? `Em dia (Vence dia ${loggedInAthlete.paymentDay})` : `PAGAMENTO PENDENTE (Venceu dia ${loggedInAthlete?.paymentDay})`}
