  'bg-blue-500', 'bg-purple-500', 'bg-orange-500', 'bg-emerald-500', 'bg-pink-500', 'bg-indigo-500'
];

const App: React.FC = () => {
  // --- PERSISTÊNCIA ---
  const [athletes, setAthletes] = useState<Athlete[]>(() => {
    const saved = localStorage.getItem('bjj_athletes_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('bjj_transactions_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [classes, setClasses] = useState<TrainingClass[]>(() => {
    const saved = localStorage.getItem('bjj_classes_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'c1', name: 'Iniciantes', schedule: '19:00', days: 'Seg/Qua/Sex', color: 'bg-blue-500' },
      { id: 'c2', name: 'Avançado/Competição', schedule: '20:30', days: 'Todos os dias', color: 'bg-purple-500' }
    ];
  });

  const [mural, setMural] = useState<MuralPhoto[]>(() => {
    const saved = localStorage.getItem('bjj_mural_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'm1', url: 'https://images.unsplash.com/photo-1555597673-b21d5c935865?auto=format&fit=crop&w=800', caption: 'OSS! Bem vindos ao tatame!', date: '2024-05-01', postedBy: 'Sensei' }
    ];
  });

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('bjj_admin_v7');
    return saved ? JSON.parse(saved) : null;
  });

  // Estados de sessão
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');

  // Estados de Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo' | 'class'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  // --- ESTADO DO TEMPORIZADOR ---
  const [timerDuration, setTimerDuration] = useState(300); // 5 min padrão
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<'buzzer' | 'bell' | 'digital'>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [manualSec, setManualSec] = useState(0);
  const timerIntervalRef = useRef<number | null>(null);

  // Efeitos de salvamento
  useEffect(() => localStorage.setItem('bjj_athletes_v7', JSON.stringify(athletes)), [athletes]);
  useEffect(() => localStorage.setItem('bjj_transactions_v7', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('bjj_classes_v7', JSON.stringify(classes)), [classes]);
  useEffect(() => localStorage.setItem('bjj_mural_v7', JSON.stringify(mural)), [mural]);
  useEffect(() => { if (adminProfile) localStorage.setItem('bjj_admin_v7', JSON.stringify(adminProfile)); }, [adminProfile]);

  // Insights do Gemini
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, transactions, athletes, user]);

  // Lógica do Temporizador
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      playAlarm();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const playAlarm = () => {
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();

    osc.connect(gain);
    gain.connect(ctx.destination);

    if (selectedAlarm === 'buzzer') {
      osc.type = 'sawtooth';
      osc.frequency.setValueAtTime(100, ctx.currentTime);
      gain.gain.setValueAtTime(0.5, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 2);
      osc.start();
      osc.stop(ctx.currentTime + 2);
    } else if (selectedAlarm === 'bell') {
      osc.type = 'sine';
      osc.frequency.setValueAtTime(880, ctx.currentTime);
      gain.gain.setValueAtTime(0.5, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 3);
      osc.start();
      osc.stop(ctx.currentTime + 3);
    } else {
      osc.type = 'square';
      osc.frequency.setValueAtTime(440, ctx.currentTime);
      gain.gain.setValueAtTime(0.3, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 1);
      osc.start();
      osc.stop(ctx.currentTime + 1);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateManualTimer = (m: number, s: number) => {
    const total = (m * 60) + s;
    setTimerDuration(total);
    setTimeLeft(total);
    setIsTimerRunning(false);
  };

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => {
      if (!a.birthDate) return false;
      return new Date(a.birthDate).getMonth() === currentMonth;
    });
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (isAdminLogin) {
      if (!adminProfile?.registered) { setView(AppView.AdminRegistration); return; }
      if (password === adminProfile.password) { setUser({ name: adminProfile.name, role: 'admin' }); setView(AppView.Dashboard); }
      else alert("Senha incorreta!");
      return;
    }
    const ath = athletes.find(a => a.accessId.toUpperCase() === loginId.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      if (!ath.profileComplete) { setOnboardingForm({...ath, address: ath.address || INITIAL_ADDRESS}); setView(AppView.ProfileCompletion); }
      else setView(AppView.Dashboard);
    } else alert("ID não encontrado. Peça ao seu professor.");
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const password = formData.get('password') as string;
    const confirm = formData.get('confirm_password') as string;
    if (password !== confirm) return alert("As senhas não coincidem!");
    const newProfile: AdminProfile = {
      name: formData.get('name') as string,
      dojoName: formData.get('dojoName') as string,
      email: formData.get('email') as string,
      phone: formData.get('phone') as string,
      address: formData.get('address') as string,
      password: password,
      registered: true
    };
    setAdminProfile(newProfile); setUser({ name: newProfile.name, role: 'admin' }); setView(AppView.Dashboard);
  };

  const finalizeOnboarding = () => {
    if (!onboardingForm.termsAccepted) return alert("Você deve aceitar os termos para continuar.");
    setAthletes(prev => prev.map(ath => ath.id === onboardingForm.id ? { ...ath, ...onboardingForm, profileComplete: true } as Athlete : ath));
    setView(AppView.Dashboard);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setForm((prev: any) => ({ ...prev, url: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-4 w-14 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-0.5" style={{ backgroundColor: BELT_COLORS[belt] || '#ffffff' }}>
        <div className="absolute left-0 h-full w-2.5 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-2 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[7px] font-bold uppercase text-slate-500 mt-0.5">{belt}</span>
    </div>
  );

  const filteredAttendanceList = useMemo(() => {
    if (selectedClassFilter === 'all') return athletes;
    return athletes.filter(a => a.classId === selectedClassFilter);
  }, [athletes, selectedClassFilter]);

  const NavButton = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => {
    const allowedForStudent = [AppView.Dashboard, AppView.Ranking, AppView.Mural, AppView.Timer];
    if (user?.role === 'student' && !allowedForStudent.includes(target)) return null;
    return (
      <button onClick={() => setView(target)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === target ? 'bg-amber-500 text-slate-950 shadow-lg scale-105' : 'text-slate-400 hover:bg-slate-800'}`}>
        <Icon size={18} /> <span>{label}</span>
      </button>
    );
  };

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter']">
      {/* Sidebar */}
      <aside className="w-72 bg-slate-900 border-r border-slate-800 p-8 hidden md:flex flex-col gap-6">
        <div className="flex items-center space-x-3 mb-8">
          <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg"><Medal className="text-slate-950" size={24} /></div>
          <span className="text-xl font-black uppercase italic tracking-tighter text-white">TIME BJJ</span>
        </div>
        <nav className="flex-1 space-y-1.5">
          <NavButton target={AppView.Dashboard} icon={Home} label="Início" />
          <NavButton target={AppView.Athletes} icon={Users} label="Alunos" />
          <NavButton target={AppView.Classes} icon={LayoutGrid} label="Turmas" />
          <NavButton target={AppView.Attendance} icon={CalendarCheck} label="Frequência" />
          <NavButton target={AppView.Finance} icon={DollarSign} label="Financeiro" />
          <NavButton target={AppView.Ranking} icon={Trophy} label="Ranking" />
          <NavButton target={AppView.Mural} icon={ImageIcon} label="Mural" />
          <NavButton target={AppView.Timer} icon={Clock} label="Temporizador" />
        </nav>
        <button onClick={() => { setUser(null); setView(AppView.Login); }} className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-2 hover:text-red-500 p-4 transition-colors"><LogOut size={16}/> Sair</button>
      </aside>

      <main className="flex-1 p-6 md:p-12 overflow-y-auto pb-24 md:pb-12">
        {view === AppView.Login && (
          <div className="min-h-[80vh] flex items-center justify-center p-4">
            <div className="bg-slate-900 p-10 md:p-16 rounded-[4rem] border border-slate-800 w-full max-w-lg shadow-2xl relative overflow-hidden text-center">
               <div className="absolute top-0 right-0 w-64 h-64 bg-amber-500/5 rounded-full -translate-y-32 translate-x-32"></div>
               <div className="relative z-10">
                 <div className="w-16 h-16 bg-amber-500 rounded-2xl flex items-center justify-center mb-10 shadow-xl mx-auto"><Medal className="text-slate-950" size={32} /></div>
                 <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2 leading-none">{adminProfile?.dojoName || "TIME BJJ"}</h2>
                 <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-10">OSS! BEM VINDO AO TIME</p>
                 <div className="flex bg-slate-800 p-1.5 rounded-2xl mb-8 border border-slate-700">
                    <button onClick={() => setIsAdminLogin(false)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all ${!isAdminLogin ? 'bg-white text-slate-950 shadow-lg' : 'text-slate-500'}`}>Aluno</button>
                    <button onClick={() => setIsAdminLogin(true)} className={`flex-1 py-3 rounded-xl font-black text-[10px] uppercase transition-all ${isAdminLogin ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-500'}`}>Professor</button>
                 </div>
                 <div className="space-y-4">
                   {isAdminLogin ? (
                     <div className="relative">
                       <Lock className="absolute left-5 top-5 text-slate-600" size={20} />
                       <input type="password" placeholder="Senha do Professor" value={password} onChange={e => setPassword(e.target.value)} className="w-full p-5 pl-14 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white outline-none focus:ring-2 focus:ring-amber-500 transition-all font-black uppercase tracking-widest text-[11px]" />
                     </div>
                   ) : (
                    <div className="relative">
                      <Key className="absolute left-5 top-5 text-slate-600" size={20} />
                      <input type="text" placeholder="ID de Acesso (Ex: BJJ-1234)" value={loginId} onChange={e => setLoginId(e.target.value)} className="w-full p-5 pl-14 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white outline-none focus:ring-2 focus:ring-amber-500 transition-all font-black uppercase tracking-widest text-[11px]" />
                    </div>
                   )}
                   <button onClick={handleLogin} className="w-full bg-white text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-500 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-2 group">
                     Entrar no Tatame <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform"/>
                   </button>
                 </div>
               </div>
            </div>
          </div>
        )}

        {view === AppView.Timer && (
          <div className="space-y-10 animate-in fade-in duration-500 flex flex-col items-center">
             <header className="text-center w-full">
               <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">Treino de Lutas</h2>
               <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest">Controle de Tempo do Tatame</p>
             </header>

             <div className="w-full max-w-2xl bg-slate-900 rounded-[4rem] border border-slate-800 p-12 shadow-2xl flex flex-col items-center gap-10">
                {/* Timer Display */}
                <div className="text-[140px] font-black text-white leading-none tracking-tighter tabular-nums mb-4 drop-shadow-[0_0_30px_rgba(251,191,36,0.2)]">
                  {formatTime(timeLeft)}
                </div>

                {/* Manual Adjustment Inputs */}
                <div className="bg-slate-950 p-8 rounded-[3rem] border border-slate-800 w-full shadow-inner flex flex-col items-center gap-4">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Settings2 size={14}/> Ajuste Manual</p>
                  <div className="flex items-center gap-4">
                    <div className="flex flex-col items-center">
                      <label className="text-[8px] font-black text-slate-600 uppercase mb-1">Min</label>
                      <input 
                        type="number" 
                        min="0" 
                        max="99" 
                        value={manualMin} 
                        onChange={(e) => {
                          const val = parseInt(e.target.value) || 0;
                          setManualMin(val);
                          updateManualTimer(val, manualSec);
                        }}
                        className="w-20 p-4 bg-slate-900 border border-slate-700 rounded-2xl text-white font-black text-xl text-center outline-none focus:ring-2 focus:ring-amber-500 transition-all"
                      />
                    </div>
                    <span className="text-white font-black text-3xl mt-5">:</span>
                    <div className="flex flex-col items-center">
                      <label className="text-[8px] font-black text-slate-600 uppercase mb-1">Seg</label>
                      <input 
                        type="number" 
                        min="0" 
                        max="59" 
                        value={manualSec} 
                        onChange={(e) => {
                          const val = parseInt(e.target.value) || 0;
                          setManualSec(val);
                          updateManualTimer(manualMin, val);
                        }}
                        className="w-20 p-4 bg-slate-900 border border-slate-700 rounded-2xl text-white font-black text-xl text-center outline-none focus:ring-2 focus:ring-amber-500 transition-all"
                      />
                    </div>
                  </div>
                </div>

                {/* Quick Presets */}
                <div className="flex gap-3 flex-wrap justify-center">
                  {[2, 3, 5, 6, 8, 10].map(m => (
                    <button key={m} onClick={() => { 
                      setManualMin(m);
                      setManualSec(0);
                      updateManualTimer(m, 0);
                    }} className={`px-6 py-3 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${timerDuration === m * 60 && manualSec === 0 ? 'bg-amber-500 text-slate-950' : 'bg-slate-800 text-slate-500 hover:text-white'}`}>
                      {m} min
                    </button>
                  ))}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full">
                   <div className="space-y-4">
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center flex items-center justify-center gap-2"><Volume2 size={14}/> Alerta de Fim</p>
                      <div className="flex bg-slate-950 p-2 rounded-[2rem] border border-slate-800">
                         {(['buzzer', 'bell', 'digital'] as const).map(s => (
                           <button key={s} onClick={() => setSelectedAlarm(s)} className={`flex-1 py-3 rounded-xl font-black text-[9px] uppercase transition-all ${selectedAlarm === s ? 'bg-amber-500 text-slate-950' : 'text-slate-600'}`}>{s}</button>
                         ))}
                      </div>
                   </div>
                   <div className="flex items-center justify-center gap-4">
                      <button onClick={() => setIsTimerRunning(!isTimerRunning)} className={`w-24 h-24 rounded-[2.5rem] flex items-center justify-center shadow-2xl transition-all hover:scale-105 ${isTimerRunning ? 'bg-red-500 text-white' : 'bg-emerald-500 text-white'}`}>
                        {isTimerRunning ? <Pause size={40} /> : <Play size={40} className="ml-1" />}
                      </button>
                      <button onClick={() => { setIsTimerRunning(false); setTimeLeft(timerDuration); }} className="w-20 h-20 bg-slate-800 rounded-[2.5rem] flex items-center justify-center text-slate-400 hover:text-white transition-all">
                        <RotateCcw size={32} />
                      </button>
                   </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-6 w-full max-w-2xl">
                <div className="bg-slate-900/50 p-8 rounded-[3rem] border border-slate-800 flex items-center gap-6">
                   <div className="w-12 h-12 bg-amber-500/10 rounded-2xl flex items-center justify-center text-amber-500"><Bell size={24}/></div>
                   <p className="text-[11px] font-medium text-slate-400 leading-relaxed uppercase font-black italic">Ajuste o tempo livremente para drills específicos ou rolas curtos.</p>
                </div>
             </div>
          </div>
        )}

        {view === AppView.Dashboard && (
          <div className="space-y-10 animate-in fade-in duration-500">
             <header className="flex justify-between items-center">
              <div>
                <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">OSS, {user?.name}</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2">{user?.role === 'admin' ? adminProfile?.dojoName : 'Painel do Aluno'}</p>
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {user?.role === 'student' ? (
                  <>
                    <div className={`p-10 rounded-[3rem] border flex items-center gap-6 relative overflow-hidden shadow-2xl transition-all ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-red-500/10 border-red-500/30 shadow-red-500/5 animate-pulse'}`}>
                      <div className={`p-5 rounded-3xl ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'bg-emerald-500' : 'bg-red-500'} shadow-xl`}><CreditCard className="text-white" size={28} /></div>
                      <div>
                        <h4 className="text-xl font-black text-white uppercase italic">Financeiro</h4>
                        <p className={`text-[11px] font-black uppercase ${loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? 'text-emerald-500' : 'text-red-500'}`}>
                          {loggedInAthlete && loggedInAthlete.paymentDay >= new Date().getDate() ? `Em dia (Vence dia ${loggedInAthlete.paymentDay})` : `PAGAMENTO PENDENTE (Venceu dia ${loggedInAthlete?.paymentDay})`}
                        </p>
                      </div>
                    </div>
                    <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 flex items-center gap-8 shadow-2xl">
                      <div className="w-24 h-24 bg-slate-800 rounded-3xl flex items-center justify-center border-2 border-amber-500/20"><UserIcon size={40} className="text-amber-500" /></div>
                      <div>
                        <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">{loggedInAthlete?.name}</h3>
                        <BeltBadge belt={loggedInAthlete?.belt || 'Branca'} degrees={loggedInAthlete?.degrees || 0} />
                        <p className="text-[10px] font-black text-slate-500 uppercase mt-4">Sua Turma: {classes.find(c => c.id === loggedInAthlete?.classId)?.name || 'Sem Turma'}</p>
                      </div>
                    </div>
                  </>
                ) : (
                  <div className="md:col-span-2 grid grid-cols-2 md:grid-cols-4 gap-6">
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 shadow-xl"><p className="text-[10px] font-black text-slate-500 uppercase mb-2">Total Alunos</p><p className="text-3xl font-black text-white">{athletes.length}</p></div>
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-emerald-500 shadow-xl"><p className="text-[10px] font-black text-emerald-500 uppercase mb-2">Caixa</p><p className="text-3xl font-black text-white">R$ {stats.balance}</p></div>
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-amber-500 shadow-xl"><p className="text-[10px] font-black text-amber-500 uppercase mb-2">Cobrança</p><p className="text-3xl font-black text-white">{stats.imminentPayments.length}</p></div>
                    <div className="bg-slate-900 p-8 rounded-[2rem] border border-slate-800 border-b-indigo-500 shadow-xl"><p className="text-[10px] font-black text-indigo-500 uppercase mb-2">B-Day</p><p className="text-3xl font-black text-white">{stats.birthdays.length}</p></div>
                  </div>
                )}
            </div>

            {user?.role === 'admin' && (
              <div className="bg-amber-500 text-slate-950 p-10 rounded-[3rem] shadow-2xl relative overflow-hidden group transition-all hover:scale-[1.01]">
                <Star size={180} className="absolute -bottom-10 -right-10 opacity-10 group-hover:rotate-45 transition-all duration-1000" />
