import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, Lock, ShieldCheck, Mail, MapPin, Phone, Briefcase,
  TrendingDown, TrendingUp, Camera, Image as ImageIcon, Info, Upload, ChevronRight,
  Clock, Filter, LayoutGrid, Trash2, Play, Pause, RotateCcw, Volume2, Bell, Settings2,
  VolumeX
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address, MuralPhoto, AgeCategory, TrainingClass } from './types';
import { getDojoInsights } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78350f',
  'Preta': '#0f172a'
};

const CLASS_COLORS = [
  'bg-blue-500', 'bg-purple-500', 'bg-orange-500', 'bg-emerald-500', 'bg-pink-500', 'bg-indigo-500'
];

const App: React.FC = () => {
  // --- PERSISTÊNCIA ---
  const [athletes, setAthletes] = useState<Athlete[]>(() => {
    const saved = localStorage.getItem('bjj_athletes_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('bjj_transactions_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [classes, setClasses] = useState<TrainingClass[]>(() => {
    const saved = localStorage.getItem('bjj_classes_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'c1', name: 'Iniciantes', schedule: '19:00', days: 'Seg/Qua/Sex', color: 'bg-blue-500' },
      { id: 'c2', name: 'Avançado/Competição', schedule: '20:30', days: 'Todos os dias', color: 'bg-purple-500' }
    ];
  });

  const [mural, setMural] = useState<MuralPhoto[]>(() => {
    const saved = localStorage.getItem('bjj_mural_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'm1', url: 'https://images.unsplash.com/photo-1555597673-b21d5c935865?auto=format&fit=crop&w=800', caption: 'OSS! Bem vindos ao tatame!', date: '2024-05-01', postedBy: 'Sensei' }
    ];
  });

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('bjj_admin_v7');
    return saved ? JSON.parse(saved) : null;
  });

  // Estados de sessão
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [loginId, setLoginId] = useState('');
  const [password, setPassword] = useState('');
  const [isAdminLogin, setIsAdminLogin] = useState(false);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');

  // Estados de Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo' | 'class'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  // --- ESTADO DO TEMPORIZADOR ---
  const [timerDuration, setTimerDuration] = useState(300); // 5 min padrão
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<'buzzer' | 'bell' | 'digital'>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [manualSec, setManualSec] = useState(0);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const alarmOscillatorsRef = useRef<OscillatorNode[]>([]);

  // Efeitos de salvamento
  useEffect(() => localStorage.setItem('bjj_athletes_v7', JSON.stringify(athletes)), [athletes]);
  useEffect(() => localStorage.setItem('bjj_transactions_v7', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('bjj_classes_v7', JSON.stringify(classes)), [classes]);
  useEffect(() => localStorage.setItem('bjj_mural_v7', JSON.stringify(mural)), [mural]);
  useEffect(() => { if (adminProfile) localStorage.setItem('bjj_admin_v7', JSON.stringify(adminProfile)); }, [adminProfile]);

  // Insights do Gemini
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, transactions, athletes, user]);

  // Lógica do Temporizador
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      startContinuousAlarm();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const startContinuousAlarm = () => {
    stopAlarm(); // Garante que não há som tocando antes
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    audioContextRef.current = ctx;
    setIsAlarmPlaying(true);

    const playRound = () => {
      if (!audioContextRef.current) return;

      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);

      if (selectedAlarm === 'buzzer') {
        // Som de "buzzer" de tatame pesado
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(120, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 0.1);
        gain.gain.setValueAtTime(0.5, ctx.currentTime + 0.8);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 1);
        osc.start();
        osc.stop(ctx.currentTime + 1.1);
      } else if (selectedAlarm === 'bell') {
        // Sino de luta
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1200, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
        osc.start();
        osc.stop(ctx.currentTime + 1.6);
      } else {
        // Digital "beep"
        osc.type = 'square';
        osc.frequency.setValueAtTime(440, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 0.05);
        gain.gain.setValueAtTime(0.3, ctx.currentTime + 0.4);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.5);
        osc.start();
        osc.stop(ctx.currentTime + 0.6);
      }

      alarmOscillatorsRef.current.push(osc);
    };

    // Tocar o som repetidamente até parar
    const interval = selectedAlarm === 'bell' ? 2000 : 1200;
    const soundInterval = setInterval(() => {
      if (audioContextRef.current) {
        playRound();
      } else {
        clearInterval(soundInterval);
      }
    }, interval);

    playRound(); // Primeira execução imediata
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    alarmOscillatorsRef.current.forEach(osc => {
      try { osc.stop(); } catch (e) {}
    });
    alarmOscillatorsRef.current = [];
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateManualTimer = (m: number, s: number) => {
    const total = (m * 60) + s;
    setTimerDuration(total);
    setTimeLeft(total);
    setIsTimerRunning(false);
    stopAlarm();
  };

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => {
      if (!a.birthDate) return false;
      return new Date(a.birthDate).getMonth() === currentMonth;
    });
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (isAdminLogin) {
      if (!adminProfile?.registered) { setView(AppView.AdminRegistration); return; }
      if (password === adminProfile.password) { setUser({ name: adminProfile.name, role: 'admin' }); setView(AppView.Dashboard); }
      else alert("Senha incorreta!");
      return;
    }
    const ath = athletes.find(a => a.accessId.toUpperCase() === loginId.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      if (!ath.profileComplete) { setOnboardingForm({...ath, address: ath.address || INITIAL_ADDRESS}); setView(AppView.ProfileCompletion); }
      else setView(AppView.Dashboard);
    } else alert("ID não encontrado. Peça ao seu professor.");
  };

