         <button onClick={() => setView(AppView.Dashboard)} className={`p-2 transition-all ${view === AppView.Dashboard ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Home size={24}/></button>
         <button onClick={() => setView(AppView.Timer)} className={`p-2 transition-all ${view === AppView.Timer ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Clock size={24}/></button>
         <button onClick={() => setView(AppView.Ranking)} className={`p-2 transition-all ${view === AppView.Ranking ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Trophy size={24}/></button>
         <button onClick={() => setView(AppView.Mural)} className={`p-2 transition-all ${view === AppView.Mural ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><ImageIcon size={24}/></button>
      </nav>

      {/* MODALS */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[3.5rem] w-full max-w-md p-10 md:p-12 shadow-2xl animate-in zoom-in-95 duration-300 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">
                {editId ? 'Editar' : 'Novo'} {modalType === 'athlete' ? 'Atleta' : modalType === 'class' ? 'Turma' : modalType === 'photo' ? 'Mural' : 'Fluxo'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="bg-slate-800 p-2 rounded-2xl text-slate-500 hover:text-white transition-all"><X size={28} /></button>
            </div>

            {modalType === 'athlete' && (
              <div className="space-y-4">
                <input type="text" placeholder="Nome do Aluno" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500 transition-all" />
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Turma de Treino Habitual</label>
                  <select value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white uppercase text-[10px] font-black outline-none focus:ring-2 focus:ring-amber-500">
                    <option value="">Nenhuma Turma</option>
                    {classes.map(c => <option key={c.id} value={c.id}>{c.name} ({c.schedule})</option>)}
                  </select>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Categoria</label>
                    <select value={form.category} onChange={e => setForm({...form, category: e.target.value as AgeCategory, belt: e.target.value === 'Infantil' ? 'Cinza' : 'Branca'})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white uppercase text-[10px] font-black outline-none">
                      <option value="Adulto">Adulto (16+)</option>
                      <option value="Infantil">Infantil</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Vencimento (Dia)</label>
                    <input type="number" min="1" max="31" value={form.paymentDay || ''} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white outline-none focus:ring-2 focus:ring-amber-500" />
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Faixa</label>
                    <select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white uppercase text-[10px] font-black outline-none">
                      {form.category === 'Adulto' ? (
                        ['Branca', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)
                      ) : (
                        ['Branca', 'Cinza', 'Amarela', 'Laranja', 'Verde'].map(b => <option key={b} value={b}>{b}</option>)
                      )}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Graus</label>
                    <select value={form.degrees} onChange={e => setForm({...form, degrees: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white uppercase text-[10px] font-black outline-none">
                      {[0, 1, 2, 3, 4].map(d => <option key={d} value={d}>{d} Graus</option>)}
                    </select>
                  </div>
                </div>
              </div>
            )}

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: false, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              } else if (modalType === 'class') {
                if (editId) setClasses(prev => prev.map(c => c.id === editId ? { ...c, ...form } : c));
                else setClasses(prev => [...prev, { ...form, id: Date.now().toString() }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString(), amount: Number(form.amount) }]);
              } else if (modalType === 'photo') {
                if (!form.url) return alert("Escolha uma imagem!");
                setMural(prev => [{ ...form, id: Date.now().toString(), date: new Date().toLocaleDateString(), postedBy: user?.name || 'Mestre' }, ...prev]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-400 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-2">
              <Save size={20} /> Salvar OSS
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, Lock, ShieldCheck, Mail, MapPin, Phone, Briefcase,
  TrendingDown, TrendingUp, Camera, Image as ImageIcon, Info, Upload, ChevronRight,
  Clock, Filter, LayoutGrid, Trash2, Play, Pause, RotateCcw, Volume2, Bell, Settings2,
  VolumeX, Fingerprint
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address, MuralPhoto, AgeCategory, TrainingClass } from './types';
import { getDojoInsights } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78350f',
  'Preta': '#0f172a'
};

const CLASS_COLORS = [
  'bg-blue-500', 'bg-purple-500', 'bg-orange-500', 'bg-emerald-500', 'bg-pink-500', 'bg-indigo-500'
];

const App: React.FC = () => {
  // --- PERSISTÊNCIA ---
  const [athletes, setAthletes] = useState<Athlete[]>(() => {
    const saved = localStorage.getItem('bjj_athletes_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('bjj_transactions_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [classes, setClasses] = useState<TrainingClass[]>(() => {
    const saved = localStorage.getItem('bjj_classes_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'c1', name: 'Iniciantes', schedule: '19:00', days: 'Seg/Qua/Sex', color: 'bg-blue-500' },
      { id: 'c2', name: 'Avançado/Competição', schedule: '20:30', days: 'Todos os dias', color: 'bg-purple-500' }
    ];
  });

  const [mural, setMural] = useState<MuralPhoto[]>(() => {
    const saved = localStorage.getItem('bjj_mural_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'm1', url: 'https://images.unsplash.com/photo-1555597673-b21d5c935865?auto=format&fit=crop&w=800', caption: 'OSS! Bem vindos ao tatame!', date: '2024-05-01', postedBy: 'Sensei' }
    ];
  });

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('bjj_admin_v7');
    return saved ? JSON.parse(saved) : null;
  });

  // Estados de sessão
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [accessKey, setAccessKey] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');

  // Estados de Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo' | 'class'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  // --- ESTADO DO TEMPORIZADOR ---
  const [timerDuration, setTimerDuration] = useState(300);
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<'buzzer' | 'bell' | 'digital'>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [manualSec, setManualSec] = useState(0);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const alarmOscillatorsRef = useRef<OscillatorNode[]>([]);

  // Efeitos de salvamento
  useEffect(() => localStorage.setItem('bjj_athletes_v7', JSON.stringify(athletes)), [athletes]);
  useEffect(() => localStorage.setItem('bjj_transactions_v7', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('bjj_classes_v7', JSON.stringify(classes)), [classes]);
  useEffect(() => localStorage.setItem('bjj_mural_v7', JSON.stringify(mural)), [mural]);
  useEffect(() => { if (adminProfile) localStorage.setItem('bjj_admin_v7', JSON.stringify(adminProfile)); }, [adminProfile]);

  // Insights do Gemini
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, transactions, athletes, user]);

  // Lógica do Temporizador
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      startContinuousAlarm();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const startContinuousAlarm = () => {
    stopAlarm();
    const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
    audioContextRef.current = ctx;
    setIsAlarmPlaying(true);

    const playRound = () => {
      if (!audioContextRef.current) return;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);
      if (selectedAlarm === 'buzzer') {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(120, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 0.1);
        gain.gain.setValueAtTime(0.5, ctx.currentTime + 0.8);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 1);
        osc.start();
        osc.stop(ctx.currentTime + 1.1);
      } else if (selectedAlarm === 'bell') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1200, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
        osc.start();
        osc.stop(ctx.currentTime + 1.6);
      } else {
        osc.type = 'square';
        osc.frequency.setValueAtTime(440, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 0.05);
        gain.gain.setValueAtTime(0.3, ctx.currentTime + 0.4);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.5);
        osc.start();
        osc.stop(ctx.currentTime + 0.6);
      }
      alarmOscillatorsRef.current.push(osc);
    };
    const interval = selectedAlarm === 'bell' ? 2000 : 1200;
    const soundInterval = setInterval(() => {
      if (audioContextRef.current) playRound();
      else clearInterval(soundInterval);
    }, interval);
    playRound();
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    alarmOscillatorsRef.current.forEach(osc => { try { osc.stop(); } catch (e) {} });
    alarmOscillatorsRef.current = [];
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateManualTimer = (m: number, s: number) => {
    const total = (m * 60) + s;
    setTimerDuration(total);
    setTimeLeft(total);
    setIsTimerRunning(false);
    stopAlarm();
  };

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => {
      if (!a.birthDate) return false;
      return new Date(a.birthDate).getMonth() === currentMonth;
    });
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (!adminProfile?.registered) {
      setView(AppView.AdminRegistration);
      return;
    }

    // Tenta primeiro como Professor (Admin)
    if (accessKey === adminProfile.password) {
      setUser({ name: adminProfile.name, role: 'admin' });
      setView(AppView.Dashboard);
      setAccessKey('');
      return;
    }

    // Tenta como Aluno
    const ath = athletes.find(a => a.accessId.toUpperCase() === accessKey.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      setAccessKey('');
      if (!ath.profileComplete) {
        setOnboardingForm({...ath, address: ath.address || INITIAL_ADDRESS});
        setView(AppView.ProfileCompletion);
      } else {
        setView(AppView.Dashboard);
      }
      return;
    }

    alert("Chave de acesso inválida! Verifique com seu Sensei.");
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const password = formData.get('password') as string;
    const confirm = formData.get('confirm_password') as string;
    if (password !== confirm) return alert("As senhas não coincidem!");
    const newProfile: AdminProfile = {
      name: formData.get('name') as string,
      dojoName: formData.get('dojoName') as string,
      email: formData.get('email') as string,
      phone: formData.get('phone') as string,
      address: formData.get('address') as string,
      password: password,
      registered: true
    };
    setAdminProfile(newProfile); setUser({ name: newProfile.name, role: 'admin' }); setView(AppView.Dashboard);
  };

  const finalizeOnboarding = () => {
    if (!onboardingForm.termsAccepted) return alert("Você deve aceitar os termos para continuar.");
    setAthletes(prev => prev.map(ath => ath.id === onboardingForm.id ? { ...ath, ...onboardingForm, profileComplete: true } as Athlete : ath));
    setView(AppView.Dashboard);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setForm((prev: any) => ({ ...prev, url: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const BeltBadge = ({ belt, degrees }: { belt: Belt, degrees: number }) => (
    <div className="flex flex-col items-center">
      <div className="h-4 w-14 rounded border border-slate-700 relative overflow-hidden flex items-center justify-end px-0.5" style={{ backgroundColor: BELT_COLORS[belt] || '#ffffff' }}>
        <div className="absolute left-0 h-full w-2.5 bg-red-600"></div>
        <div className="flex space-x-0.5">
          {[...Array(degrees)].map((_, i) => <div key={i} className="h-2 w-0.5 bg-white"></div>)}
        </div>
      </div>
      <span className="text-[7px] font-bold uppercase text-slate-500 mt-0.5">{belt}</span>
    </div>
  );

  const filteredAttendanceList = useMemo(() => {
    if (selectedClassFilter === 'all') return athletes;
    return athletes.filter(a => a.classId === selectedClassFilter);
  }, [athletes, selectedClassFilter]);

  const NavButton = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => {
    const allowedForStudent = [AppView.Dashboard, AppView.Ranking, AppView.Mural, AppView.Timer];
    if (user?.role === 'student' && !allowedForStudent.includes(target)) return null;
    return (
      <button onClick={() => setView(target)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === target ? 'bg-amber-500 text-slate-950 shadow-lg scale-105' : 'text-slate-400 hover:bg-slate-800'}`}>
        <Icon size={18} /> <span>{label}</span>
      </button>
    );
  };

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter']">
      {/* Sidebar */}
      {view !== AppView.Login && view !== AppView.AdminRegistration && view !== AppView.ProfileCompletion && (
        <aside className="w-72 bg-slate-900 border-r border-slate-800 p-8 hidden md:flex flex-col gap-6">
          <div className="flex items-center space-x-3 mb-8">
            <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg"><Medal className="text-slate-950" size={24} /></div>
            <span className="text-xl font-black uppercase italic tracking-tighter text-white">TIME BJJ</span>
          </div>
          <nav className="flex-1 space-y-1.5">
            <NavButton target={AppView.Dashboard} icon={Home} label="Início" />
            <NavButton target={AppView.Athletes} icon={Users} label="Alunos" />
            <NavButton target={AppView.Classes} icon={LayoutGrid} label="Turmas" />
            <NavButton target={AppView.Attendance} icon={CalendarCheck} label="Frequência" />
            <NavButton target={AppView.Finance} icon={DollarSign} label="Financeiro" />
            <NavButton target={AppView.Ranking} icon={Trophy} label="Ranking" />
            <NavButton target={AppView.Mural} icon={ImageIcon} label="Mural" />
            <NavButton target={AppView.Timer} icon={Clock} label="Temporizador" />
          </nav>
          <button onClick={() => { setUser(null); setView(AppView.Login); }} className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-2 hover:text-red-500 p-4 transition-colors"><LogOut size={16}/> Sair</button>
        </aside>
      )}

      <main className="flex-1 p-6 md:p-12 overflow-y-auto pb-24 md:pb-12">
        {view === AppView.Login && (
          <div className="min-h-[80vh] flex items-center justify-center p-4">
            <div className="bg-slate-900 p-10 md:p-16 rounded-[4rem] border border-slate-800 w-full max-w-lg shadow-2xl relative overflow-hidden text-center">
               <div className="absolute top-0 right-0 w-64 h-64 bg-amber-500/5 rounded-full -translate-y-32 translate-x-32"></div>
               <div className="relative z-10">
                 <div className="w-16 h-16 bg-amber-500 rounded-2xl flex items-center justify-center mb-10 shadow-xl mx-auto"><Medal className="text-slate-950" size={32} /></div>
                 <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2 leading-none">{adminProfile?.dojoName || "TIME BJJ"}</h2>
                 <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-12">OSS! INSIRA SUA CHAVE DE ACESSO</p>

                 <div className="space-y-6">
                    <div className="relative">
                      <Fingerprint className="absolute left-6 top-6 text-slate-600" size={24} />
                      <input 
                        type="password" 
                        placeholder="SENHA / CHAVE DE ACESSO" 
                        value={accessKey} 
                        onChange={e => setAccessKey(e.target.value)} 
                        onKeyDown={e => e.key === 'Enter' && handleLogin()}
                        className="w-full p-6 pl-16 bg-slate-800 border border-slate-700 rounded-[2rem] text-white outline-none focus:ring-2 focus:ring-amber-500 transition-all font-black uppercase tracking-[0.2em] text-[12px]" 
                      />
                    </div>
                    <button onClick={handleLogin} className="w-full bg-white text-slate-950 font-black p-7 rounded-[2rem] hover:bg-amber-500 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-3 group">
                      Entrar no Tatame <ArrowRight size={24} className="group-hover:translate-x-2 transition-transform"/>
                    </button>
                    <p className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Acesso seguro para alunos e professores</p>
                 </div>
               </div>
            </div>
          </div>
        )}

        {view === AppView.AdminRegistration && (
          <div className="min-h-[80vh] flex items-center justify-center p-4">
            <form onSubmit={registerAdmin} className="bg-slate-900 p-10 md:p-16 rounded-[4rem] border border-slate-800 w-full max-w-2xl shadow-2xl space-y-8">
