type AlarmType = 'buzzer' | 'bell' | 'MATE' | 'FIM' | 'TIME';

const App: React.FC = () => {
  // --- PERSISTÊNCIA ---
  const [athletes, setAthletes] = useState<Athlete[]>(() => {
    const saved = localStorage.getItem('bjj_athletes_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('bjj_transactions_v7');
    return saved ? JSON.parse(saved) : [];
  });

  const [classes, setClasses] = useState<TrainingClass[]>(() => {
    const saved = localStorage.getItem('bjj_classes_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'c1', name: 'Iniciantes', schedule: '19:00', days: 'Seg/Qua/Sex', color: 'bg-blue-500' },
      { id: 'c2', name: 'Avançado/Competição', schedule: '20:30', days: 'Todos os dias', color: 'bg-purple-500' }
    ];
  });

  const [mural, setMural] = useState<MuralPhoto[]>(() => {
    const saved = localStorage.getItem('bjj_mural_v7');
    return saved ? JSON.parse(saved) : [
      { id: 'm1', url: 'https://images.unsplash.com/photo-1555597673-b21d5c935865?auto=format&fit=crop&w=800', caption: 'OSS! Bem vindos ao tatame!', date: '2024-05-01', postedBy: 'Sensei' }
    ];
  });

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('bjj_admin_v7');
    return saved ? JSON.parse(saved) : null;
  });

  // Estados de sessão
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [accessKey, setAccessKey] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');

  // Estados de Modal
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo' | 'class'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [onboardingForm, setOnboardingForm] = useState<Partial<Athlete>>({});

  // --- ESTADO DO TEMPORIZADOR ---
  const [timerDuration, setTimerDuration] = useState(300);
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<AlarmType>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [manualSec, setManualSec] = useState(0);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Efeitos de salvamento
  useEffect(() => localStorage.setItem('bjj_athletes_v7', JSON.stringify(athletes)), [athletes]);
  useEffect(() => localStorage.setItem('bjj_transactions_v7', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('bjj_classes_v7', JSON.stringify(classes)), [classes]);
  useEffect(() => localStorage.setItem('bjj_mural_v7', JSON.stringify(mural)), [mural]);
  useEffect(() => { if (adminProfile) localStorage.setItem('bjj_admin_v7', JSON.stringify(adminProfile)); }, [adminProfile]);

  // Insights do Gemini
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, transactions, athletes, user]);

  // Lógica do Temporizador
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      startContinuousAlarm();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    } else {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const startContinuousAlarm = () => {
    stopAlarm();
    setIsAlarmPlaying(true);

    const playRound = () => {
      // Síntese de Voz para alertas personalizados
      if (['MATE', 'FIM', 'TIME'].includes(selectedAlarm)) {
        const text = selectedAlarm === 'MATE' ? 'MATÊ! MATÊ!' : selectedAlarm === 'FIM' ? 'FIM DE TREINO! OSS!' : 'IT IS TIME! FIGHT!';
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = selectedAlarm === 'TIME' ? 'en-US' : 'pt-BR';
        utterance.rate = 1.2;
        window.speechSynthesis.speak(utterance);
        return;
      }

      // Contexto de áudio para Buzzer e Sino
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      audioContextRef.current = ctx;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);

      if (selectedAlarm === 'buzzer') {
        osc.type = 'sawtooth';
        osc.frequency.setValueAtTime(100, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.6, ctx.currentTime + 0.1);
        gain.gain.setValueAtTime(0.6, ctx.currentTime + 0.9);
        gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 1.2);
        osc.start();
        osc.stop(ctx.currentTime + 1.3);
      } else if (selectedAlarm === 'bell') {
        osc.type = 'sine';
        osc.frequency.setValueAtTime(1000, ctx.currentTime);
        gain.gain.setValueAtTime(0, ctx.currentTime);
        gain.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 0.05);
        gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
        osc.start();
        osc.stop(ctx.currentTime + 1.6);
      }
    };

    const intervalTime = selectedAlarm === 'bell' ? 2500 : 1500;
    alarmIntervalRef.current = window.setInterval(playRound, intervalTime);
    playRound(); // Execução imediata
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (alarmIntervalRef.current) {
      clearInterval(alarmIntervalRef.current);
      alarmIntervalRef.current = null;
    }
    if (audioContextRef.current) {
      audioContextRef.current.close();
      audioContextRef.current = null;
    }
    window.speechSynthesis.cancel();
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const updateManualTimer = (m: number, s: number) => {
    const total = (m * 60) + s;
    setTimerDuration(total);
    setTimeLeft(total);
    setIsTimerRunning(false);
    stopAlarm();
  };

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => {
      if (!a.birthDate) return false;
      return new Date(a.birthDate).getMonth() === currentMonth;
    });
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const loggedInAthlete = useMemo(() => 
    user?.athleteId ? athletes.find(a => a.id === user.athleteId) : null
  , [user, athletes]);

  const handleLogin = () => {
    if (!adminProfile?.registered) {
      setView(AppView.AdminRegistration);
      return;
    }
    if (accessKey === adminProfile.password) {
      setUser({ name: adminProfile.name, role: 'admin' });
      setView(AppView.Dashboard);
      setAccessKey('');
      return;
    }
    const ath = athletes.find(a => a.accessId.toUpperCase() === accessKey.toUpperCase());
    if (ath) {
      setUser({ name: ath.name, role: 'student', athleteId: ath.id });
      setAccessKey('');
      if (!ath.profileComplete) {
        setOnboardingForm({...ath, address: ath.address || INITIAL_ADDRESS});
        setView(AppView.ProfileCompletion);
      } else {
        setView(AppView.Dashboard);
      }
      return;
    }
    alert("Chave de acesso inválida! Verifique com seu Sensei.");
  };

  const registerAdmin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const password = formData.get('password') as string;
    const confirm = formData.get('confirm_password') as string;
    if (password !== confirm) return alert("As senhas não coincidem!");
    const newProfile: AdminProfile = {
      name: formData.get('name') as string,
      dojoName: formData.get('dojoName') as string,
      email: formData.get('email') as string,
      phone: formData.get('phone') as string,
      address: formData.get('address') as string,
      password: password,
      registered: true
    };
    setAdminProfile(newProfile); setUser({ name: newProfile.name, role: 'admin' }); setView(AppView.Dashboard);
  };

  const finalizeOnboarding = () => {
    if (!onboardingForm.termsAccepted) return alert("Você deve aceitar os termos para continuar.");
    setAthletes(prev => prev.map(ath => ath.id === onboardingForm.id ? { ...ath, ...onboardingForm, profileComplete: true } as Athlete : ath));
    setView(AppView.Dashboard);
  };

  const NavButton = ({ target, icon: Icon, label }: { target: AppView, icon: any, label: string }) => {
    const allowedForStudent = [AppView.Dashboard, AppView.Ranking, AppView.Mural, AppView.Timer];
    if (user?.role === 'student' && !allowedForStudent.includes(target)) return null;
    return (
      <button onClick={() => setView(target)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === target ? 'bg-amber-500 text-slate-950 shadow-lg scale-105' : 'text-slate-400 hover:bg-slate-800'}`}>
        <Icon size={18} /> <span>{label}</span>
      </button>
    );
  };

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter']">
      {/* Sidebar */}
      {view !== AppView.Login && view !== AppView.AdminRegistration && view !== AppView.ProfileCompletion && (
        <aside className="w-72 bg-slate-900 border-r border-slate-800 p-8 hidden md:flex flex-col gap-6">
          <div className="flex items-center space-x-3 mb-8">
            <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg"><Medal className="text-slate-950" size={24} /></div>
            <span className="text-xl font-black uppercase italic tracking-tighter text-white">TIME BJJ</span>
          </div>
          <nav className="flex-1 space-y-1.5">
            <NavButton target={AppView.Dashboard} icon={Home} label="Início" />
            <NavButton target={AppView.Athletes} icon={Users} label="Alunos" />
            <NavButton target={AppView.Classes} icon={LayoutGrid} label="Turmas" />
            <NavButton target={AppView.Attendance} icon={CalendarCheck} label="Frequência" />
            <NavButton target={AppView.Finance} icon={DollarSign} label="Financeiro" />
            <NavButton target={AppView.Ranking} icon={Trophy} label="Ranking" />
            <NavButton target={AppView.Mural} icon={ImageIcon} label="Mural" />
            <NavButton target={AppView.Timer} icon={Clock} label="Temporizador" />
          </nav>
          <button onClick={() => { setUser(null); setView(AppView.Login); }} className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-2 hover:text-red-500 p-4 transition-colors"><LogOut size={16}/> Sair</button>
        </aside>
      )}

      <main className="flex-1 p-6 md:p-12 overflow-y-auto pb-24 md:pb-12">
        {view === AppView.Login && (
          <div className="min-h-[80vh] flex items-center justify-center p-4">
            <div className="bg-slate-900 p-10 md:p-16 rounded-[4rem] border border-slate-800 w-full max-w-lg shadow-2xl relative overflow-hidden text-center">
               <div className="absolute top-0 right-0 w-64 h-64 bg-amber-500/5 rounded-full -translate-y-32 translate-x-32"></div>
               <div className="relative z-10">
                 <div className="w-16 h-16 bg-amber-500 rounded-2xl flex items-center justify-center mb-10 shadow-xl mx-auto"><Medal className="text-slate-950" size={32} /></div>
                 <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2 leading-none">{adminProfile?.dojoName || "TIME BJJ"}</h2>
                 <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-12">OSS! INSIRA SUA CHAVE DE ACESSO</p>
                 <div className="space-y-6">
                    <div className="relative">
                      <Fingerprint className="absolute left-6 top-6 text-slate-600" size={24} />
                      <input 
                        type="password" 
                        placeholder="SENHA / CHAVE DE ACESSO" 
                        value={accessKey} 
                        onChange={e => setAccessKey(e.target.value)} 
                        onKeyDown={e => e.key === 'Enter' && handleLogin()}
                        className="w-full p-6 pl-16 bg-slate-800 border border-slate-700 rounded-[2rem] text-white outline-none focus:ring-2 focus:ring-amber-500 transition-all font-black uppercase tracking-[0.2em] text-[12px]" 
                      />
                    </div>
                    <button onClick={handleLogin} className="w-full bg-white text-slate-950 font-black p-7 rounded-[2rem] hover:bg-amber-500 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-3 group">
                      Entrar no Tatame <ArrowRight size={24} className="group-hover:translate-x-2 transition-transform"/>
                    </button>
                 </div>
               </div>
            </div>
          </div>
        )}

        {view === AppView.Timer && (
          <div className="space-y-10 animate-in fade-in duration-500 flex flex-col items-center">
             <header className="text-center w-full">
               <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2">Tatame Timer</h2>
               <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest italic">Controle Profissional de Rounds</p>
             </header>

             {isAlarmPlaying && (
               <div className="w-full max-w-2xl bg-red-600 text-white p-6 rounded-[2rem] flex items-center justify-between shadow-2xl animate-pulse ring-4 ring-white/20">
                  <div className="flex items-center gap-4">
                    <AlertTriangle size={32} />
                    <span className="font-black uppercase italic tracking-widest text-[14px]">PAROU! PAROU! ROUND FINALIZADO!</span>
                  </div>
                  <button onClick={stopAlarm} className="bg-white text-red-600 px-6 py-4 rounded-2xl font-black uppercase text-[11px] flex items-center gap-2 hover:scale-105 transition-all shadow-xl">
