                             <p className="text-[10px] font-black text-white uppercase">{classes.find(c => c.id === ath.classId)?.name || 'Sem Turma'}</p>
                           </div>
                        </td>
                        <td className="px-8 py-6"><BeltBadge belt={ath.belt} degrees={ath.degrees} /></td>
                        <td className="px-8 py-6">
                           <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-md ${ath.paymentDay >= new Date().getDate() ? 'bg-emerald-500/10 text-emerald-500' : 'bg-red-500/10 text-red-500 animate-pulse'}`}>
