                        <td className="px-8 py-6 text-right">
                          <button onClick={() => { setForm(ath); setEditId(ath.id); setModalType('athlete'); setIsModalOpen(true); }} className="p-3 text-slate-500 hover:text-white transition-all transform hover:rotate-12"><Edit size={18} /></button>
