           <button onClick={() => setView(AppView.Timer)} className={`p-2 transition-all ${view === AppView.Timer ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Clock size={24}/></button>
           <button onClick={() => setView(AppView.Ranking)} className={`p-2 transition-all ${view === AppView.Ranking ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Trophy size={24}/></button>
           <button onClick={() => setView(AppView.Mural)} className={`p-2 transition-all ${view === AppView.Mural ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><ImageIcon size={24}/></button>
        </nav>
      )}

      {/* MODALS */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[3.5rem] w-full max-w-md p-10 md:p-12 shadow-2xl animate-in zoom-in-95 duration-300 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">
                {editId ? 'Editar' : 'Novo'} {modalType === 'athlete' ? 'Atleta' : modalType === 'class' ? 'Turma' : modalType === 'photo' ? 'Mural' : 'Fluxo'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="bg-slate-800 p-2 rounded-2xl text-slate-500 hover:text-white transition-all"><X size={28} /></button>
            </div>
            {modalType === 'athlete' && (
              <div className="space-y-4">
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Nome do Aluno</label>
                  <input type="text" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500 transition-all" />
                </div>
                <div className="space-y-1">
                  <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Senha de Acesso</label>
                  <input type="text" value={form.accessId || ''} onChange={e => setForm({...form, accessId: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase outline-none focus:ring-2 focus:ring-amber-500 transition-all" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Faixa</label>
                    <select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white uppercase text-[10px] font-black outline-none">
                      {['Branca', 'Cinza', 'Amarela', 'Laranja', 'Verde', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-500 uppercase ml-3 tracking-widest">Dia Vencimento</label>
                    <input type="number" min="1" max="31" value={form.paymentDay || ''} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white outline-none focus:ring-2 focus:ring-amber-500" />
                  </div>
                </div>
              </div>
            )}
            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: false, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-400 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-2">
              <Save size={20} /> Salvar OSS
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

