        if (a.lastAttendance === todayStr) {
          alert("Presença já registrada hoje! OSS!");
          return a;
        }
        return { ...a, attendanceCount: a.attendanceCount + 1, lastAttendance: todayStr };
      }
      return a;
    }));
    alert("Presença confirmada! Bom treino!");
