          </div>
        )}

        {/* MURAL VIEW */}
        {view === AppView.Mural && (
          <div className="space-y-10 animate-in fade-in">
            <header className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Mural do Tatame</h2>
              <button onClick={() => { setForm({}); setModalType('photo'); setIsModalOpen(true); }} className="bg-amber-500 text-slate-950 px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center gap-2 shadow-xl"><Plus size={18} /> Postar Foto</button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {mural.map(photo => (
                <div key={photo.id} className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl group">
                  <div className="h-64 overflow-hidden relative">
                    <img src={photo.url} alt={photo.caption} className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-950/80 to-transparent flex items-end p-6">
                      <p className="text-[11px] font-black uppercase italic tracking-widest text-amber-500">Postado por {photo.postedBy}</p>
                    </div>
                  </div>
                  <div className="p-6">
                    <p className="text-sm font-bold leading-relaxed">{photo.caption}</p>
                    <p className="text-[9px] font-black uppercase text-slate-500 mt-4 tracking-widest">{photo.date}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* TIMER VIEW */}
        {view === AppView.Timer && (
          <div className="space-y-10 animate-in fade-in flex flex-col items-center">
             <header className="text-center w-full">
               <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2 leading-none">Tatame Timer</h2>
               <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest italic tracking-widest">OSS! Controle de Rounds</p>
             </header>

             {isAlarmPlaying && (
               <div className="w-full max-w-2xl bg-red-600 text-white p-6 rounded-[2rem] flex items-center justify-between shadow-2xl animate-pulse ring-4 ring-white/20">
                  <div className="flex items-center gap-4">
                    <AlertTriangle size={32} />
                    <span className="font-black uppercase italic tracking-widest text-[14px]">TEMPO ESGOTADO - ROUND FINALIZADO!</span>
                  </div>
                  <button onClick={stopAlarm} className="bg-white text-red-600 px-6 py-4 rounded-2xl font-black uppercase text-[11px] flex items-center gap-2 shadow-xl hover:scale-105 transition-all">
                    <VolumeX size={18} /> PARAR
                  </button>
               </div>
             )}

             <div className="w-full max-w-2xl bg-slate-900 rounded-[4rem] border border-slate-800 p-12 shadow-2xl flex flex-col items-center gap-10 relative overflow-hidden">
                {isTimerRunning && <div className="absolute top-0 left-0 h-1 bg-amber-500 animate-pulse w-full"></div>}
                <div className={`text-[140px] font-black text-white leading-none tracking-tighter tabular-nums mb-4 drop-shadow-[0_0_30px_rgba(251,191,36,0.2)] ${timeLeft === 0 ? 'text-red-500 animate-bounce' : ''}`}>
                  {formatTime(timeLeft)}
                </div>

                <div className="bg-slate-950 p-8 rounded-[3rem] border border-slate-800 w-full shadow-inner flex flex-col items-center gap-6">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2"><Settings2 size={14}/> Ajuste Manual</p>
                  <div className="flex items-center gap-6">
                    <div className="flex flex-col items-center">
                      <label className="text-[8px] font-black text-slate-600 uppercase mb-2">Minutos</label>
                      <input type="number" min="0" max="99" value={manualMin} onChange={(e) => { const v = parseInt(e.target.value) || 0; setManualMin(v); updateManualTimer(v, manualSec); }} className="w-24 p-5 bg-slate-900 border border-slate-700 rounded-2xl text-white font-black text-3xl text-center outline-none focus:ring-2 focus:ring-amber-500 transition-all shadow-xl" />
                    </div>
                    <span className="text-white font-black text-4xl mt-8">:</span>
                    <div className="flex flex-col items-center">
                      <label className="text-[8px] font-black text-slate-600 uppercase mb-2">Segundos</label>
                      <input type="number" min="0" max="59" value={manualSec} onChange={(e) => { const v = parseInt(e.target.value) || 0; setManualSec(v); updateManualTimer(manualMin, v); }} className="w-24 p-5 bg-slate-900 border border-slate-700 rounded-2xl text-white font-black text-3xl text-center outline-none focus:ring-2 focus:ring-amber-500 transition-all shadow-xl" />
                    </div>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full">
                   <div className="space-y-4">
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center italic font-black"><Volume2 size={14}/> Seleção de Som</p>
                      <div className="grid grid-cols-2 gap-2 bg-slate-950 p-3 rounded-[2.5rem] border border-slate-800">
                         {(['buzzer', 'bell', 'MATE', 'FIM', 'TIME'] as AlarmType[]).map(s => (
                           <button key={s} onClick={() => { setSelectedAlarm(s); stopAlarm(); }} className={`py-3 px-2 rounded-xl font-black text-[9px] uppercase transition-all ${selectedAlarm === s ? 'bg-amber-500 text-slate-950 shadow-lg scale-105' : 'text-slate-600 hover:text-slate-400'}`}>
                             {s === 'buzzer' ? 'Buzzer' : s === 'bell' ? 'Sino' : s}
                           </button>
                         ))}
                      </div>
                   </div>
                   <div className="flex items-center justify-center gap-4">
                      <button onClick={() => { setIsTimerRunning(!isTimerRunning); stopAlarm(); }} className={`w-28 h-28 rounded-[3rem] flex items-center justify-center shadow-2xl transition-all hover:scale-105 ${isTimerRunning ? 'bg-red-500 text-white' : 'bg-emerald-500 text-white ring-4 ring-emerald-500/20'}`}>
                        {isTimerRunning ? <Pause size={48} /> : <Play size={48} className="ml-1" />}
                      </button>
                      <button onClick={() => { setIsTimerRunning(false); setTimeLeft(timerDuration); stopAlarm(); }} className="w-24 h-24 bg-slate-800 rounded-[3rem] flex items-center justify-center text-slate-400 hover:text-white transition-all shadow-xl border border-slate-700">
                        <RotateCcw size={40} />
                      </button>
                   </div>
                </div>
             </div>
          </div>
        )}

        {/* ATTENDANCE VIEW */}
        {view === AppView.Attendance && user?.role === 'admin' && (
          <div className="space-y-10 animate-in fade-in">
             <header className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Lista de Presença</h2>
              <div className="flex items-center gap-4 bg-slate-900 p-2 rounded-2xl border border-slate-800">
                 <Filter size={18} className="text-slate-500 ml-2" />
                 <select value={selectedClassFilter} onChange={e => setSelectedClassFilter(e.target.value)} className="bg-transparent text-[10px] font-black uppercase text-white outline-none">
                    <option value="all">Todas as Turmas</option>
                    {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                 </select>
              </div>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredAthletes.map(ath => (
                <div key={ath.id} className="bg-slate-900 p-8 rounded-[3rem] border border-slate-800 flex flex-col items-center shadow-2xl transition-all hover:scale-[1.02]">
                   <div className="w-20 h-20 bg-slate-800 rounded-[2rem] flex items-center justify-center font-black text-amber-500 text-3xl italic mb-4">OSS</div>
                   <h4 className="font-black text-white uppercase italic text-center mb-1">{ath.name}</h4>
                   <BeltBadge belt={ath.belt} degrees={ath.degrees} />
                   <div className="mt-8 w-full">
                      <button onClick={() => markAttendance(ath.id)} className={`w-full py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest flex items-center justify-center gap-2 transition-all ${ath.lastAttendance === new Date().toISOString().split('T')[0] ? 'bg-emerald-500 text-white' : 'bg-slate-800 text-slate-400 hover:bg-slate-700 hover:text-white'}`}>
                        {ath.lastAttendance === new Date().toISOString().split('T')[0] ? <><CheckCircle2 size={16}/> PRESENTE</> : <><Calendar size={16}/> MARCAR PRESENÇA</>}
                      </button>
                   </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* CLASSES VIEW */}
        {view === AppView.Classes && user?.role === 'admin' && (
          <div className="space-y-10 animate-in fade-in">
            <header className="flex justify-between items-center">
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Gestão de Turmas</h2>
              <button onClick={() => { setForm({ color: 'bg-blue-500' }); setEditId(null); setModalType('class'); setIsModalOpen(true); }} className="bg-amber-500 text-slate-950 px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center gap-2 shadow-xl"><Plus size={18} /> Nova Turma</button>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {classes.map(c => (
                <div key={c.id} className="bg-slate-900 rounded-[2.5rem] border border-slate-800 p-8 shadow-2xl relative overflow-hidden group">
                  <div className={`absolute top-0 right-0 w-2 h-full ${c.color}`}></div>
                  <div className="flex justify-between items-start mb-6">
                    <div className={`${c.color} p-3 rounded-2xl shadow-lg`}><LayoutGrid className="text-white" size={24} /></div>
                    <div className="flex gap-2">
                       <button onClick={() => { setForm(c); setEditId(c.id); setModalType('class'); setIsModalOpen(true); }} className="p-2 text-slate-600 hover:text-white transition-all"><Edit size={18} /></button>
                       <button onClick={() => setClasses(prev => prev.filter(item => item.id !== c.id))} className="p-2 text-slate-600 hover:text-red-500 transition-all"><Trash2 size={18} /></button>
                    </div>
                  </div>
                  <h4 className="text-xl font-black text-white uppercase italic mb-2 leading-tight">{c.name}</h4>
                  <div className="space-y-3">
                    <div className="flex items-center gap-2 text-slate-500"><Clock size={14} /><span className="text-[10px] font-black uppercase">{c.schedule}</span></div>
                    <div className="flex items-center gap-2 text-slate-500"><CalendarCheck size={14} /><span className="text-[10px] font-black uppercase">{c.days}</span></div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

      </main>

      {/* BOTTOM NAV FOR MOBILE */}
      {user && view !== AppView.Login && (
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-slate-900/95 backdrop-blur-xl border-t border-slate-800 flex justify-around p-4 z-[100]">
           <button onClick={() => setView(AppView.Dashboard)} className={`p-2 transition-all ${view === AppView.Dashboard ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Home size={24}/></button>
           <button onClick={() => setView(AppView.Timer)} className={`p-2 transition-all ${view === AppView.Timer ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Clock size={24}/></button>
           <button onClick={() => setView(AppView.Ranking)} className={`p-2 transition-all ${view === AppView.Ranking ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><Trophy size={24}/></button>
           <button onClick={() => setView(AppView.Mural)} className={`p-2 transition-all ${view === AppView.Mural ? 'text-amber-500 scale-110' : 'text-slate-600'}`}><ImageIcon size={24}/></button>
        </nav>
      )}

      {/* MODALS */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/90 backdrop-blur-xl z-[200] flex items-center justify-center p-4">
          <div className="bg-slate-900 border border-slate-800 rounded-[3.5rem] w-full max-w-md p-10 md:p-12 shadow-2xl animate-in zoom-in-95 overflow-y-auto max-h-[90vh]">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">
                {editId ? 'Editar' : 'Novo'} {modalType === 'athlete' ? 'Atleta' : modalType === 'class' ? 'Turma' : modalType === 'photo' ? 'Mural' : 'Fluxo'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="bg-slate-800 p-2 rounded-2xl text-slate-500 hover:text-white transition-all"><X size={28} /></button>
            </div>

            <div className="space-y-4">
              {modalType === 'athlete' && (
                <>
                  <input type="text" placeholder="Nome Completo" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  <input type="text" placeholder="Senha/Chave de Acesso" value={form.accessId || ''} onChange={e => setForm({...form, accessId: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  <div className="grid grid-cols-2 gap-4">
                    <select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none">
                      {['Branca', 'Cinza', 'Amarela', 'Laranja', 'Verde', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)}
                    </select>
                    <input type="number" placeholder="Dia Vencimento" value={form.paymentDay || ''} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  </div>
                  <select value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none">
                    <option value="">Escolha uma Turma</option>
                    {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </>
              )}

              {modalType === 'transaction' && (
                <>
                  <input type="text" placeholder="Descrição" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  <input type="number" placeholder="Valor (R$)" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  <input type="date" value={form.date || ''} onChange={e => setForm({...form, date: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                </>
              )}

              {modalType === 'photo' && (
                <>
                  <div className="bg-slate-800 border-2 border-dashed border-slate-700 rounded-[2rem] p-10 text-center relative hover:border-amber-500/50 transition-all">
                    {form.url ? <img src={form.url} className="w-full h-32 object-cover rounded-xl" /> : <div className="flex flex-col items-center"><Camera className="text-slate-600 mb-2" size={32}/><p className="text-[9px] font-black uppercase text-slate-500">Escolha uma Foto</p></div>}
                    <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer" />
                  </div>
                  <input type="text" placeholder="Legenda da Foto" value={form.caption || ''} onChange={e => setForm({...form, caption: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                </>
              )}

              {modalType === 'class' && (
                <>
                  <input type="text" placeholder="Nome da Turma" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  <input type="text" placeholder="Horário (Ex: 19:00)" value={form.schedule || ''} onChange={e => setForm({...form, schedule: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  <input type="text" placeholder="Dias (Ex: Seg/Qua/Sex)" value={form.days || ''} onChange={e => setForm({...form, days: e.target.value})} className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
                  <div className="flex gap-2 justify-center py-2">
                    {CLASS_COLORS.map(c => <button key={c} onClick={() => setForm({...form, color: c})} className={`w-8 h-8 rounded-full ${c} ${form.color === c ? 'ring-4 ring-white' : ''}`} />)}
                  </div>
                </>
              )}
            </div>

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: true, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString() }]);
              } else if (modalType === 'photo') {
                if (!form.url) return alert("Adicione uma foto!");
                setMural(prev => [{ ...form, id: Date.now().toString(), date: new Date().toLocaleDateString(), postedBy: user?.name || 'Mestre' }, ...prev]);
              } else if (modalType === 'class') {
                if (editId) setClasses(prev => prev.map(c => c.id === editId ? { ...c, ...form } : c));
                else setClasses(prev => [...prev, { ...form, id: Date.now().toString() }]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-400 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-2">
              <Save size={20} /> Salvar OSS
            </button>
          </div>
        </div>
      )}

      {/* ADMIN REGISTRATION VIEW */}
      {view === AppView.AdminRegistration && (
        <div className="min-h-screen flex items-center justify-center p-4">
          <form onSubmit={(e) => {
            e.preventDefault();
            const f = new FormData(e.currentTarget);
            const p = f.get('password') as string;
            const newAdmin: AdminProfile = {
              name: f.get('name') as string,
              dojoName: f.get('dojoName') as string,
              email: f.get('email') as string,
              phone: f.get('phone') as string,
              address: f.get('address') as string,
              password: p,
              registered: true
            };
            setAdminProfile(newAdmin); setUser({ name: newAdmin.name, role: 'admin' }); setView(AppView.Dashboard);
          }} className="bg-slate-900 p-10 md:p-16 rounded-[4rem] border border-slate-800 w-full max-w-2xl shadow-2xl space-y-8">
            <div className="text-center">
              <ShieldCheck className="mx-auto text-amber-500 mb-4" size={48} />
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Configurar Sensei</h2>
              <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2 tracking-widest">OSS! Configure sua academia</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input required name="name" placeholder="Nome do Professor" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
              <input required name="dojoName" placeholder="Nome da Academia" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
              <input required name="email" type="email" placeholder="E-mail" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none md:col-span-2" />
              <input required name="password" type="password" placeholder="Definir Senha do Professor" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black text-[10px] outline-none md:col-span-2" />
            </div>
            <button type="submit" className="w-full bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-white transition-all uppercase tracking-widest italic text-sm shadow-2xl">Finalizar Cadastro OSS</button>
          </form>
        </div>
      )}
    </div>
  );
};

export default App;

export type UserRole = 'admin' | 'professor' | 'student';
export type AgeCategory = 'Infantil' | 'Adulto';

export type AdultBelt = 'Branca' | 'Azul' | 'Roxa' | 'Marrom' | 'Preta';
export type KidsBelt = 'Branca' | 'Cinza' | 'Amarela' | 'Laranja' | 'Verde';
export type Belt = AdultBelt | KidsBelt;

export interface Address {
  street: string;
  number: string;
  neighborhood: string;
  city: string;
  cep: string;
}

export interface AdminProfile {
  name: string;
  dojoName: string;
  email: string;
  password: string;
  phone: string;
  address: string;
  registered: boolean;
}

export interface TrainingClass {
  id: string;
  name: string;
  schedule: string;
  days: string;
  color: string;
}

export interface Athlete {
  id: string;
  accessId: string;
  name: string;
  email: string;
  cpf: string;
  birthDate: string;
  joinDate: string;
  paymentDay: number;
  status: 'active' | 'inactive';
  attendanceCount: number;
  lastAttendance?: string;
  belt: Belt;
  degrees: number;
  category: AgeCategory;
  classId?: string; 
  phone: string;
  emergencyContact: string;
  emergencyPhone: string;
  bloodType: string;
  medicalNotes: string;
  allergies: string;
  medications: string;
  address: Address;
  termsAccepted: boolean;
  profileComplete: boolean;
}

export interface Transaction {
  id: string;
  type: 'income' | 'expense';
  amount: number;
  date: string;
  description: string;
  category: string;
  athleteId?: string;
  status: 'pending' | 'verified';
}

export interface MuralPhoto {
  id: string;
  url: string;
  caption: string;
  date: string;
  postedBy: string;
}

export enum AppView {
  Login = 'login',
  Dashboard = 'dashboard', 
  Athletes = 'athletes',
  Classes = 'classes',
  Attendance = 'attendance',
  Finance = 'finance',
  Ranking = 'ranking',
  Mural = 'mural',
  Timer = 'timer',
  ProfileCompletion = 'profile-completion',
  AdminRegistration = 'admin-registration',
  Settings = 'settings'
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  User as UserIcon, Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, HeartPulse, AlertTriangle, Save, CreditCard, Key, ArrowRight, 
  ClipboardCheck, Cake, Lock, ShieldCheck, Mail, MapPin, Phone, Briefcase,
  TrendingDown, TrendingUp, Camera, Image as ImageIcon, Info, Upload, ChevronRight,
  Clock, Filter, LayoutGrid, Trash2, Play, Pause, RotateCcw, Volume2, Bell, Settings2,
  VolumeX, Fingerprint, Calendar, Database, Download, FileJson, ShieldAlert
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address, MuralPhoto, AgeCategory, TrainingClass } from './types';
import { getDojoInsights } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78350f',
  'Preta': '#0f172a'
};

const CLASS_COLORS = [
  'bg-blue-500', 
  'bg-purple-500', 
  'bg-emerald-500', 
  'bg-red-500', 
  'bg-amber-500', 
  'bg-indigo-500', 
  'bg-pink-500', 
  'bg-slate-700'
];

const BeltBadge: React.FC<{ belt: Belt; degrees: number }> = ({ belt, degrees }) => {
