type AlarmType = 'buzzer' | 'bell' | 'MATE' | 'FIM' | 'TIME';

const App: React.FC = () => {
  // --- PERSISTÊNCIA ---
  const [athletes, setAthletes] = useState<Athlete[]>(() => {
    const saved = localStorage.getItem('timebjj_athletes');
    return saved ? JSON.parse(saved) : [];
  });

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('timebjj_transactions');
    return saved ? JSON.parse(saved) : [];
  });

  const [classes, setClasses] = useState<TrainingClass[]>(() => {
    const saved = localStorage.getItem('timebjj_classes');
    return saved ? JSON.parse(saved) : [
      { id: 'c1', name: 'Iniciantes', schedule: '19:00', days: 'Seg/Qua/Sex', color: 'bg-blue-500' },
      { id: 'c2', name: 'Avançado/Competição', schedule: '20:30', days: 'Todos os dias', color: 'bg-purple-500' }
    ];
  });

  const [mural, setMural] = useState<MuralPhoto[]>(() => {
    const saved = localStorage.getItem('timebjj_mural');
    return saved ? JSON.parse(saved) : [];
  });

  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => {
    const saved = localStorage.getItem('timebjj_admin');
    return saved ? JSON.parse(saved) : null;
  });

  // --- ESTADOS DE UI ---
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [accessKey, setAccessKey] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'photo' | 'class'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');

  // --- TEMPORIZADOR ---
  const [timerDuration, setTimerDuration] = useState(300);
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<AlarmType>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [manualSec, setManualSec] = useState(0);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  const updateManualTimer = (m: number, s: number) => {
    const total = (m * 60) + s;
    setTimerDuration(total);
    setTimeLeft(total);
  };

  // Efeitos de Persistência
  useEffect(() => localStorage.setItem('timebjj_athletes', JSON.stringify(athletes)), [athletes]);
  useEffect(() => localStorage.setItem('timebjj_transactions', JSON.stringify(transactions)), [transactions]);
  useEffect(() => localStorage.setItem('timebjj_classes', JSON.stringify(classes)), [classes]);
  useEffect(() => localStorage.setItem('timebjj_mural', JSON.stringify(mural)), [mural]);
  useEffect(() => { if (adminProfile) localStorage.setItem('timebjj_admin', JSON.stringify(adminProfile)); }, [adminProfile]);

  // IA Insights
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, transactions, athletes, user]);

  // Lógica do Temporizador
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      startContinuousAlarm();
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
    } else if (timerIntervalRef.current) {
      clearInterval(timerIntervalRef.current);
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  // --- BACKUP & RESTORE LOGIC ---
  const exportDatabase = () => {
    const fullData = {
      athletes,
      transactions,
      classes,
      mural,
      adminProfile,
      exportDate: new Date().toISOString(),
      appName: "Sistema BJJ - Backup"
    };

    const blob = new Blob([JSON.stringify(fullData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `backup_timebjj_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    alert("Backup exportado com sucesso! Guarde este arquivo em um local seguro.");
  };

  const importDatabase = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (!confirm("Isso irá substituir todos os dados atuais pelos dados do arquivo. Deseja continuar?")) {
      e.target.value = '';
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);

        // Validação simples
        if (!json.athletes || !json.classes) {
          throw new Error("Formato de arquivo inválido.");
        }

        setAthletes(json.athletes);
        setTransactions(json.transactions || []);
        setClasses(json.classes);
        setMural(json.mural || []);
        setAdminProfile(json.adminProfile || null);

        alert("Dados restaurados com sucesso! OSS!");
        setView(AppView.Dashboard);
      } catch (error) {
        alert("Erro ao importar arquivo: formato incompatível.");
      }
    };
    reader.readAsText(file);
  };

  const startContinuousAlarm = () => {
    stopAlarm();
    setIsAlarmPlaying(true);
    const playRound = () => {
      if (['MATE', 'FIM', 'TIME'].includes(selectedAlarm)) {
        const text = selectedAlarm === 'MATE' ? 'MATÊ! MATÊ!' : selectedAlarm === 'FIM' ? 'FIM DE TREINO! OSS!' : 'IT IS TIME! FIGHT!';
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.lang = selectedAlarm === 'TIME' ? 'en-US' : 'pt-BR';
        utterance.rate = 1.1;
        window.speechSynthesis.speak(utterance);
      } else {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioContextRef.current = ctx;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain);
        gain.connect(ctx.destination);
        if (selectedAlarm === 'buzzer') {
          osc.type = 'sawtooth';
          osc.frequency.setValueAtTime(100, ctx.currentTime);
          gain.gain.setValueAtTime(0, ctx.currentTime);
          gain.gain.linearRampToValueAtTime(0.6, ctx.currentTime + 0.1);
          gain.gain.setValueAtTime(0.6, ctx.currentTime + 0.9);
          gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 1.2);
          osc.start();
          osc.stop(ctx.currentTime + 1.3);
        } else if (selectedAlarm === 'bell') {
          osc.type = 'sine';
          osc.frequency.setValueAtTime(1000, ctx.currentTime);
          gain.gain.setValueAtTime(0, ctx.currentTime);
          gain.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 0.05);
          gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.5);
          osc.start();
          osc.stop(ctx.currentTime + 1.6);
        }
      }
    };
    alarmIntervalRef.current = window.setInterval(playRound, 2000);
    playRound();
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (alarmIntervalRef.current) clearInterval(alarmIntervalRef.current);
    if (audioContextRef.current) audioContextRef.current.close();
    window.speechSynthesis.cancel();
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && (a.paymentDay - today <= 3 && a.paymentDay >= today));
    const birthdays = athletes.filter(a => a.birthDate && new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminentPayments, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const handleLogin = () => {
    if (!adminProfile?.registered) { setView(AppView.AdminRegistration); return; }
    if (accessKey === adminProfile.password) { setUser({ name: adminProfile.name, role: 'admin' }); setView(AppView.Dashboard); setAccessKey(''); return; }
    const ath = athletes.find(a => a.accessId.toUpperCase() === accessKey.toUpperCase());
    if (ath) { setUser({ name: ath.name, role: 'student', athleteId: ath.id }); setAccessKey(''); setView(ath.profileComplete ? AppView.Dashboard : AppView.ProfileCompletion); return; }
    alert("Chave de acesso inválida!");
  };

  const markAttendance = (athleteId: string) => {
    const todayStr = new Date().toISOString().split('T')[0];
    setAthletes(prev => prev.map(a => {
      if (a.id === athleteId) {
        if (a.lastAttendance === todayStr) {
          alert("Presença já registrada hoje! OSS!");
          return a;
        }
        return { ...a, attendanceCount: a.attendanceCount + 1, lastAttendance: todayStr };
      }
      return a;
    }));
    alert("Presença confirmada! Bom treino!");
  };

  const filteredAthletes = useMemo(() => {
    if (selectedClassFilter === 'all') return athletes;
    return athletes.filter(a => a.classId === selectedClassFilter);
  }, [athletes, selectedClassFilter]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setForm((prev: any) => ({ ...prev, url: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter']">
      {/* Sidebar - Only visible when logged in */}
      {user && view !== AppView.Login && (
        <aside className="w-72 bg-slate-900 border-r border-slate-800 p-8 hidden md:flex flex-col gap-6 sticky top-0 h-screen">
          <div className="flex items-center space-x-3 mb-8">
            <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg"><Medal className="text-slate-950" size={24} /></div>
            <span className="text-xl font-black uppercase italic tracking-tighter text-white">TIME BJJ</span>
          </div>
          <nav className="flex-1 space-y-1">
            <button onClick={() => setView(AppView.Dashboard)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Dashboard ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}><Home size={18} /><span>Dashboard</span></button>
            {user.role === 'admin' && (
              <>
                <button onClick={() => setView(AppView.Athletes)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Athletes ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Users size={18} /><span>Alunos</span></button>
                <button onClick={() => setView(AppView.Classes)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Classes ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><LayoutGrid size={18} /><span>Turmas</span></button>
                <button onClick={() => setView(AppView.Attendance)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Attendance ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><CalendarCheck size={18} /><span>Presença</span></button>
                <button onClick={() => setView(AppView.Finance)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Finance ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><DollarSign size={18} /><span>Financeiro</span></button>
                <button onClick={() => setView(AppView.Settings)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Settings ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Database size={18} /><span>Sistema</span></button>
              </>
            )}
            <button onClick={() => setView(AppView.Ranking)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Ranking ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Trophy size={18} /><span>Ranking</span></button>
            <button onClick={() => setView(AppView.Mural)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Mural ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><ImageIcon size={18} /><span>Mural</span></button>
            <button onClick={() => setView(AppView.Timer)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Timer ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Clock size={18} /><span>Temporizador</span></button>
          </nav>
          <button onClick={() => { setUser(null); setView(AppView.Login); }} className="text-[10px] font-black uppercase text-slate-500 flex items-center gap-2 hover:text-red-500 p-4 transition-colors mt-auto"><LogOut size={16}/> Sair</button>
        </aside>
      )}

      <main className="flex-1 p-6 md:p-12 overflow-y-auto pb-24 md:pb-12">
        {/* LOGIN VIEW */}
        {view === AppView.Login && (
          <div className="min-h-[80vh] flex items-center justify-center p-4">
            <div className="bg-slate-900 p-10 md:p-16 rounded-[4rem] border border-slate-800 w-full max-w-lg shadow-2xl relative overflow-hidden text-center">
               <div className="absolute top-0 right-0 w-64 h-64 bg-amber-500/5 rounded-full -translate-y-32 translate-x-32"></div>
               <div className="relative z-10">
                 <div className="w-16 h-16 bg-amber-500 rounded-2xl flex items-center justify-center mb-10 shadow-xl mx-auto font-black text-slate-950 text-3xl italic">OSS</div>
                 <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter mb-2 leading-none">{adminProfile?.dojoName || "TIME BJJ"}</h2>
                 <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mb-12">OSS! INSIRA SUA CHAVE DE ACESSO</p>
                 <div className="space-y-6 text-left">
                    <div className="relative">
                      <Fingerprint className="absolute left-6 top-6 text-slate-600" size={24} />
                      <input 
                        type="password" 
                        placeholder="CHAVE DE ACESSO" 
                        value={accessKey} 
                        onChange={e => setAccessKey(e.target.value)} 
                        onKeyDown={e => e.key === 'Enter' && handleLogin()}
                        className="w-full p-6 pl-16 bg-slate-800 border border-slate-700 rounded-[2rem] text-white outline-none focus:ring-2 focus:ring-amber-500 transition-all font-black uppercase tracking-[0.2em] text-[12px]" 
                      />
                    </div>
                    <button onClick={handleLogin} className="w-full bg-white text-slate-950 font-black p-7 rounded-[2rem] hover:bg-amber-500 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-3 group">
                      Entrar no Tatame <ArrowRight size={24} className="group-hover:translate-x-2 transition-transform"/>
                    </button>
                 </div>
               </div>
            </div>
          </div>
        )}

        {/* SETTINGS / BACKUP VIEW */}
        {view === AppView.Settings && user?.role === 'admin' && (
          <div className="space-y-10 animate-in fade-in">
             <header>
               <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Gestão do Sistema</h2>
               <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-1">Backup e Restauração de Dados</p>
             </header>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 shadow-2xl space-y-6">
                   <div className="w-14 h-14 bg-amber-500 rounded-2xl flex items-center justify-center shadow-lg"><Download className="text-slate-950" size={28} /></div>
                   <div>
                     <h4 className="text-xl font-black text-white uppercase italic mb-2">Exportar Dados</h4>
                     <p className="text-slate-500 text-xs leading-relaxed font-medium">Baixe um arquivo contendo todas as informações de alunos, financeiro, turmas e mural. Recomenda-se fazer backup semanalmente.</p>
                   </div>
                   <button onClick={exportDatabase} className="w-full bg-amber-500 text-slate-950 font-black py-5 rounded-2xl hover:bg-white transition-all uppercase text-[11px] tracking-widest flex items-center justify-center gap-2">
                     <FileJson size={18}/> Gerar Backup (.json)
                   </button>
                </div>

                <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 shadow-2xl space-y-6">
                   <div className="w-14 h-14 bg-indigo-500 rounded-2xl flex items-center justify-center shadow-lg"><Upload className="text-white" size={28} /></div>
                   <div>
                     <h4 className="text-xl font-black text-white uppercase italic mb-2">Restaurar Dados</h4>
                     <p className="text-slate-500 text-xs leading-relaxed font-medium">Importe um arquivo de backup para restaurar as informações em caso de reinstalação ou troca de dispositivo.</p>
                   </div>
                   <div className="relative">
                      <input 
                        type="file" 
                        accept=".json" 
                        onChange={importDatabase}
                        className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" 
                      />
                      <button className="w-full bg-slate-800 text-white font-black py-5 rounded-2xl border border-slate-700 hover:bg-slate-700 transition-all uppercase text-[11px] tracking-widest flex items-center justify-center gap-2">
                        <Upload size={18}/> Selecionar Arquivo
                      </button>
                   </div>
                </div>

                <div className="md:col-span-2 bg-red-500/10 border border-red-500/30 p-8 rounded-[2.5rem] flex items-start gap-4">
                   <ShieldAlert className="text-red-500 shrink-0" size={24} />
                   <div>
                     <p className="text-red-500 font-black uppercase italic text-[10px] mb-1">Aviso de Segurança</p>
                     <p className="text-slate-400 text-[11px] font-medium leading-relaxed">Este sistema armazena dados localmente no navegador. Se você limpar o cache, desinstalar o app ou formatar o dispositivo, os dados serão perdidos. **Sempre utilize a exportação para manter uma cópia externa.**</p>
                   </div>
                </div>
             </div>
          </div>
        )}

        {/* DASHBOARD VIEW */}
        {view === AppView.Dashboard && user && (
          <div className="space-y-10 animate-in fade-in duration-500">
             <header className="flex justify-between items-center">
              <div>
                <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">OSS, {user.name}</h2>
                <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2">{user.role === 'admin' ? adminProfile?.dojoName : 'Área do Aluno'}</p>
              </div>
            </header>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {user.role === 'student' ? (
                  <>
                    <div className={`p-10 rounded-[3rem] border flex items-center gap-6 relative overflow-hidden shadow-2xl transition-all ${athletes.find(a => a.id === user.athleteId)?.paymentDay >= new Date().getDate() ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-red-500/10 border-red-500/30 shadow-red-500/5 animate-pulse'}`}>
                      <div className={`p-5 rounded-3xl ${athletes.find(a => a.id === user.athleteId)?.paymentDay >= new Date().getDate() ? 'bg-emerald-500' : 'bg-red-500'} shadow-xl`}><CreditCard className="text-white" size={28} /></div>
                      <div>
                        <h4 className="text-xl font-black text-white uppercase italic">Financeiro</h4>
                        <p className={`text-[11px] font-black uppercase ${athletes.find(a => a.id === user.athleteId)?.paymentDay >= new Date().getDate() ? 'text-emerald-500' : 'text-red-500'}`}>
                          Vencimento: Dia {athletes.find(a => a.id === user.athleteId)?.paymentDay}
                        </p>
                      </div>
                    </div>
                    <div className="bg-slate-900 p-10 rounded-[3rem] border border-slate-800 flex items-center gap-8 shadow-2xl">
                      <div className="w-24 h-24 bg-slate-800 rounded-3xl flex items-center justify-center border-2 border-amber-500/20 font-black text-amber-500 text-4xl italic">OSS</div>
                      <div>
                        <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">{user.name}</h3>
                        <BeltBadge belt={athletes.find(a => a.id === user.athleteId)?.belt || 'Branca'} degrees={athletes.find(a => a.id === user.athleteId)?.degrees || 0} />
                      </div>
                    </div>
                  </>
