              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString() }]);
              } else if (modalType === 'photo') {
                if (!form.url) return alert("Adicione uma foto!");
                setMural(prev => [{ ...form, id: Date.now().toString(), date: new Date().toLocaleDateString(), postedBy: user?.name || 'Mestre' }, ...prev]);
              } else if (modalType === 'class') {
                if (editId) setClasses(prev => prev.map(c => c.id === editId ? { ...c, ...form } : c));
                else setClasses(prev => [...prev, { ...form, id: Date.now().toString() }]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-10 bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-amber-400 transition-all uppercase tracking-widest italic text-sm shadow-2xl flex items-center justify-center gap-2">
              <Save size={20} /> Salvar OSS
            </button>
          </div>
        </div>
      )}

      {/* ADMIN REGISTRATION VIEW */}
      {view === AppView.AdminRegistration && (
        <div className="min-h-screen flex items-center justify-center p-4">
          <form onSubmit={(e) => {
            e.preventDefault();
            const f = new FormData(e.currentTarget);
            const p = f.get('password') as string;
            const newAdmin: AdminProfile = {
              name: f.get('name') as string,
              dojoName: f.get('dojoName') as string,
              email: f.get('email') as string,
              phone: f.get('phone') as string,
              address: f.get('address') as string,
              password: p,
              registered: true
            };
            setAdminProfile(newAdmin); setUser({ name: newAdmin.name, role: 'admin' }); setView(AppView.Dashboard);
          }} className="bg-slate-900 p-10 md:p-16 rounded-[4rem] border border-slate-800 w-full max-w-2xl shadow-2xl space-y-8">
            <div className="text-center">
              <ShieldCheck className="mx-auto text-amber-500 mb-4" size={48} />
              <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Configurar Sensei</h2>
              <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2 tracking-widest">OSS! Configure sua academia</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input required name="name" placeholder="Nome do Professor" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
              <input required name="dojoName" placeholder="Nome da Academia" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none" />
              <input required name="email" type="email" placeholder="E-mail" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black uppercase text-[10px] outline-none md:col-span-2" />
              <input required name="password" type="password" placeholder="Definir Senha do Professor" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-[1.5rem] text-white font-black text-[10px] outline-none md:col-span-2" />
            </div>
            <button type="submit" className="w-full bg-amber-500 text-slate-950 font-black p-6 rounded-[1.5rem] hover:bg-white transition-all uppercase tracking-widest italic text-sm shadow-2xl">Finalizar Cadastro OSS</button>
          </form>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
