          <nav className="flex-1 space-y-1">
            <button onClick={() => navigateTo(AppView.Dashboard)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Dashboard ? 'bg-amber-500 text-slate-950 shadow-lg' : 'text-slate-400 hover:bg-slate-800'}`}><Home size={18} /><span>Dashboard</span></button>
            {user.role === 'admin' && (
              <>
                <button onClick={() => navigateTo(AppView.Athletes)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Athletes ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Users size={18} /><span>Alunos</span></button>
                <button onClick={() => navigateTo(AppView.Classes)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Classes ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><LayoutGrid size={18} /><span>Turmas</span></button>
                <button onClick={() => navigateTo(AppView.Attendance)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Attendance ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><CalendarCheck size={18} /><span>Presença</span></button>
                <button onClick={() => navigateTo(AppView.Finance)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Finance ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><DollarSign size={18} /><span>Financeiro</span></button>
                <button onClick={() => navigateTo(AppView.Settings)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Settings ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Database size={18} /><span>Sistema</span></button>
              </>
            )}
            <button onClick={() => navigateTo(AppView.Ranking)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Ranking ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Trophy size={18} /><span>Ranking</span></button>
            <button onClick={() => navigateTo(AppView.Mural)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Mural ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><ImageIcon size={18} /><span>Mural</span></button>
            <button onClick={() => navigateTo(AppView.Timer)} className={`w-full flex items-center space-x-3 p-3 lg:p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === AppView.Timer ? 'bg-amber-500 text-slate-950' : 'text-slate-400 hover:bg-slate-800'}`}><Clock size={18} /><span>Temporizador</span></button>
