                 <div className="w-12 h-12 sm:w-16 sm:h-16 bg-amber-500 rounded-2xl flex items-center justify-center mb-6 sm:mb-10 shadow-xl mx-auto font-black text-slate-950 text-2xl sm:text-3xl italic">OSS</div>
                 <h2 className="text-3xl sm:text-4xl font-black text-white italic uppercase tracking-tighter mb-2 leading-none">{adminProfile?.dojoName || "TIME BJJ"}</h2>
                 <p className="text-slate-500 text-[9px] sm:text-[10px] font-black uppercase tracking-widest mb-8 sm:mb-12">OSS! INSIRA SUA CHAVE DE ACESSO</p>
                 <div className="space-y-4 sm:space-y-6 text-left">
                    <div className="relative">
                      <Fingerprint className="absolute left-5 sm:left-6 top-5 sm:top-6 text-slate-600" size={20} sm:size={24} />
                      <input 
                        type="password" 
                        placeholder="CHAVE DE ACESSO" 
                        value={accessKey} 
                        onChange={e => setAccessKey(e.target.value)} 
                        onKeyDown={e => e.key === 'Enter' && handleLogin()}
                        className="w-full p-5 sm:p-6 pl-14 sm:pl-16 bg-slate-800 border border-slate-700 rounded-[1.5rem] sm:rounded-[2rem] text-white outline-none focus:ring-2 focus:ring-amber-500 transition-all font-black uppercase tracking-[0.2em] text-[11px] sm:text-[12px]" 
                      />
