                      <div className={`p-4 rounded-2xl ${athletes.find(a => a.id === user.athleteId)?.paymentDay >= new Date().getDate() ? 'bg-emerald-500' : 'bg-red-500'} shadow-xl`}><CreditCard className="text-white" size={24} /></div>
                      <div>
                        <h4 className="text-lg font-black text-white uppercase italic">Financeiro</h4>
                        <p className={`text-[10px] font-black uppercase ${athletes.find(a => a.id === user.athleteId)?.paymentDay >= new Date().getDate() ? 'text-emerald-500' : 'text-red-500'}`}>
