                    <div className="bg-slate-900 p-5 sm:p-8 rounded-[1.5rem] border border-slate-800 border-b-amber-500 shadow-xl"><p className="text-[9px] font-black text-amber-500 uppercase mb-2">Cobranças</p><p className="text-2xl sm:text-3xl font-black text-white">{stats.imminentPayments.length}</p></div>
