                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Chave de Acesso</label><input type="text" placeholder="Senha/Chave" value={form.accessId || ''} onChange={e => setForm({...form, accessId: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" /></div>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Faixa</label><select value={form.belt} onChange={e => setForm({...form, belt: e.target.value as Belt})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none">{['Branca', 'Cinza', 'Amarela', 'Laranja', 'Verde', 'Azul', 'Roxa', 'Marrom', 'Preta'].map(b => <option key={b} value={b}>{b}</option>)}</select></div>
                    <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Graus</label><input type="number" min="0" max="4" value={form.degrees || 0} onChange={e => setForm({...form, degrees: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black text-[10px] outline-none" /></div>
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Vencimento (Dia)</label><input type="number" placeholder="Dia Vencimento" value={form.paymentDay || ''} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" /></div>
                    <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Turma</label><select value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none"><option value="">Escolha Turma</option>{classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}</select></div>
                  </div>
                </>
              )}

              {modalType === 'transaction' && (
                <>
                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Descrição</label><input type="text" placeholder="Ex: Mensalidade Fulano" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Valor (R$)</label><input type="number" placeholder="0.00" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-slate-500 ml-1">Data</label><input type="date" value={form.date || ''} onChange={e => setForm({...form, date: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" /></div>
                </>
              )}

              {modalType === 'photo' && (
                <>
                  <div className="bg-slate-800 border-2 border-dashed border-slate-700 rounded-[1.5rem] p-6 text-center relative">
                    {form.url ? <img src={form.url} className="w-full h-32 object-cover rounded-xl" /> : <div className="flex flex-col items-center"><Camera className="text-slate-600 mb-2" size={28}/><p className="text-[9px] font-black uppercase text-slate-500">Toque para Foto</p></div>}
                    <input type="file" accept="image/*" onChange={handleFileChange} className="absolute inset-0 opacity-0 cursor-pointer" />
                  </div>
                  <input type="text" placeholder="Legenda da Foto" value={form.caption || ''} onChange={e => setForm({...form, caption: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" />
                </>
              )}

              {modalType === 'class' && (
                <>
                  <input type="text" placeholder="Nome da Turma" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" />
                  <input type="text" placeholder="Horário (Ex: 19:00)" value={form.schedule || ''} onChange={e => setForm({...form, schedule: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" />
                  <input type="text" placeholder="Dias (Ex: Seg/Qua/Sex)" value={form.days || ''} onChange={e => setForm({...form, days: e.target.value})} className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" />
                  <div className="flex gap-2 justify-center py-2 flex-wrap">
                    {CLASS_COLORS.map(c => <button key={c} onClick={() => setForm({...form, color: c})} className={`w-8 h-8 rounded-full ${c} ${form.color === c ? 'ring-2 ring-white ring-offset-2 ring-offset-slate-900' : ''}`} />)}
                  </div>
                </>
              )}
            </div>

            <button onClick={() => {
              if (modalType === 'athlete') {
                if (editId) setAthletes(prev => prev.map(a => a.id === editId ? { ...a, ...form } : a));
                else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), attendanceCount: 0, status: 'active', profileComplete: true, address: INITIAL_ADDRESS, joinDate: new Date().toISOString().split('T')[0] }]);
              } else if (modalType === 'transaction') {
                setTransactions(prev => [...prev, { ...form, id: Date.now().toString() }]);
              } else if (modalType === 'photo') {
                if (!form.url) return alert("Adicione uma foto!");
                setMural(prev => [{ ...form, id: Date.now().toString(), date: new Date().toLocaleDateString(), postedBy: user?.name || 'Mestre' }, ...prev]);
              } else if (modalType === 'class') {
                if (editId) setClasses(prev => prev.map(c => c.id === editId ? { ...c, ...form } : c));
                else setClasses(prev => [...prev, { ...form, id: Date.now().toString() }]);
              }
              setIsModalOpen(false);
            }} className="w-full mt-6 bg-amber-500 text-slate-950 font-black p-5 rounded-xl transition-all uppercase tracking-widest italic text-xs shadow-2xl flex items-center justify-center gap-2">
              <Save size={18} /> Salvar OSS
            </button>
          </div>
        </div>
      )}

      {/* ADMIN REGISTRATION VIEW */}
      {view === AppView.AdminRegistration && (
        <div className="min-h-screen flex items-center justify-center p-4">
          <form onSubmit={(e) => {
            e.preventDefault();
            const f = new FormData(e.currentTarget);
            const p = f.get('password') as string;
            const newAdmin: AdminProfile = {
              name: f.get('name') as string,
              dojoName: f.get('dojoName') as string,
              email: f.get('email') as string,
              phone: f.get('phone') as string,
              address: f.get('address') as string,
              password: p,
              registered: true
            };
            setAdminProfile(newAdmin); setUser({ name: newAdmin.name, role: 'admin' }); navigateTo(AppView.Dashboard);
          }} className="bg-slate-900 p-8 sm:p-10 md:p-16 rounded-[2rem] sm:rounded-[4rem] border border-slate-800 w-full max-w-2xl shadow-2xl space-y-6 sm:space-y-8">
            <div className="text-center">
              <ShieldCheck className="mx-auto text-amber-500 mb-4" size={40} sm:size={48} />
              <h2 className="text-2xl sm:text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Sensei Config</h2>
              <p className="text-slate-500 font-bold text-[9px] uppercase tracking-widest mt-2">OSS! Primeiro acesso do Mestre</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input required name="name" placeholder="Seu Nome" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" />
              <input required name="dojoName" placeholder="Nome do Dojo" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none" />
              <input required name="email" type="email" placeholder="E-mail" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black uppercase text-[10px] outline-none md:col-span-2" />
              <input required name="password" type="password" placeholder="Senha do Sistema" className="w-full p-4 bg-slate-800 border border-slate-700 rounded-xl text-white font-black text-[10px] outline-none md:col-span-2" />
            </div>
            <button type="submit" className="w-full bg-amber-500 text-slate-950 font-black p-5 rounded-xl transition-all uppercase tracking-widest italic text-xs">Ativar Academia OSS</button>
          </form>
        </div>
      )}
    </div>
  );
};

