import { GoogleGenAI, Type } from "@google/genai";

export const getDojoInsights = async (athletes: any[], transactions: any[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const dataSummary = {
    totalAthletes: athletes.length,
    activeAthletes: athletes.filter(a => a.status === 'active').length,
    attendanceAverage: athletes.reduce((acc, a) => acc + a.attendanceCount, 0) / (athletes.length || 1),
    balance: transactions.reduce((acc, t) => acc + (t.type === 'income' ? t.amount : -t.amount), 0),
    imminentPayments: athletes.filter(a => {
      const today = new Date().getDate();
      return a.paymentDay - today <= 3 && a.paymentDay >= today;
    }).length
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Você é o "Sensei Virtual", um consultor especialista em gestão de academias de Jiu-Jitsu (BJJ). 
      Analise os seguintes dados da academia e forneça um relatório estratégico curto e motivador em Português:

      DADOS:
      ${JSON.stringify(dataSummary)}

      ESTRUTURA DA RESPOSTA:
      1. Diagnóstico de Saúde Financeira.
      2. Alerta de Frequência e Engajamento.
      3. Uma sugestão prática para retenção.

      Seja direto, use termos do BJJ e tom profissional.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao processar insights. Foque nos fundamentos. OSS!";
  }
};

export const searchYoutubeVideos = async (query: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Pesquise no YouTube músicas de treino ou vídeos relacionados a: "${query}". 
      Retorne uma lista de 6 vídeos populares. Para cada vídeo, forneça o título exato e o ID do vídeo (ex: dQw4w9WgXcQ).
      Retorne APENAS um JSON válido.`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            results: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  videoId: { type: Type.STRING, description: "O ID único de 11 caracteres do vídeo do YouTube" }
                },
                required: ["title", "videoId"]
              }
            }
          },
          required: ["results"]
        }
      }
    });

    const json = JSON.parse(response.text);
    return json.results as { title: string; videoId: string }[];
  } catch (error) {
    console.error("Search Error:", error);
    return [];
  }
};

