      ${JSON.stringify(dataSummary)}

      ESTRUTURA DA RESPOSTA:
      1. Diagnóstico de Saúde Financeira.
      2. Alerta de Frequência e Engajamento.
      3. Uma sugestão prática para retenção.

      Seja direto, use termos do BJJ e tom profissional.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao processar insights. Foque nos fundamentos. OSS!";
  }
};

export const searchYoutubeVideos = async (query: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Encontre 6 vídeos de música ou mixes no YouTube para a busca: "${query}". 
      Dê preferência a vídeos que permitam "Embed" (incorporação em outros sites).
      Retorne APENAS um JSON no formato: {"results": [{"title": "Nome do Vídeo", "videoId": "ID_DE_11_CARACTERES"}]}`,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            results: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  videoId: { type: Type.STRING, description: "O ID único de 11 caracteres do vídeo do YouTube (ex: dQw4w9WgXcQ)" }
                },
                required: ["title", "videoId"]
              }
            }
          },
          required: ["results"]
        }
      }
    });

    const json = JSON.parse(response.text);
    return json.results as { title: string; videoId: string }[];
  } catch (error) {
    console.error("Search Error:", error);
    return [];
  }
};

