  const [isSearching, setIsSearching] = useState(false);

  // Temporizador
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<AlarmType>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [manualSec, setManualSec] = useState(0);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Sincronização LocalStorage
  useEffect(() => {
    localStorage.setItem('timebjj_athletes', JSON.stringify(athletes));
    localStorage.setItem('timebjj_transactions', JSON.stringify(transactions));
    localStorage.setItem('timebjj_classes', JSON.stringify(classes));
    if (adminProfile) localStorage.setItem('timebjj_admin', JSON.stringify(adminProfile));
    localStorage.setItem('timebjj_last_videoId', currentVideoId);
  }, [athletes, transactions, classes, adminProfile, currentVideoId]);

  // IA Insights
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, user]);

  // Lógica do Temporizador
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      startContinuousAlarm();
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const startContinuousAlarm = () => {
    stopAlarm();
    setIsAlarmPlaying(true);
    const play = () => {
      if (['MATE', 'FIM', 'TIME'].includes(selectedAlarm)) {
        const msg = selectedAlarm === 'MATE' ? 'MATÊ!' : selectedAlarm === 'FIM' ? 'FIM DE TREINO!' : 'IT IS TIME!';
        const utt = new SpeechSynthesisUtterance(msg);
        utt.lang = selectedAlarm === 'TIME' ? 'en-US' : 'pt-BR';
        window.speechSynthesis.speak(utt);
      } else {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioContextRef.current = ctx;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.frequency.setValueAtTime(selectedAlarm === 'buzzer' ? 120 : 1000, ctx.currentTime);
        osc.start(); osc.stop(ctx.currentTime + 1.2);
      }
    };
    alarmIntervalRef.current = window.setInterval(play, 2000);
    play();
  };

