import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, AlertTriangle, Save, CreditCard, ArrowRight, 
  ImageIcon, Upload, ChevronRight,
  Clock, Filter, LayoutGrid, Trash2, Play, Pause, RotateCcw, Volume2, 
  VolumeX, Fingerprint, Calendar, Database, Download, FileJson, ShieldAlert,
  Youtube, Music, Search, PlayCircle, Loader2, ExternalLink, Info
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address, MuralPhoto, TrainingClass } from './types';
import { getDojoInsights, searchYoutubeVideos } from './geminiService';

const INITIAL_ADDRESS: Address = { street: '', number: '', neighborhood: '', city: '', cep: '' };

