type AlarmType = 'buzzer' | 'bell' | 'MATE' | 'FIM' | 'TIME';

const App: React.FC = () => {
  // Estados de Persistência
  const [athletes, setAthletes] = useState<Athlete[]>(() => JSON.parse(localStorage.getItem('timebjj_athletes') || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(() => JSON.parse(localStorage.getItem('timebjj_transactions') || '[]'));
  const [classes, setClasses] = useState<TrainingClass[]>(() => JSON.parse(localStorage.getItem('timebjj_classes') || '[]'));
  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => JSON.parse(localStorage.getItem('timebjj_admin') || 'null'));

  // Estados de UI
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [accessKey, setAccessKey] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction' | 'class'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Estados de Música (YouTube)
  const [currentVideoId, setCurrentVideoId] = useState<string>(() => localStorage.getItem('timebjj_last_videoId') || 'dQw4w9WgXcQ');
  const [videoInput, setVideoInput] = useState('');
  const [searchResults, setSearchResults] = useState<{title: string, videoId: string}[]>([]);
  const [isSearching, setIsSearching] = useState(false);

  // Temporizador
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<AlarmType>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [manualSec, setManualSec] = useState(0);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Sincronização LocalStorage
  useEffect(() => {
    localStorage.setItem('timebjj_athletes', JSON.stringify(athletes));
    localStorage.setItem('timebjj_transactions', JSON.stringify(transactions));
    localStorage.setItem('timebjj_classes', JSON.stringify(classes));
    if (adminProfile) localStorage.setItem('timebjj_admin', JSON.stringify(adminProfile));
    localStorage.setItem('timebjj_last_videoId', currentVideoId);
  }, [athletes, transactions, classes, adminProfile, currentVideoId]);

  // IA Insights
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, user]);

  // Lógica do Temporizador
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      startContinuousAlarm();
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const startContinuousAlarm = () => {
    stopAlarm();
    setIsAlarmPlaying(true);
    const play = () => {
      if (['MATE', 'FIM', 'TIME'].includes(selectedAlarm)) {
        const msg = selectedAlarm === 'MATE' ? 'MATÊ!' : selectedAlarm === 'FIM' ? 'FIM DE TREINO!' : 'IT IS TIME!';
        const utt = new SpeechSynthesisUtterance(msg);
        utt.lang = selectedAlarm === 'TIME' ? 'en-US' : 'pt-BR';
        window.speechSynthesis.speak(utt);
      } else {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioContextRef.current = ctx;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.frequency.setValueAtTime(selectedAlarm === 'buzzer' ? 120 : 1000, ctx.currentTime);
        osc.start(); osc.stop(ctx.currentTime + 1.2);
      }
    };
    alarmIntervalRef.current = window.setInterval(play, 2000);
    play();
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (alarmIntervalRef.current) clearInterval(alarmIntervalRef.current);
    if (audioContextRef.current) audioContextRef.current.close();
    window.speechSynthesis.cancel();
  };

  const formatTime = (s: number) => `${Math.floor(s / 60).toString().padStart(2, '0')}:${(s % 60).toString().padStart(2, '0')}`;

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminentPayments = athletes.filter(a => a.status === 'active' && Math.abs(a.paymentDay - today) <= 3);
    const birthdays = athletes.filter(a => a.birthDate && new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
