            </div>
            <button type="submit" className="w-full bg-amber-500 text-slate-950 font-black p-7 rounded-[2rem] uppercase italic text-sm shadow-2xl active:scale-95 transition-all hover:bg-white">Iniciar Sistema OSS</button>
