import { GoogleGenAI, Type } from "@google/genai";

export const getDojoInsights = async (athletes: any[], transactions: any[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const dataSummary = {
    totalAthletes: athletes.length,
    activeAthletes: athletes.filter(a => a.status === 'active').length,
    attendanceAverage: athletes.reduce((acc, a) => acc + a.attendanceCount, 0) / (athletes.length || 1),
    balance: transactions.reduce((acc, t) => acc + (t.type === 'income' ? t.amount : -t.amount), 0),
    imminentPayments: athletes.filter(a => {
      const today = new Date().getDate();
      return a.paymentDay - today <= 3 && a.paymentDay >= today;
    }).length
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Você é o "Sensei Virtual", um consultor especialista em gestão de academias de Jiu-Jitsu (BJJ). 
      Analise os seguintes dados da academia e forneça um relatório estratégico curto e motivador em Português:

      DADOS:
      ${JSON.stringify(dataSummary)}

      ESTRUTURA DA RESPOSTA:
      1. Diagnóstico de Saúde Financeira.
      2. Alerta de Frequência e Engajamento.
      3. Uma sugestão prática para retenção de alunos.

      Seja direto, use termos do BJJ (raspagem, ajuste, guarda, pressão) e mantenha o tom profissional.`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao processar insights. Foque nos fundamentos e no controle de presença. OSS!";
  }
};

