                        <td className={`px-8 py-6 text-right font-black ${t.type === 'income' ? 'text-emerald-500' : 'text-red-500'}`}>{t.type === 'income' ? '+' : '-'} R$ {t.amount.toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        )}

        {/* RANKING */}
        {view === AppView.Ranking && (
          <div className="space-y-8 animate-in fade-in max-w-2xl mx-auto pb-10">
             <header className="text-center"><h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Ranking do Tatame</h2></header>
             <div className="space-y-4">
                {stats.ranking.map((ath, idx) => (
                  <div key={ath.id} className={`p-6 rounded-[2.5rem] border flex items-center gap-6 shadow-2xl transition-all ${idx === 0 ? 'bg-amber-500 border-amber-400 text-slate-950 scale-105' : 'bg-slate-900 border-slate-800 text-white'}`}>
