        {/* ANIVERSARIANTES */}
        {view === AppView.Birthdays && (
          <div className="space-y-8 animate-in fade-in max-w-3xl mx-auto pb-10">
             <header className="text-center"><h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">B-Days do Mês</h2></header>
             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {stats.birthdays.length > 0 ? stats.birthdays.map(ath => (
                  <div key={ath.id} className="p-8 bg-indigo-500/10 border border-indigo-500/30 rounded-[2.5rem] flex flex-col items-center gap-4 text-center shadow-xl">
                    <div className="w-16 h-16 bg-indigo-500 rounded-2xl flex items-center justify-center text-white shadow-lg"><Cake size={32}/></div>
                    <div>
                      <p className="font-black text-white uppercase italic text-lg">{ath.name}</p>
                      <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest mt-1">Nasc: {new Date(ath.birthDate).toLocaleDateString()}</p>
                    </div>
                    <BeltBadge belt={ath.belt} degrees={ath.degrees} />
                  </div>
                )) : (
                  <div className="col-span-full p-20 text-center opacity-30">
                    <Cake size={64} className="mx-auto mb-4" />
