        {/* TIMER */}
        {view === AppView.Timer && (
          <div className="flex flex-col items-center gap-10 animate-in zoom-in-95 duration-500 max-w-4xl mx-auto pb-10">
             <header className="text-center"><h2 className="text-4xl font-black text-white italic uppercase tracking-tighter">Round Clock</h2></header>
             {isAlarmPlaying && (
               <button onClick={stopAlarm} className="bg-red-600 text-white p-6 rounded-3xl w-full animate-pulse flex items-center justify-between shadow-2xl ring-4 ring-red-500/30">
                  <span className="font-black italic uppercase text-sm">Fim do Round! Toque para parar OSS!</span>
                  <VolumeX size={24}/>
               </button>
             )}
             <div className="bg-slate-900 p-12 sm:p-20 rounded-[4rem] border border-slate-800 shadow-2xl flex flex-col items-center gap-10 relative w-full border-b-amber-500/30">
                <div className="text-[110px] sm:text-[160px] font-black text-white tabular-nums tracking-tighter leading-none drop-shadow-[0_0_40px_rgba(251,191,36,0.3)]">{formatTime(timeLeft)}</div>
                <div className="flex items-center gap-8">
                   <div className="flex flex-col items-center">
                      <input type="number" min="0" value={manualMin} onChange={e => { const val = parseInt(e.target.value)||0; setManualMin(val); setTimeLeft(val*60); }} className="w-24 p-5 bg-slate-950 rounded-2xl text-center text-4xl font-black text-white border border-slate-700 outline-none focus:ring-2 focus:ring-amber-500" />
                      <span className="text-[10px] font-black uppercase text-slate-500 mt-2 tracking-widest italic">Mins</span>
                   </div>
                </div>
                <div className="flex items-center gap-6">
                   <button onClick={() => { setIsTimerRunning(!isTimerRunning); stopAlarm(); }} className={`w-32 h-32 rounded-[3rem] flex items-center justify-center transition-all shadow-2xl active:scale-90 ring-8 ${isTimerRunning ? 'bg-red-500 ring-red-500/10' : 'bg-emerald-500 ring-emerald-500/10'}`}>
                      {isTimerRunning ? <Pause size={56} /> : <Play size={56} className="ml-2" fill="currentColor" />}
                   </button>
                   <button onClick={() => { setIsTimerRunning(false); setTimeLeft(manualMin*60); stopAlarm(); }} className="w-20 h-20 bg-slate-800 rounded-[2rem] flex items-center justify-center text-slate-400 active:scale-95 transition-all hover:text-white shadow-md"><RotateCcw size={32}/></button>
                </div>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 w-full max-w-lg">
                  {(['buzzer', 'bell', 'MATE', 'FIM'] as AlarmType[]).map(a => (
                    <button key={a} onClick={() => setSelectedAlarm(a)} className={`p-4 rounded-2xl text-[10px] font-black uppercase transition-all shadow-sm ${selectedAlarm === a ? 'bg-amber-500 text-slate-950' : 'bg-slate-800 text-slate-500 hover:text-slate-300'}`}>{a}</button>
