        )}

        {/* SETTINGS */}
        {view === AppView.Settings && user?.role === 'admin' && (
          <div className="space-y-10 animate-in fade-in">
             <header><h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Ajustes & Backup</h2></header>
             <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 space-y-6 shadow-2xl relative overflow-hidden">
                   <Download className="text-amber-500" size={40} />
                   <h4 className="text-xl font-black text-white uppercase italic">Baixar Dados</h4>
                   <p className="text-slate-500 text-xs leading-relaxed">Exporte todos os alunos e finanças para um arquivo JSON.</p>
                   <button onClick={() => {
                     const data = { athletes, transactions, adminProfile, date: new Date().toISOString() };
                     const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                     const url = URL.createObjectURL(blob);
                     const a = document.createElement('a'); a.href = url; a.download = `backup_timebjj_${new Date().toISOString().split('T')[0]}.json`; a.click();
                   }} className="w-full bg-amber-500 text-slate-950 font-black py-4 rounded-2xl uppercase text-[10px] flex items-center justify-center gap-2 active:scale-95 shadow-xl"><FileJson size={16}/> Exportar</button>
                </div>
                <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 space-y-6 shadow-2xl">
                   <Upload className="text-indigo-500" size={40} />
