                   <input type="file" accept=".json" onChange={(e) => {
                     const f = e.target.files?.[0]; if(!f) return;
                     const reader = new FileReader();
                     reader.onload = (ev) => {
                       try {
                         const json = JSON.parse(ev.target?.result as string);
                         if(json.athletes) {
                           setAthletes(json.athletes); setTransactions(json.transactions || []);
                           setAdminProfile(json.adminProfile || null); alert("OSS! Dados restaurados."); setView(AppView.Dashboard);
                         }
                       } catch { alert("Arquivo inválido."); }
                     }; reader.readAsText(f);
                   }} className="w-full text-[10px] text-slate-500 file:mr-4 file:py-3 file:px-6 file:rounded-xl file:border-0 file:text-[10px] file:font-black file:bg-slate-800 file:text-white" />
                </div>
             </div>
          </div>
        )}
      </main>

      {/* BOTTOM NAV MOBILE */}
      {user && view !== AppView.Login && (
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-slate-900/98 backdrop-blur-3xl border-t border-slate-800 flex justify-around p-4 pb-8 z-[60] shadow-[0_-15px_40px_rgba(0,0,0,0.8)]">
           <button onClick={() => navigateTo(AppView.Dashboard)} className={`flex flex-col items-center gap-1.5 transition-all ${view === AppView.Dashboard ? 'text-amber-500' : 'text-slate-600'}`}><Home size={22}/><span className="text-[8px] font-black uppercase tracking-widest">Início</span></button>
           <button onClick={() => navigateTo(AppView.Ranking)} className={`flex flex-col items-center gap-1.5 transition-all ${view === AppView.Ranking ? 'text-amber-500' : 'text-slate-600'}`}><Trophy size={22}/><span className="text-[8px] font-black uppercase tracking-widest">Rank</span></button>
           <button onClick={() => navigateTo(AppView.Timer)} className={`flex flex-col items-center gap-1.5 transition-all ${view === AppView.Timer ? 'text-amber-500' : 'text-slate-600'}`}><Clock size={22}/><span className="text-[8px] font-black uppercase tracking-widest">Timer</span></button>
           <button onClick={() => setIsMobileMenuOpen(true)} className="flex flex-col items-center gap-1.5 text-slate-600 active:text-amber-500"><Menu size={22}/><span className="text-[8px] font-black uppercase tracking-widest">Mais</span></button>
        </nav>
      )}

      {/* MOBILE MENU FULLSCREEN */}
      {isMobileMenuOpen && (
        <div className="fixed inset-0 bg-slate-950/98 z-[200] flex flex-col p-8 pt-24 animate-in fade-in slide-in-from-bottom-5 backdrop-blur-3xl overflow-hidden">
          <button onClick={() => setIsMobileMenuOpen(false)} className="absolute top-10 right-10 bg-slate-800 text-white p-4 rounded-3xl shadow-2xl active:scale-90 border border-slate-700">
             <X size={32}/>
          </button>

          <div className="flex-1 overflow-y-auto custom-scrollbar">
            <h2 className="text-4xl font-black italic uppercase text-white mb-10 tracking-tighter border-b border-slate-800 pb-4">Menu Sistema</h2>
            <div className="grid grid-cols-1 gap-4">
              {[
                { v: AppView.Dashboard, i: Home, t: "Home", color: "text-amber-500" },
                { v: AppView.Athletes, i: Users, t: "Alunos", admin: true, color: "text-amber-500" },
                { v: AppView.Attendance, i: CalendarCheck, t: "Chamada", admin: true, color: "text-emerald-500" },
                { v: AppView.Finance, i: DollarSign, t: "Financeiro", admin: true, color: "text-indigo-500" },
                { v: AppView.Ranking, i: Trophy, t: "Ranking", color: "text-amber-400" },
                { v: AppView.Birthdays, i: Cake, t: "B-Days", color: "text-indigo-400" },
                { v: AppView.Timer, i: Clock, t: "Temporizador", color: "text-amber-500" },
                { v: AppView.Settings, i: Database, t: "Ajustes", admin: true, color: "text-slate-400" }
              ].map(item => (
                (!item.admin || user?.role === 'admin') && (
                  <button key={item.v} onClick={() => navigateTo(item.v)} className="flex items-center gap-6 bg-slate-900 border border-slate-800 p-7 rounded-[2.5rem] text-white font-black uppercase text-xs active:bg-slate-800 active:border-amber-500 shadow-xl transition-all">
                    <div className={`${item.color} shrink-0`}><item.i size={30}/></div>
                    <span className="tracking-widest">{item.t}</span>
                  </button>
                )
              ))}
              <button onClick={() => { setUser(null); navigateTo(AppView.Login); }} className="flex items-center gap-6 bg-red-500/10 border border-red-500/20 p-7 rounded-[2.5rem] text-red-500 font-black uppercase text-xs mt-6 active:scale-95 transition-all shadow-xl"><LogOut size={30}/> Sair do App</button>
            </div>
          </div>
        </div>
      )}

      {/* MODALS */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/95 backdrop-blur-2xl z-[300] flex items-center justify-center p-4">
           <div className="bg-slate-900 border border-slate-800 rounded-[3rem] w-full max-w-xl p-10 shadow-[0_0_100px_rgba(0,0,0,0.8)] animate-in zoom-in-95 overflow-y-auto max-h-[92vh] border-b-amber-500/50">
              <div className="flex justify-between items-center mb-10"><h3 className="text-2xl font-black text-white italic uppercase tracking-tighter">{editId ? 'Editar' : 'Novo'} {modalType === 'athlete' ? 'Aluno' : 'Lançamento'}</h3><button onClick={() => setIsModalOpen(false)} className="text-slate-500 hover:text-white transition-colors"><X size={32}/></button></div>
              <div className="space-y-6">
                {modalType === 'athlete' && (
                  <>
                    <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-500 uppercase ml-2">Nome Completo</label><input type="text" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase focus:ring-2 focus:ring-amber-500 transition-all shadow-inner" /></div>
                    <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-500 uppercase ml-2">Chave de Acesso</label><input type="text" value={form.accessId || ''} onChange={e => setForm({...form, accessId: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase focus:ring-2 focus:ring-amber-500 transition-all shadow-inner" /></div>
                    <div className="grid grid-cols-2 gap-4">
                       <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-500 uppercase ml-2">Faixa</label><select value={form.belt} onChange={e => setForm({...form, belt: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase appearance-none"><option value="Branca">Branca</option><option value="Azul">Azul</option><option value="Roxa">Roxa</option><option value="Marrom">Marrom</option><option value="Preta">Preta</option></select></div>
                       <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-500 uppercase ml-2">Dia Vencimento</label><input type="number" min="1" max="31" value={form.paymentDay || 10} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs" /></div>
                    </div>
                    <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-500 uppercase ml-2">Data Nascimento</label><input type="date" value={form.birthDate || ''} onChange={e => setForm({...form, birthDate: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs" /></div>
                  </>
                )}
                {modalType === 'transaction' && (
                  <>
                    <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-500 uppercase ml-2">Descrição</label><input type="text" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase" /></div>
                    <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-500 uppercase ml-2">Valor R$</label><input type="number" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs" /></div>
                  </>
                )}
              </div>
              <button onClick={() => {
                if(modalType === 'athlete') {
                  if(editId) setAthletes(prev => prev.map(a => a.id === editId ? {...a, ...form} : a));
                  else setAthletes(prev => [...prev, {...form, id: Date.now().toString(), status: 'active', attendanceCount: 0}]);
                } else if(modalType === 'transaction') {
                  setTransactions(prev => [...prev, {...form, id: Date.now().toString()}]);
                }
                setIsModalOpen(false);
              }} className="w-full mt-12 bg-amber-500 text-slate-950 font-black p-7 rounded-[2rem] transition-all uppercase italic text-sm shadow-2xl active:scale-95 hover:bg-white">Finalizar OSS!</button>
           </div>
        </div>
      )}

      {/* ADMIN REGISTRATION */}
      {view === AppView.AdminRegistration && (
        <div className="min-h-screen flex items-center justify-center p-4">
          <form onSubmit={(e) => { e.preventDefault(); const f = new FormData(e.currentTarget); const newAdmin = { name: f.get('name'), dojoName: f.get('dojoName'), password: f.get('password'), registered: true }; setAdminProfile(newAdmin as any); setUser({ name: newAdmin.name as string, role: 'admin' }); setView(AppView.Dashboard); }} className="bg-slate-900 p-10 sm:p-20 rounded-[4rem] border border-slate-800 w-full max-w-2xl shadow-2xl space-y-12 text-center border-b-amber-500/50">
            <h2 className="text-4xl font-black text-white italic uppercase tracking-tighter">Ativar Sensei</h2>
            <div className="grid grid-cols-1 gap-6 text-left">
              <input required name="name" placeholder="Seu Nome Mestre" className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white font-black uppercase text-xs outline-none" />
              <input required name="dojoName" placeholder="Nome da Academia / Dojo" className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white font-black uppercase text-xs outline-none" />
              <input required name="password" type="password" placeholder="Defina sua Senha Administrativa" className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white font-black uppercase text-xs outline-none" />
            </div>
            <button type="submit" className="w-full bg-amber-500 text-slate-950 font-black p-7 rounded-[2rem] uppercase italic text-sm hover:bg-white active:scale-95 transition-all shadow-2xl">Ativar OSS!</button>
          </form>
        </div>
      )}
    </div>
  );
};

export default App;

{
  "name": "SISTEMA BJJ",
  "description": "Sistema completo para gestão de alunos, controle financeiro, frequência e aniversariantes com insights inteligentes via Gemini.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, ArrowRight, Clock, Database, Download, FileJson, 
  ShieldAlert, RotateCcw, VolumeX, Fingerprint, Calendar as CalendarIcon, 
  Info, Bell, Cake, ChevronRight, Play, Pause, Trash2, Upload
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address } from './types';
import { getDojoInsights } from './geminiService';

const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78330f',
  'Preta': '#0f172a'
};

const BeltBadge: React.FC<{ belt: Belt; degrees: number }> = ({ belt, degrees }) => (
  <div className="flex items-center gap-2">
    <div 
      className="h-4 w-12 sm:h-5 sm:w-16 rounded shadow-inner border border-slate-800 flex relative overflow-hidden shrink-0"
      style={{ backgroundColor: BELT_COLORS[belt] || '#fff' }}
    >
      <div className={`absolute right-0 top-0 bottom-0 w-4 sm:w-5 ${belt === 'Preta' ? 'bg-red-600' : 'bg-slate-950'} flex items-center justify-center gap-0.5 px-0.5`}>
        {Array.from({ length: Math.min(degrees, 4) }).map((_, i) => (
          <div key={i} className="w-[1px] sm:w-[1.5px] h-2 sm:h-3 bg-white" />
        ))}
      </div>
    </div>
    <span className="text-[8px] sm:text-[9px] font-black uppercase tracking-tighter text-slate-400 truncate">{belt}</span>
  </div>
);

const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
};

type AlarmType = 'buzzer' | 'bell' | 'MATE' | 'FIM';

const App: React.FC = () => {
  // Persistência - Using a standard prefix for this version
  const STORAGE_KEY_ATHLETES = 'sistemabjj_athletes_v1';
  const STORAGE_KEY_TRANSACTIONS = 'sistemabjj_transactions_v1';
  const STORAGE_KEY_ADMIN = 'sistemabjj_admin_v1';

  const [athletes, setAthletes] = useState<Athlete[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_ATHLETES) || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_TRANSACTIONS) || '[]'));
  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_ADMIN) || 'null'));

  // UI State
  const [user, setUser] = useState<{name: string, role: string, athleteId?: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login);
  const [accessKey, setAccessKey] = useState('');
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Timer State
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<AlarmType>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ATHLETES, JSON.stringify(athletes));
    localStorage.setItem(STORAGE_KEY_TRANSACTIONS, JSON.stringify(transactions));
    if (adminProfile) localStorage.setItem(STORAGE_KEY_ADMIN, JSON.stringify(adminProfile));
  }, [athletes, transactions, adminProfile]);

  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, user]);

  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      startAlarm();
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const startAlarm = () => {
    stopAlarm();
    setIsAlarmPlaying(true);
    const play = () => {
      if (['MATE', 'FIM'].includes(selectedAlarm)) {
        const utt = new SpeechSynthesisUtterance(selectedAlarm === 'MATE' ? 'MATÊ!' : 'FIM DE ROUND!');
        utt.lang = 'pt-BR';
        utt.rate = 1.2;
        window.speechSynthesis.speak(utt);
      } else {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioContextRef.current = ctx;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.frequency.setValueAtTime(selectedAlarm === 'buzzer' ? 140 : 880, ctx.currentTime);
        osc.start(); osc.stop(ctx.currentTime + 1.5);
      }
    };
    alarmIntervalRef.current = window.setInterval(play, 3500);
    play();
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (alarmIntervalRef.current) clearInterval(alarmIntervalRef.current);
    if (audioContextRef.current) {
        audioContextRef.current.close().catch(() => {});
        audioContextRef.current = null;
    }
    window.speechSynthesis.cancel();
  };

  const stats = useMemo(() => {
    const now = new Date();
    const today = now.getDate();
    const currentMonth = now.getMonth();
    const imminent = athletes.filter(a => a.status === 'active' && (a.paymentDay === today || (a.paymentDay > today && a.paymentDay - today <= 3)));
    const birthdays = athletes.filter(a => a.birthDate && new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminent, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const handleLogin = () => {
    const key = accessKey.trim();
    if (!adminProfile?.registered) { setView(AppView.AdminRegistration); return; }
    if (key === adminProfile.password) { setUser({ name: adminProfile.name, role: 'admin' }); setView(AppView.Dashboard); setAccessKey(''); return; }
    const ath = athletes.find(a => a.accessId.toUpperCase() === key.toUpperCase());
