              <div className="space-y-2"><label className="text-[11px] font-black text-slate-500 uppercase ml-3 tracking-widest">Nome do Dojo</label><input required name="dojoName" placeholder="EX: GRACIE ACADEMY" className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white font-black uppercase text-xs outline-none focus:ring-2 focus:ring-amber-500 transition-all" /></div>
