            </div>
            <button type="submit" className="w-full bg-amber-500 text-slate-950 font-black p-8 rounded-[2.5rem] uppercase italic text-sm hover:bg-white active:scale-95 transition-all shadow-2xl tracking-[0.2em]">ATIVAR SISTEMA OSS!</button>
