      )}
    </div>
  );
};

export default App;

{
  "name": "SISTEMA BJJ",
  "description": "Plataforma de gestão inteligente para academias de Jiu-Jitsu com controle financeiro, frequência e consultoria via IA.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, ArrowRight, Clock, Database, Download, FileJson, 
  ShieldAlert, RotateCcw, VolumeX, Fingerprint, Calendar as CalendarIcon, 
  Info, Bell, Cake, ChevronRight, Play, Pause, Trash2, Upload, TrendingUp, TrendingDown
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile, Address } from './types';
import { getDojoInsights } from './geminiService';

const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78330f',
  'Preta': '#0f172a'
};

const BeltBadge: React.FC<{ belt: Belt; degrees: number }> = ({ belt, degrees }) => (
  <div className="flex items-center gap-2">
    <div 
      className="h-4 w-12 sm:h-5 sm:w-16 rounded shadow-inner border border-slate-800 flex relative overflow-hidden shrink-0"
      style={{ backgroundColor: BELT_COLORS[belt] || '#fff' }}
    >
      <div className={`absolute right-0 top-0 bottom-0 w-4 sm:w-5 ${belt === 'Preta' ? 'bg-red-600' : 'bg-slate-950'} flex items-center justify-center gap-0.5 px-0.5`}>
        {Array.from({ length: Math.min(degrees, 4) }).map((_, i) => (
          <div key={i} className="w-[1px] sm:w-[1.5px] h-2 sm:h-3 bg-white" />
        ))}
      </div>
    </div>
    <span className="text-[8px] sm:text-[9px] font-black uppercase tracking-tighter text-slate-400 truncate">{belt}</span>
  </div>
);

const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
};

type AlarmType = 'buzzer' | 'bell' | 'MATE' | 'FIM';

const App: React.FC = () => {
  // Chaves de Persistência
  const STORAGE_KEY_ATHLETES = 'sistemabjj_athletes_v1';
  const STORAGE_KEY_TRANSACTIONS = 'sistemabjj_transactions_v1';
  const STORAGE_KEY_ADMIN = 'sistemabjj_admin_v1';

  const [athletes, setAthletes] = useState<Athlete[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_ATHLETES) || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_TRANSACTIONS) || '[]'));
  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_ADMIN) || 'null'));

  // UI State
  const [user, setUser] = useState<{name: string, role: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Dashboard);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Timer State
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<AlarmType>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  // Efeito de Login Automático
  useEffect(() => {
    if (adminProfile?.registered) {
      setUser({ name: adminProfile.name, role: 'admin' });
      setView(AppView.Dashboard);
    } else {
      setView(AppView.AdminRegistration);
    }
  }, [adminProfile]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ATHLETES, JSON.stringify(athletes));
    localStorage.setItem(STORAGE_KEY_TRANSACTIONS, JSON.stringify(transactions));
    if (adminProfile) localStorage.setItem(STORAGE_KEY_ADMIN, JSON.stringify(adminProfile));
  }, [athletes, transactions, adminProfile]);

  // Insight IA Automático
  useEffect(() => {
    if (view === AppView.Dashboard && user?.role === 'admin' && athletes.length > 0) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, user, athletes.length, transactions.length]);

  // Lógica do Timer
  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      triggerAlarm();
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const triggerAlarm = () => {
    stopAlarm();
    setIsAlarmPlaying(true);
    const play = () => {
      if (['MATE', 'FIM'].includes(selectedAlarm)) {
        const msg = new SpeechSynthesisUtterance(selectedAlarm === 'MATE' ? 'MATÊ!' : 'FIM DE ROUND!');
        msg.lang = 'pt-BR';
        msg.rate = 1.1;
        window.speechSynthesis.speak(msg);
      } else {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioContextRef.current = ctx;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.frequency.setValueAtTime(selectedAlarm === 'buzzer' ? 150 : 900, ctx.currentTime);
        osc.start(); osc.stop(ctx.currentTime + 1.2);
      }
    };
    alarmIntervalRef.current = window.setInterval(play, 3000);
    play();
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (alarmIntervalRef.current) clearInterval(alarmIntervalRef.current);
    if (audioContextRef.current) audioContextRef.current.close().catch(() => {});
    window.speechSynthesis.cancel();
  };

  const stats = useMemo(() => {
    const now = new Date();
    const today = now.getDate();
    const currentMonth = now.getMonth();
    const imminent = athletes.filter(a => a.status === 'active' && (a.paymentDay === today || (a.paymentDay > today && a.paymentDay - today <= 3)));
    const birthdays = athletes.filter(a => a.birthDate && new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminent, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const markAttendance = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    setAthletes(prev => prev.map(a => a.id === id && a.lastAttendance !== today ? { ...a, attendanceCount: a.attendanceCount + 1, lastAttendance: today } : a));
  };

  const navigateTo = (v: AppView) => { 
    setView(v); 
    setIsMobileMenuOpen(false); 
    window.scrollTo({ top: 0, behavior: 'smooth' }); 
  };

  if (view === AppView.AdminRegistration) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4 bg-slate-950 text-white font-['Inter']">
        <form onSubmit={(e) => { 
          e.preventDefault(); 
          const f = new FormData(e.currentTarget); 
          const newAdmin = { name: f.get('name'), dojoName: f.get('dojoName'), password: f.get('password'), registered: true }; 
          setAdminProfile(newAdmin as any); 
        }} className="bg-slate-900 p-8 sm:p-12 rounded-[3rem] border border-slate-800 w-full max-w-xl shadow-2xl space-y-10 text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-amber-500"></div>
          <ShieldAlert className="mx-auto text-amber-500 mb-2" size={64} />
          <h2 className="text-3xl font-black italic uppercase tracking-tighter">Ativar SISTEMA BJJ</h2>
          <div className="space-y-6 text-left">
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500 ml-2 tracking-widest">Seu Nome Mestre</label><input required name="name" placeholder="NOME COMPLETO" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase text-xs focus:ring-2 focus:ring-amber-500 transition-all outline-none" /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500 ml-2 tracking-widest">Nome da Academia</label><input required name="dojoName" placeholder="EX: GRACIE BARRA" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase text-xs focus:ring-2 focus:ring-amber-500 transition-all outline-none" /></div>
            <div className="space-y-1"><label className="text-[10px] font-black uppercase text-slate-500 ml-2 tracking-widest">Sua Senha Mestre</label><input required name="password" type="password" placeholder="DEFINA UMA SENHA" className="w-full p-5 bg-slate-800 border border-slate-700 rounded-2xl text-white font-black uppercase text-xs focus:ring-2 focus:ring-amber-500 transition-all outline-none" /></div>
          </div>
          <button type="submit" className="w-full bg-amber-500 text-slate-950 font-black p-6 rounded-2xl uppercase italic text-sm hover:bg-white active:scale-95 transition-all shadow-xl tracking-widest">Iniciar Gestão OSS!</button>
        </form>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-slate-950 text-slate-100 font-['Inter'] selection:bg-amber-500 relative">

      {/* SIDEBAR DESKTOP */}
      <aside className="w-64 lg:w-72 bg-slate-900 border-r border-slate-800 p-6 hidden md:flex flex-col gap-6 sticky top-0 h-screen z-50">
        <div className="flex items-center space-x-3 mb-8">
          <div className="w-10 h-10 bg-amber-500 rounded-xl flex items-center justify-center shadow-lg"><Medal className="text-slate-950" size={24} /></div>
          <span className="text-xl font-black italic uppercase text-white tracking-tighter leading-none">SISTEMA BJJ</span>
        </div>
        <nav className="flex-1 space-y-1 overflow-y-auto custom-scrollbar pr-1">
          {[
            { v: AppView.Dashboard, i: Home, t: "Dashboard" },
            { v: AppView.Athletes, i: Users, t: "Alunos" },
            { v: AppView.Attendance, i: CalendarCheck, t: "Chamada" },
            { v: AppView.Finance, i: DollarSign, t: "Financeiro" },
            { v: AppView.Ranking, i: Trophy, t: "Ranking" },
            { v: AppView.Birthdays, i: Cake, t: "B-Days" },
            { v: AppView.Timer, i: Clock, t: "Timer" },
            { v: AppView.Settings, i: Database, t: "Ajustes" }
          ].map(item => (
            <button key={item.v} onClick={() => navigateTo(item.v)} className={`w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest transition-all ${view === item.v ? 'bg-amber-500 text-slate-950 shadow-xl' : 'text-slate-400 hover:bg-slate-800'}`}>
              <item.i size={18} /><span>{item.t}</span>
            </button>
          ))}
        </nav>
        <div className="pt-4 border-t border-slate-800">
           <p className="text-[9px] font-black uppercase text-slate-600 mb-1 px-4">Versão 1.0.0</p>
           <button onClick={() => { localStorage.removeItem(STORAGE_KEY_ADMIN); window.location.reload(); }} className="w-full flex items-center space-x-3 p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest text-red-500 hover:bg-red-500/10 transition-all"><LogOut size={16}/> Resetar</button>
        </div>
      </aside>

      <main className="flex-1 p-4 sm:p-8 lg:p-12 overflow-y-auto pb-32 md:pb-12 max-w-full">
        {/* DASHBOARD */}
        {view === AppView.Dashboard && (
          <div className="space-y-8 animate-in fade-in duration-500 max-w-6xl mx-auto">
             <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div className="flex items-center gap-4">
                  <div className="w-14 h-14 bg-slate-900 rounded-2xl border border-slate-800 flex items-center justify-center text-amber-500 shadow-xl"><Medal size={28}/></div>
                  <div>
                    <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">{adminProfile?.dojoName}</h2>
                    <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-1">Bem-vindo de volta, {user?.name} OSS!</p>
