             {/* DASHBOARD MOBILE SHORTCUTS */}
             <div className="grid grid-cols-2 gap-3 md:hidden">
                <button onClick={() => navigateTo(AppView.Athletes)} className="bg-slate-900 p-6 rounded-[2rem] border border-slate-800 flex flex-col items-center gap-3 active:bg-slate-800 transition-all"><Users size={28} className="text-amber-500"/><span className="text-[9px] font-black uppercase tracking-widest">Alunos</span></button>
                <button onClick={() => navigateTo(AppView.Attendance)} className="bg-slate-900 p-6 rounded-[2rem] border border-slate-800 flex flex-col items-center gap-3 active:bg-slate-800 transition-all"><CalendarCheck size={28} className="text-emerald-500"/><span className="text-[9px] font-black uppercase tracking-widest">Chamada</span></button>
             </div>
          </div>
        )}

        {/* ALUNOS */}
        {view === AppView.Athletes && (
          <div className="space-y-8 animate-in slide-in-from-bottom-6 duration-500 max-w-6xl mx-auto">
             <header className="flex justify-between items-center gap-4">
                <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter leading-none">Alunos</h2>
                <button onClick={() => { setForm({ accessId: Math.floor(1000 + Math.random() * 9000).toString(), belt: 'Branca', paymentDay: 10, category: 'Adulto', degrees: 0 }); setEditId(null); setModalType('athlete'); setIsModalOpen(true); }} className="bg-amber-500 text-slate-950 px-5 py-3 rounded-xl font-black uppercase text-[10px] flex items-center gap-2 shadow-lg active:scale-95 transition-all"><Plus size={18} /> Novo Atleta</button>
             </header>
             <div className="grid grid-cols-1 gap-3">
                {athletes.map(ath => {
                   const today = new Date().getDate();
                   const isNearPayment = ath.paymentDay === today || (ath.paymentDay > today && ath.paymentDay - today <= 3);
                   return (
                     <div key={ath.id} className="bg-slate-900 border border-slate-800 p-6 rounded-[2.5rem] flex flex-col sm:flex-row sm:items-center justify-between gap-4 shadow-xl hover:border-slate-700 transition-all">
                        <div className="flex items-center gap-4">
                           <div className="w-12 h-12 bg-slate-800 rounded-2xl flex items-center justify-center font-black text-amber-500 italic shadow-inner">OSS</div>
                           <div className="overflow-hidden">
                              <p className="font-black uppercase text-sm italic truncate text-white">{ath.name}</p>
                              <BeltBadge belt={ath.belt} degrees={ath.degrees} />
                           </div>
                        </div>
                        <div className="flex items-center justify-between sm:justify-end gap-4">
                           <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${isNearPayment ? 'bg-amber-500 text-slate-950 animate-pulse shadow-lg' : 'bg-slate-800 text-slate-500'}`}>Dia {ath.paymentDay}</div>
                           <div className="flex gap-2">
                              <button onClick={() => { setForm(ath); setEditId(ath.id); setModalType('athlete'); setIsModalOpen(true); }} className="p-3 bg-slate-800 rounded-xl text-slate-400 hover:text-amber-500 transition-all active:scale-95"><Edit size={18} /></button>
                              <button onClick={() => { if(confirm("Remover atleta permanentemente?")) setAthletes(prev => prev.filter(a => a.id !== ath.id)); }} className="p-3 bg-slate-800 rounded-xl text-slate-400 hover:text-red-500 transition-all active:scale-95"><Trash2 size={18} /></button>
                           </div>
                        </div>
                     </div>
                   );
                })}
             </div>
          </div>
        )}

        {/* CHAMADA */}
        {view === AppView.Attendance && (
          <div className="space-y-8 animate-in fade-in max-w-6xl mx-auto">
             <header className="flex justify-between items-center"><h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Chamada Diária</h2><div className="bg-slate-900 p-4 rounded-2xl border border-slate-800 text-[10px] font-black text-slate-500 uppercase tracking-widest">{new Date().toLocaleDateString('pt-BR', {day: '2-digit', month: 'long'})}</div></header>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {athletes.filter(a => a.status === 'active').map(ath => {
                   const isPresentToday = ath.lastAttendance === new Date().toISOString().split('T')[0];
                   return (
                     <button key={ath.id} onClick={() => !isPresentToday && markAttendance(ath.id)} className={`p-7 rounded-[2.5rem] border transition-all flex items-center justify-between text-left group shadow-lg ${isPresentToday ? 'bg-emerald-500/10 border-emerald-500/30' : 'bg-slate-900 border-slate-800 active:scale-95'}`}>
                        <div className="overflow-hidden pr-4">
                          <p className={`font-black uppercase italic text-sm truncate ${isPresentToday ? 'text-emerald-500' : 'text-white'}`}>{ath.name}</p>
                          <BeltBadge belt={ath.belt} degrees={ath.degrees} />
                        </div>
                        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center transition-all shrink-0 ${isPresentToday ? 'bg-emerald-500 text-white shadow-xl' : 'bg-slate-800 text-slate-700'}`}>
                           {isPresentToday ? <CheckCircle2 size={28}/> : <Plus size={28}/>}
                        </div>
                     </button>
                   );
                })}
             </div>
          </div>
        )}

        {/* FINANCEIRO */}
        {view === AppView.Finance && (
          <div className="space-y-8 animate-in fade-in max-w-6xl mx-auto">
             <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h2 className="text-3xl font-black text-white italic uppercase tracking-tighter">Financeiro</h2>
                <div className="flex gap-3 w-full sm:w-auto">
                   <button onClick={() => { setForm({ type: 'income', date: new Date().toISOString().split('T')[0] }); setModalType('transaction'); setIsModalOpen(true); }} className="flex-1 sm:flex-none bg-emerald-500 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-3 shadow-xl active:scale-95 transition-all">Receita</button>
                   <button onClick={() => { setForm({ type: 'expense', date: new Date().toISOString().split('T')[0] }); setModalType('transaction'); setIsModalOpen(true); }} className="flex-1 sm:flex-none bg-red-600 text-white px-8 py-4 rounded-2xl font-black uppercase text-[10px] flex items-center justify-center gap-3 shadow-xl active:scale-95 transition-all">Despesa</button>
                </div>
             </header>
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 shadow-xl"><p className="text-[10px] font-black text-slate-500 uppercase mb-2 tracking-widest">Saldo Atual</p><p className={`text-4xl font-black tabular-nums ${stats.balance >= 0 ? 'text-emerald-500' : 'text-red-500'}`}>R$ {stats.balance.toFixed(2)}</p></div>
                <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 border-b-emerald-500 shadow-xl"><p className="text-[10px] font-black text-emerald-500 uppercase mb-2 tracking-widest">Entradas</p><p className="text-4xl font-black text-white tabular-nums">R$ {stats.income.toFixed(0)}</p></div>
                <div className="bg-slate-900 p-8 rounded-[2.5rem] border border-slate-800 border-b-red-600 shadow-xl"><p className="text-[10px] font-black text-red-600 uppercase mb-2 tracking-widest">Saídas</p><p className="text-4xl font-black text-white tabular-nums">R$ {stats.expense.toFixed(0)}</p></div>
             </div>
             <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl">
                <div className="overflow-x-auto custom-scrollbar">
                  <table className="w-full text-left">
                    <thead className="bg-slate-800/50 text-[10px] font-black uppercase text-slate-500 tracking-widest">
                      <tr><th className="px-8 py-6">Data</th><th className="px-8 py-6">Descrição</th><th className="px-8 py-6 text-right">Valor</th></tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800/50">
                      {transactions.slice().reverse().map(t => (
                        <tr key={t.id} className="hover:bg-slate-800/30 transition-colors">
                          <td className="px-8 py-6 text-xs text-slate-500 font-mono">{new Date(t.date).toLocaleDateString('pt-BR')}</td>
                          <td className="px-8 py-6 font-black uppercase text-xs tracking-wide">{t.description}</td>
                          <td className={`px-8 py-6 text-right font-black tabular-nums ${t.type === 'income' ? 'text-emerald-500' : 'text-red-500'}`}>{t.type === 'income' ? '+' : '-'} R$ {t.amount.toFixed(2)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
             </div>
          </div>
        )}

        {/* RANKING */}
        {view === AppView.Ranking && (
          <div className="space-y-8 animate-in fade-in max-w-2xl mx-auto pb-10">
             <header className="text-center"><h2 className="text-4xl font-black text-white italic uppercase tracking-tighter leading-none">Ranking de Frequência</h2></header>
             <div className="space-y-4">
                {stats.ranking.map((ath, idx) => (
                  <div key={ath.id} className={`p-8 rounded-[3rem] border flex items-center gap-6 shadow-2xl transition-all ${idx === 0 ? 'bg-amber-500 border-amber-400 text-slate-950 scale-[1.03]' : 'bg-slate-900 border-slate-800 text-white'}`}>
                     <div className={`text-4xl font-black italic w-16 text-center shrink-0 ${idx === 0 ? 'text-slate-950' : 'text-slate-700'}`}>{idx + 1}º</div>
                     <div className="flex-1 overflow-hidden">
                        <p className="font-black uppercase italic text-lg truncate leading-none mb-1">{ath.name}</p>
                        <p className={`text-[10px] font-black uppercase tracking-widest ${idx === 0 ? 'text-slate-900' : 'text-slate-500'}`}>{ath.attendanceCount} TREINOS</p>
                     </div>
                     <BeltBadge belt={ath.belt} degrees={ath.degrees} />
