           <div className="bg-slate-900 border border-slate-800 rounded-[3.5rem] w-full max-w-xl p-12 shadow-[0_0_120px_rgba(0,0,0,0.8)] animate-in zoom-in-95 overflow-y-auto max-h-[92vh] border-b-amber-500/50">
              <div className="flex justify-between items-center mb-10">
                <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter leading-none">{editId ? 'Editar' : 'Novo'} {modalType === 'athlete' ? 'Atleta' : 'Lançamento'}</h3>
                <button onClick={() => setIsModalOpen(false)} className="text-slate-600 hover:text-white transition-colors p-2"><X size={36}/></button>
              </div>
              <div className="space-y-7">
                {modalType === 'athlete' && (
                  <>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3">Nome Completo</label><input type="text" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase focus:ring-2 focus:ring-amber-500 transition-all shadow-inner" /></div>
                    <div className="grid grid-cols-2 gap-5">
                       <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3">Faixa</label><select value={form.belt} onChange={e => setForm({...form, belt: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase appearance-none"><option value="Branca">Branca</option><option value="Azul">Azul</option><option value="Roxa">Roxa</option><option value="Marrom">Marrom</option><option value="Preta">Preta</option></select></div>
                       <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3">Mensalidade (Dia)</label><input type="number" min="1" max="31" value={form.paymentDay || 10} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs" /></div>
                    </div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3">Data de Nascimento</label><input type="date" value={form.birthDate || ''} onChange={e => setForm({...form, birthDate: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs" /></div>
                  </>
                )}
                {modalType === 'transaction' && (
                  <>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3">Descrição</label><input type="text" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase focus:ring-2 focus:ring-amber-500 shadow-inner" /></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3">Valor R$</label><input type="number" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs shadow-inner" /></div>
                  </>
                )}
              </div>
              <button onClick={() => {
                if(modalType === 'athlete') {
                  if(editId) setAthletes(prev => prev.map(a => a.id === editId ? {...a, ...form} : a));
                  else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), status: 'active', attendanceCount: 0, accessId: Math.floor(1000 + Math.random() * 9000).toString() }]);
                } else if(modalType === 'transaction') {
                  setTransactions(prev => [...prev, { ...form, id: Date.now().toString() }]);
                }
                setIsModalOpen(false);
              }} className="w-full mt-12 bg-amber-500 text-slate-950 font-black p-8 rounded-[2.5rem] transition-all uppercase italic text-sm shadow-2xl active:scale-95 hover:bg-white tracking-widest">Salvar OSS!</button>
           </div>
        </div>
      )}

    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  Users, CalendarCheck, DollarSign, Trophy, Plus, Menu, X, LogOut, 
  Medal, CheckCircle2, Home, Star, UserPlus, 
  Edit, ArrowRight, Clock, Database, Download, FileJson, 
  ShieldAlert, RotateCcw, VolumeX, Fingerprint, Calendar as CalendarIcon, 
  Info, Bell, Cake, ChevronRight, Play, Pause, Trash2, Upload, LayoutDashboard,
  Smartphone, UserCheck
} from 'lucide-react';
import { Athlete, Transaction, AppView, Belt, AdminProfile } from './types';
import { getDojoInsights } from './geminiService';

const BELT_COLORS: Record<string, string> = {
  'Branca': '#f8fafc',
  'Cinza': '#64748b',
  'Amarela': '#fbbf24',
  'Laranja': '#f97316',
  'Verde': '#16a34a',
  'Azul': '#2563eb',
  'Roxa': '#7c3aed',
  'Marrom': '#78330f',
  'Preta': '#0f172a'
};

const BeltBadge: React.FC<{ belt: Belt; degrees: number }> = ({ belt, degrees }) => (
  <div className="flex items-center gap-2">
    <div 
      className="h-4 w-12 sm:h-5 sm:w-16 rounded shadow-inner border border-slate-800 flex relative overflow-hidden shrink-0"
      style={{ backgroundColor: BELT_COLORS[belt] || '#fff' }}
    >
      <div className={`absolute right-0 top-0 bottom-0 w-4 sm:w-5 ${belt === 'Preta' ? 'bg-red-600' : 'bg-slate-950'} flex items-center justify-center gap-0.5 px-0.5`}>
        {Array.from({ length: Math.min(degrees, 4) }).map((_, i) => (
          <div key={i} className="w-[1px] sm:w-[1.5px] h-2 sm:h-3 bg-white" />
        ))}
      </div>
    </div>
    <span className="text-[8px] sm:text-[9px] font-black uppercase tracking-tighter text-slate-400 truncate">{belt}</span>
  </div>
);

const formatTime = (seconds: number) => {
  const m = Math.floor(seconds / 60);
  const s = seconds % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
};

type AlarmType = 'buzzer' | 'bell' | 'MATE' | 'FIM';

const App: React.FC = () => {
  const STORAGE_KEY_ATHLETES = 'sistemabjj_athletes_prod';
  const STORAGE_KEY_TRANSACTIONS = 'sistemabjj_transactions_prod';
  const STORAGE_KEY_ADMIN = 'sistemabjj_admin_prod';

  const [athletes, setAthletes] = useState<Athlete[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_ATHLETES) || '[]'));
  const [transactions, setTransactions] = useState<Transaction[]>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_TRANSACTIONS) || '[]'));
  const [adminProfile, setAdminProfile] = useState<AdminProfile | null>(() => JSON.parse(localStorage.getItem(STORAGE_KEY_ADMIN) || 'null'));

  // UI State
  const [user, setUser] = useState<{name: string, role: string} | null>(null);
  const [view, setView] = useState<AppView>(AppView.Login); // AppView.Login agora é o Portal de Boas-Vindas
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'athlete' | 'transaction'>('athlete');
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<any>({});
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Timer State
  const [timeLeft, setTimeLeft] = useState(300);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [selectedAlarm, setSelectedAlarm] = useState<AlarmType>('buzzer');
  const [manualMin, setManualMin] = useState(5);
  const [isAlarmPlaying, setIsAlarmPlaying] = useState(false);
  const timerIntervalRef = useRef<number | null>(null);
  const alarmIntervalRef = useRef<number | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ATHLETES, JSON.stringify(athletes));
    localStorage.setItem(STORAGE_KEY_TRANSACTIONS, JSON.stringify(transactions));
    if (adminProfile) localStorage.setItem(STORAGE_KEY_ADMIN, JSON.stringify(adminProfile));
  }, [athletes, transactions, adminProfile]);

  // Se não houver perfil, força o registro
  useEffect(() => {
    if (!adminProfile?.registered) {
      setView(AppView.AdminRegistration);
    }
  }, [adminProfile]);

  // Insight IA
  useEffect(() => {
    if (user?.role === 'admin' && athletes.length > 0 && view === AppView.Dashboard) {
      getDojoInsights(athletes, transactions).then(setAiInsight);
    }
  }, [view, user, athletes.length]);

  useEffect(() => {
    if (isTimerRunning && timeLeft > 0) {
      timerIntervalRef.current = window.setInterval(() => setTimeLeft(prev => prev - 1), 1000);
    } else if (timeLeft === 0 && isTimerRunning) {
      setIsTimerRunning(false);
      triggerAlarm();
    }
    return () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };
  }, [isTimerRunning, timeLeft]);

  const triggerAlarm = () => {
    stopAlarm();
    setIsAlarmPlaying(true);
    const play = () => {
      if (['MATE', 'FIM'].includes(selectedAlarm)) {
        const msg = new SpeechSynthesisUtterance(selectedAlarm === 'MATE' ? 'MATÊ!' : 'FIM DE ROUND!');
        msg.lang = 'pt-BR';
        window.speechSynthesis.speak(msg);
      } else {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
        audioContextRef.current = ctx;
        const osc = ctx.createOscillator();
        const gain = ctx.createGain();
        osc.connect(gain); gain.connect(ctx.destination);
        osc.frequency.setValueAtTime(selectedAlarm === 'buzzer' ? 140 : 880, ctx.currentTime);
        osc.start(); osc.stop(ctx.currentTime + 1.2);
      }
    };
    alarmIntervalRef.current = window.setInterval(play, 3500);
    play();
  };

  const stopAlarm = () => {
    setIsAlarmPlaying(false);
    if (alarmIntervalRef.current) clearInterval(alarmIntervalRef.current);
    if (audioContextRef.current) audioContextRef.current.close().catch(() => {});
    window.speechSynthesis.cancel();
  };

  const stats = useMemo(() => {
    const today = new Date().getDate();
    const currentMonth = new Date().getMonth();
    const imminent = athletes.filter(a => a.status === 'active' && (a.paymentDay === today || (a.paymentDay > today && a.paymentDay - today <= 3)));
    const birthdays = athletes.filter(a => a.birthDate && new Date(a.birthDate).getMonth() === currentMonth);
    const ranking = [...athletes].sort((a, b) => b.attendanceCount - a.attendanceCount);
    const income = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const expense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    return { imminent, birthdays, ranking, balance: income - expense, income, expense };
  }, [athletes, transactions]);

  const markAttendance = (id: string) => {
    const today = new Date().toISOString().split('T')[0];
    setAthletes(prev => prev.map(a => a.id === id && a.lastAttendance !== today ? { ...a, attendanceCount: a.attendanceCount + 1, lastAttendance: today } : a));
    alert("Presença marcada! OSS!");
  };

  const navigateTo = (v: AppView) => { 
    setView(v); 
    setIsMobileMenuOpen(false); 
    window.scrollTo({ top: 0, behavior: 'smooth' }); 
  };

  const handleLogout = () => {
    setUser(null);
    setView(AppView.Login);
    setIsMobileMenuOpen(false);
  };

  // TELA DE REGISTRO INICIAL
  if (view === AppView.AdminRegistration) {
    return (
      <div className="min-h-screen flex items-center justify-center p-4 bg-slate-950 text-white font-['Inter']">
        <form onSubmit={(e) => { 
          e.preventDefault(); 
          const f = new FormData(e.currentTarget); 
          const newAdmin = { name: f.get('name'), dojoName: f.get('dojoName'), password: '', registered: true }; 
          setAdminProfile(newAdmin as any); 
          setUser({ name: newAdmin.name as string, role: 'admin' });
          setView(AppView.Dashboard);
        }} className="bg-slate-900 p-8 sm:p-12 rounded-[3rem] border border-slate-800 w-full max-w-xl shadow-2xl space-y-10 text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-amber-500"></div>
          <ShieldAlert className="mx-auto text-amber-500 mb-2" size={64} />
          <h2 className="text-3xl font-black italic uppercase tracking-tighter leading-none">Configurar SISTEMA BJJ</h2>
