      {/* MODAL GLOBAL */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-slate-950/96 backdrop-blur-2xl z-[300] flex items-center justify-center p-4">
           <div className="bg-slate-900 border border-slate-800 rounded-[3.5rem] w-full max-w-xl p-12 shadow-[0_0_120px_rgba(0,0,0,0.8)] animate-in zoom-in-95 overflow-y-auto max-h-[92vh] border-b-amber-500/50">
              <div className="flex justify-between items-center mb-10">
                <h3 className="text-2xl font-black text-white italic uppercase tracking-tighter leading-none">{editId ? 'Editar' : 'Novo'} {modalType === 'athlete' ? 'Atleta' : 'Lançamento'}</h3>
                <button onClick={() => setIsModalOpen(false)} className="text-slate-600 hover:text-white transition-colors p-2"><X size={36}/></button>
              </div>
              <div className="space-y-7">
                {modalType === 'athlete' && (
                  <>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3 tracking-widest">Nome do Atleta</label><input type="text" value={form.name || ''} onChange={e => setForm({...form, name: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase focus:ring-2 focus:ring-amber-500 transition-all shadow-inner" /></div>
                    <div className="grid grid-cols-2 gap-5">
                       <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3 tracking-widest">Faixa</label><select value={form.belt} onChange={e => setForm({...form, belt: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase appearance-none"><option value="Branca">Branca</option><option value="Azul">Azul</option><option value="Roxa">Roxa</option><option value="Marrom">Marrom</option><option value="Preta">Preta</option></select></div>
                       <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3 tracking-widest">Dia Mensalidade</label><input type="number" min="1" max="31" value={form.paymentDay || 10} onChange={e => setForm({...form, paymentDay: parseInt(e.target.value)})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs" /></div>
                    </div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3 tracking-widest">Data Nascimento</label><input type="date" value={form.birthDate || ''} onChange={e => setForm({...form, birthDate: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs" /></div>
                  </>
                )}
                {modalType === 'transaction' && (
                  <>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3 tracking-widest">Descrição do Item</label><input type="text" value={form.description || ''} onChange={e => setForm({...form, description: e.target.value})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs uppercase focus:ring-2 focus:ring-amber-500 shadow-inner" /></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-500 uppercase ml-3 tracking-widest">Valor R$</label><input type="number" value={form.amount || ''} onChange={e => setForm({...form, amount: parseFloat(e.target.value)})} className="w-full p-6 bg-slate-800 border border-slate-700 rounded-3xl text-white outline-none font-black text-xs shadow-inner" /></div>
                  </>
                )}
              </div>
              <button onClick={() => {
                if(modalType === 'athlete') {
                  if(editId) setAthletes(prev => prev.map(a => a.id === editId ? {...a, ...form} : a));
                  else setAthletes(prev => [...prev, { ...form, id: Date.now().toString(), status: 'active', attendanceCount: 0, accessId: Math.floor(1000 + Math.random() * 9000).toString() }]);
                } else if(modalType === 'transaction') {
                  setTransactions(prev => [...prev, { ...form, id: Date.now().toString() }]);
                }
                setIsModalOpen(false);
              }} className="w-full mt-12 bg-amber-500 text-slate-950 font-black p-8 rounded-[2.5rem] transition-all uppercase italic text-sm shadow-2xl active:scale-95 hover:bg-white tracking-widest">Salvar OSS!</button>
           </div>
        </div>
      )}

    </div>
  );
};

